client/types/database.ts.content:
/**
 * WilderGo Database Schema Types
 * Complete TypeScript definitions for Supabase database
 * Ready for integration when Supabase is connected
 */

// ============================================================================
// ENUMS
// ============================================================================

export type AppMode = 'dating' | 'friends' | 'builder';

export type VerificationStatus = 'pending' | 'verified' | 'failed' | 'expired';

export type HelpCategory = 'mechanical' | 'medical' | 'security' | 'supplies';

export type HelpPriority = 'critical' | 'urgent' | 'assistance';

export type HelpRequestStatus =
  | 'broadcasting'
  | 'responding'
  | 'resolved'
  | 'cancelled'
  | 'expired';

export type MessageStatus = 'sent' | 'delivered' | 'read';

export type ConvoyRole = 'leader' | 'member';

export type SubscriptionTier = 'free' | 'convoy';

export type BuilderSpecialty =
  | 'electrical'
  | 'plumbing'
  | 'solar'
  | 'mechanical'
  | 'interior'
  | 'exterior'
  | 'full_build';

// ============================================================================
// USER & PROFILE
// ============================================================================

export interface Profile {
  id: string; // UUID, references auth.users
  created_at: string;
  updated_at: string;

  // Basic info
  display_name: string;
  bio: string | null;
  avatar_url: string | null;

  // Rig info
  rig_type: string | null; // e.g., "2020 Sprinter 144"
  rig_name: string | null; // e.g., "The Wanderer"
  rig_photos: string[]; // Array of photo URLs

  // Verification
  photo_verified: boolean;
  photo_verified_at: string | null;
  verification_confidence: number | null; // 0-100

  // Location (last known)
  last_latitude: number | null;
  last_longitude: number | null;
  last_location_update: string | null;
  location_sharing_enabled: boolean;
  ghost_mode_enabled: boolean;

  // Nomadic Pulse
  current_heading: string | null; // e.g., "Arches NP"
  current_location_name: string | null; // e.g., "Moab, UT"
  traveling_with: number; // Number of companions
  on_the_road_since: string | null; // Date started nomading

  // Social
  instagram_handle: string | null;
  website_url: string | null;

  // Subscription
  subscription_tier: SubscriptionTier;
  subscription_expires_at: string | null;

  // Settings
  notifications_enabled: boolean;
  dating_mode_enabled: boolean;
  friends_mode_enabled: boolean;
  builder_mode_enabled: boolean;
}

export interface ProfilePreferences {
  id: string; // UUID
  profile_id: string; // References profiles.id
  created_at: string;
  updated_at: string;

  // Dating preferences
  looking_for: ('men' | 'women' | 'non_binary' | 'everyone')[];
  age_range_min: number;
  age_range_max: number;
  max_distance_miles: number;

  // Route matching
  route_overlap_threshold: number; // Minimum % overlap to show match

  // Notification preferences
  notify_new_matches: boolean;
  notify_messages: boolean;
  notify_help_requests: boolean;
  notify_convoy_updates: boolean;
  notify_campfire_events: boolean;
}

// ============================================================================
// ROUTES & TRAVEL
// ============================================================================

export interface Route {
  id: string; // UUID
  profile_id: string; // References profiles.id
  created_at: string;
  updated_at: string;

  name: string;
  description: string | null;

  // Route geometry (PostGIS)
  route_geometry: unknown; // PostGIS geography type

  // Waypoints
  start_location: string;
  end_location: string;
  waypoints: RouteWaypoint[];

  // Timing
  start_date: string | null;
  end_date: string | null;
  is_flexible: boolean;

  // Status
  is_active: boolean;
  is_public: boolean;
}

export interface RouteWaypoint {
  name: string;
  latitude: number;
  longitude: number;
  arrival_date: string | null;
  departure_date: string | null;
  notes: string | null;
}

export interface RouteOverlap {
  id: string; // UUID
  route_a_id: string; // References routes.id
  route_b_id: string; // References routes.id
  profile_a_id: string; // References profiles.id
  profile_b_id: string; // References profiles.id

  overlap_percentage: number; // 0-100
  overlap_distance_miles: number;
  overlap_start_date: string | null;
  overlap_end_date: string | null;

  // Overlap geometry
  overlap_geometry: unknown; // PostGIS geography type

  calculated_at: string;
}

// ============================================================================
// MATCHING & CONNECTIONS
// ============================================================================

export interface Match {
  id: string; // UUID
  created_at: string;
  updated_at: string;

  profile_a_id: string; // References profiles.id
  profile_b_id: string; // References profiles.id

  // Match context
  mode: AppMode;
  route_overlap_id: string | null; // References route_overlaps.id

  // Swipe states
  profile_a_liked: boolean | null;
  profile_b_liked: boolean | null;

  // Match status
  is_match: boolean; // Both liked
  matched_at: string | null;

  // Conversation
  last_message_at: string | null;
  unread_count_a: number;
  unread_count_b: number;
}

export interface Swipe {
  id: string; // UUID
  created_at: string;

  swiper_id: string; // References profiles.id
  swiped_id: string; // References profiles.id

  direction: 'like' | 'pass';
  mode: AppMode;
}

// ============================================================================
// MESSAGING
// ============================================================================

export interface Conversation {
  id: string; // UUID
  created_at: string;
  updated_at: string;

  match_id: string; // References matches.id

  // Participants
  participant_a_id: string; // References profiles.id
  participant_b_id: string; // References profiles.id

  // Last message preview
  last_message_text: string | null;
  last_message_at: string | null;
  last_message_sender_id: string | null;

  // Status
  is_archived_a: boolean;
  is_archived_b: boolean;
  is_blocked: boolean;
  blocked_by: string | null;
}

export interface Message {
  id: string; // UUID
  created_at: string;

  conversation_id: string; // References conversations.id
  sender_id: string; // References profiles.id

  // Content
  text: string | null;
  image_url: string | null;
  location_share: {
    latitude: number;
    longitude: number;
    address: string;
  } | null;

  // AI-generated icebreaker flag
  is_ai_suggested: boolean;

  // Status
  status: MessageStatus;
  delivered_at: string | null;
  read_at: string | null;
}

// ============================================================================
// HELP / SOS SYSTEM
// ============================================================================

export interface HelpRequest {
  id: string; // UUID
  created_at: string;
  updated_at: string;

  requester_id: string; // References profiles.id

  // Request details
  category: HelpCategory;
  priority: HelpPriority;
  description: string;

  // Location
  latitude: number;
  longitude: number;
  address: string | null;

  // Nomadic Pulse context
  heading: string | null;
  rig_type: string | null;

  // Status
  status: HelpRequestStatus;
  resolved_at: string | null;
  resolved_by: string | null; // References profiles.id

  // Broadcasting
  broadcast_radius_miles: number;
  responders_notified: number;

  // AI Triage
  ai_triage_advice: string | null;
}

export interface HelpResponse {
  id: string; // UUID
  created_at: string;
  updated_at: string;

  request_id: string; // References help_requests.id
  responder_id: string; // References profiles.id

  // Response details
  message: string;
  eta_minutes: number | null;
  distance_miles: number;

  // Status
  status: 'offered' | 'en_route' | 'arrived' | 'completed' | 'cancelled';

  // Location at response time
  responder_latitude: number;
  responder_longitude: number;
}

// ============================================================================
// CONVOYS
// ============================================================================

export interface Convoy {
  id: string; // UUID
  created_at: string;
  updated_at: string;

  name: string;
  description: string | null;

  leader_id: string; // References profiles.id

  // Route
  route_id: string | null; // References routes.id
  destination: string | null;

  // Settings
  max_members: number;
  is_public: boolean;
  requires_verification: boolean;

  // Stats
  member_count: number;
}

export interface ConvoyMember {
  id: string; // UUID
  created_at: string;

  convoy_id: string; // References convoys.id
  profile_id: string; // References profiles.id

  role: ConvoyRole;
  joined_at: string;

  // Position in convoy
  position_order: number;

  // Status
  is_active: boolean;
  last_location_latitude: number | null;
  last_location_longitude: number | null;
  last_location_update: string | null;
}

// ============================================================================
// CAMPFIRE EVENTS
// ============================================================================

export interface CampfireEvent {
  id: string; // UUID
  created_at: string;
  updated_at: string;

  host_id: string; // References profiles.id

  // Event details
  title: string;
  description: string | null;
  event_type: 'meetup' | 'potluck' | 'workshop' | 'hangout' | 'other';

  // Location
  latitude: number;
  longitude: number;
  address: string | null;
  location_name: string | null; // e.g., "BLM Land near Quartzsite"

  // Timing
  starts_at: string;
  ends_at: string | null;

  // Capacity
  max_attendees: number | null;
  current_attendees: number;

  // Status
  is_cancelled: boolean;
  is_public: boolean;
}

export interface CampfireRSVP {
  id: string; // UUID
  created_at: string;

  event_id: string; // References campfire_events.id
  profile_id: string; // References profiles.id

  status: 'going' | 'maybe' | 'not_going';
}

// ============================================================================
// BUILDER NETWORK
// ============================================================================

export interface Builder {
  id: string; // UUID
  profile_id: string; // References profiles.id
  created_at: string;
  updated_at: string;

  // Business info
  business_name: string | null;
  tagline: string | null;

  // Specialties
  specialties: BuilderSpecialty[];

  // Verification
  is_verified: boolean;
  verified_at: string | null;
  years_experience: number | null;

  // Portfolio
  portfolio_photos: string[];
  builds_completed: number;

  // Availability
  is_available: boolean;
  service_radius_miles: number | null;

  // Location
  base_latitude: number | null;
  base_longitude: number | null;
  base_location_name: string | null;
  is_mobile: boolean; // Travels to clients

  // Ratings
  average_rating: number | null;
  review_count: number;
}

export interface BuilderReview {
  id: string; // UUID
  created_at: string;

  builder_id: string; // References builders.id
  reviewer_id: string; // References profiles.id

  rating: number; // 1-5
  review_text: string | null;

  // Project context
  project_type: BuilderSpecialty;
  project_photos: string[];
}

export interface BuilderInquiry {
  id: string; // UUID
  created_at: string;
  updated_at: string;

  builder_id: string; // References builders.id
  requester_id: string; // References profiles.id

  // Inquiry details
  project_type: BuilderSpecialty;
  description: string;
  budget_range: string | null;
  timeline: string | null;

  // Status
  status: 'pending' | 'responded' | 'accepted' | 'declined' | 'completed';

  // Location
  project_latitude: number | null;
  project_longitude: number | null;
  project_location_name: string | null;
}

// ============================================================================
// NOTIFICATIONS
// ============================================================================

export interface Notification {
  id: string; // UUID
  created_at: string;

  profile_id: string; // References profiles.id

  type:
    | 'new_match'
    | 'new_message'
    | 'help_request'
    | 'help_response'
    | 'convoy_invite'
    | 'campfire_event'
    | 'route_overlap'
    | 'builder_request'
    | 'verification_complete'
    | 'subscription_update';

  title: string;
  body: string;

  // Related data
  data: Record<string, unknown>;

  // Status
  is_read: boolean;
  read_at: string | null;

  // Push
  push_sent: boolean;
  push_sent_at: string | null;
}

// ============================================================================
// PASSPORT / ACHIEVEMENTS
// ============================================================================

export interface PassportStamp {
  id: string; // UUID
  created_at: string;

  profile_id: string; // References profiles.id

  // Location
  latitude: number;
  longitude: number;
  location_name: string;
  state: string | null;
  country: string;

  // Visit info
  visited_at: string;
  photo_url: string | null;
  notes: string | null;
}

export interface Achievement {
  id: string; // UUID
  created_at: string;

  profile_id: string; // References profiles.id

  achievement_type:
    | 'first_match'
    | 'first_help'
    | 'first_convoy'
    | 'states_visited_10'
    | 'states_visited_25'
    | 'states_visited_50'
    | 'helped_10_nomads'
    | 'verified_builder'
    | 'convoy_leader';

  earned_at: string;
}

// ============================================================================
// DATABASE TYPE HELPER
// ============================================================================

export interface Database {
  public: {
    Tables: {
      profiles: {
        Row: Profile;
        Insert: Omit<Profile, 'created_at' | 'updated_at'>;
        Update: Partial<Omit<Profile, 'id' | 'created_at'>>;
      };
      profile_preferences: {
        Row: ProfilePreferences;
        Insert: Omit<ProfilePreferences, 'id' | 'created_at' | 'updated_at'>;
        Update: Partial<Omit<ProfilePreferences, 'id' | 'profile_id' | 'created_at'>>;
      };
      routes: {
        Row: Route;
        Insert: Omit<Route, 'id' | 'created_at' | 'updated_at'>;
        Update: Partial<Omit<Route, 'id' | 'profile_id' | 'created_at'>>;
      };
      route_overlaps: {
        Row: RouteOverlap;
        Insert: Omit<RouteOverlap, 'id' | 'calculated_at'>;
        Update: Partial<Omit<RouteOverlap, 'id'>>;
      };
      matches: {
        Row: Match;
        Insert: Omit<Match, 'id' | 'created_at' | 'updated_at'>;
        Update: Partial<Omit<Match, 'id' | 'created_at'>>;
      };
      swipes: {
        Row: Swipe;
        Insert: Omit<Swipe, 'id' | 'created_at'>;
        Update: never;
      };
      conversations: {
        Row: Conversation;
        Insert: Omit<Conversation, 'id' | 'created_at' | 'updated_at'>;
        Update: Partial<Omit<Conversation, 'id' | 'created_at'>>;
      };
      messages: {
        Row: Message;
        Insert: Omit<Message, 'id' | 'created_at'>;
        Update: Partial<Omit<Message, 'id' | 'created_at' | 'conversation_id' | 'sender_id'>>;
      };
      help_requests: {
        Row: HelpRequest;
        Insert: Omit<HelpRequest, 'id' | 'created_at' | 'updated_at'>;
        Update: Partial<Omit<HelpRequest, 'id' | 'created_at' | 'requester_id'>>;
      };
      help_responses: {
        Row: HelpResponse;
        Insert: Omit<HelpResponse, 'id' | 'created_at' | 'updated_at'>;
        Update: Partial<Omit<HelpResponse, 'id' | 'created_at' | 'request_id' | 'responder_id'>>;
      };
      convoys: {
        Row: Convoy;
        Insert: Omit<Convoy, 'id' | 'created_at' | 'updated_at' | 'member_count'>;
        Update: Partial<Omit<Convoy, 'id' | 'created_at' | 'leader_id'>>;
      };
      convoy_members: {
        Row: ConvoyMember;
        Insert: Omit<ConvoyMember, 'id' | 'created_at'>;
        Update: Partial<Omit<ConvoyMember, 'id' | 'created_at' | 'convoy_id' | 'profile_id'>>;
      };
      campfire_events: {
        Row: CampfireEvent;
        Insert: Omit<CampfireEvent, 'id' | 'created_at' | 'updated_at' | 'current_attendees'>;
        Update: Partial<Omit<CampfireEvent, 'id' | 'created_at' | 'host_id'>>;
      };
      campfire_rsvps: {
        Row: CampfireRSVP;
        Insert: Omit<CampfireRSVP, 'id' | 'created_at'>;
        Update: Partial<Omit<CampfireRSVP, 'id' | 'created_at' | 'event_id' | 'profile_id'>>;
      };
      builders: {
        Row: Builder;
        Insert: Omit<Builder, 'id' | 'created_at' | 'updated_at' | 'average_rating' | 'review_count'>;
        Update: Partial<Omit<Builder, 'id' | 'created_at' | 'profile_id'>>;
      };
      builder_reviews: {
        Row: BuilderReview;
        Insert: Omit<BuilderReview, 'id' | 'created_at'>;
        Update: never;
      };
      builder_inquiries: {
        Row: BuilderInquiry;
        Insert: Omit<BuilderInquiry, 'id' | 'created_at' | 'updated_at'>;
        Update: Partial<Omit<BuilderInquiry, 'id' | 'created_at' | 'builder_id' | 'requester_id'>>;
      };
      notifications: {
        Row: Notification;
        Insert: Omit<Notification, 'id' | 'created_at'>;
        Update: Partial<Omit<Notification, 'id' | 'created_at' | 'profile_id'>>;
      };
      passport_stamps: {
        Row: PassportStamp;
        Insert: Omit<PassportStamp, 'id' | 'created_at'>;
        Update: Partial<Omit<PassportStamp, 'id' | 'created_at' | 'profile_id'>>;
      };
      achievements: {
        Row: Achievement;
        Insert: Omit<Achievement, 'id' | 'created_at'>;
        Update: never;
      };
    };
  };
}

export default Database;

server/services/auth.ts.content:
import { getAuth, getFirestore } from './firebase';
import * as crypto from 'crypto';
import pg from 'pg';
const { Pool } = pg;

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

function generateToken(): string {
  return crypto.randomBytes(32).toString('hex');
}

function hashPassword(password: string, salt: string): string {
  return crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
}

function verifyPassword(password: string, salt: string, hash: string): boolean {
  const checkHash = hashPassword(password, salt);
  return crypto.timingSafeEqual(Buffer.from(hash), Buffer.from(checkHash));
}

export async function signUp(
  email: string,
  password: string
): Promise<{ success: boolean; uid?: string; message?: string }> {
  const normalizedEmail = email.toLowerCase().trim();
  console.log(`[AUTH SIGNUP] === Starting signup for: ${normalizedEmail} ===`);

  try {
    if (password.length < 6) {
      console.log(`[AUTH SIGNUP] REJECTED: Password too short (${password.length} chars)`);
      return { success: false, message: 'Password must be at least 6 characters.' };
    }

    const auth = getAuth();
    console.log(`[AUTH SIGNUP] Firebase Auth instance obtained successfully`);

    let existingUser = null;
    try {
      existingUser = await auth.getUserByEmail(normalizedEmail);
    } catch (lookupError: any) {
      if (lookupError.code === 'auth/user-not-found') {
        console.log(`[AUTH SIGNUP] No existing user found - proceeding with creation`);
      } else {
        console.error(`[AUTH SIGNUP] Error checking existing user:`, lookupError.code, lookupError.message);
        throw lookupError;
      }
    }

    if (existingUser) {
      console.log(`[AUTH SIGNUP] REJECTED: User already exists with uid: ${existingUser.uid}`);
      return { success: false, message: 'An account with this email already exists.' };
    }

    console.log(`[AUTH SIGNUP] Calling Firebase auth.createUser()...`);
    const firebaseUser = await auth.createUser({
      email: normalizedEmail,
      password: password,
      emailVerified: false,
    });

    console.log(`[AUTH SIGNUP] SUCCESS: Firebase user created with uid: ${firebaseUser.uid}`);

    const salt = crypto.randomBytes(16).toString('hex');
    const hash = hashPassword(password, salt);
    try {
      await pool.query(
        `INSERT INTO users (email, firebase_uid, password_hash, password_salt) VALUES ($1, $2, $3, $4) ON CONFLICT (email) DO UPDATE SET password_hash = $3, password_salt = $4, firebase_uid = $2`,
        [normalizedEmail, firebaseUser.uid, hash, salt]
      );
      console.log(`[AUTH SIGNUP] Password hash stored in PostgreSQL`);
    } catch (dbError: any) {
      console.warn(`[AUTH SIGNUP] PostgreSQL write failed (non-critical): ${dbError.message}`);
    }

    try {
      const db = getFirestore();
      await db.collection('users').doc(firebaseUser.uid).set({
        email: normalizedEmail,
        emailVerified: false,
        selfieVerified: false,
        selfieSubmitted: false,
        onboardingComplete: false,
        createdAt: new Date().toISOString(),
        lastLogin: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      });
    } catch (firestoreError: any) {
      console.warn(`[AUTH SIGNUP] Firestore write failed (non-critical): ${firestoreError.message}`);
    }

    return { success: true, uid: firebaseUser.uid };
  } catch (error: any) {
    console.error(`[AUTH SIGNUP] FIREBASE ERROR:`);
    console.error(`[AUTH SIGNUP]   code: ${error.code}`);
    console.error(`[AUTH SIGNUP]   message: ${error.message}`);
    console.error(`[AUTH SIGNUP]   full error:`, JSON.stringify(error, null, 2));

    let userMessage = 'Failed to create account.';
    if (error.code === 'auth/email-already-exists') {
      userMessage = 'An account with this email already exists.';
    } else if (error.code === 'auth/invalid-email') {
      userMessage = 'Invalid email address format.';
    } else if (error.code === 'auth/weak-password') {
      userMessage = 'Password is too weak. Use at least 6 characters.';
    } else if (error.code === 'auth/operation-not-allowed') {
      userMessage = 'Email/password accounts are not enabled. Please enable them in Firebase Console.';
    } else if (error.message) {
      userMessage = error.message;
    }

    return { success: false, message: userMessage };
  }
}

export async function signIn(
  email: string,
  password: string
): Promise<{ success: boolean; uid?: string; emailVerified?: boolean; selfieVerified?: boolean; invitedBy?: string; onboardingComplete?: boolean; message?: string }> {
  const normalizedEmail = email.toLowerCase().trim();
  console.log(`[AUTH SIGNIN] === Starting signin for: ${normalizedEmail} ===`);

  try {
    const auth = getAuth();

    let firebaseUser;
    try {
      firebaseUser = await auth.getUserByEmail(normalizedEmail);
      console.log(`[AUTH SIGNIN] Found Firebase user: uid=${firebaseUser.uid}`);
    } catch (lookupError: any) {
      if (lookupError.code === 'auth/user-not-found') {
        return { success: false, message: 'No account found with this email.' };
      }
      throw lookupError;
    }

    try {
      const dbResult = await pool.query(
        `SELECT password_hash, password_salt FROM users WHERE email = $1`,
        [normalizedEmail]
      );
      if (dbResult.rows.length > 0 && dbResult.rows[0].password_hash && dbResult.rows[0].password_salt) {
        const { password_hash, password_salt } = dbResult.rows[0];
        if (!verifyPassword(password, password_salt, password_hash)) {
          console.log(`[AUTH SIGNIN] Password verification failed for: ${normalizedEmail}`);
          return { success: false, message: 'Incorrect password. Please try again.' };
        }
        console.log(`[AUTH SIGNIN] Password verified successfully`);
      } else {
        console.log(`[AUTH SIGNIN] No stored password hash found - storing one now`);
        const salt = crypto.randomBytes(16).toString('hex');
        const hash = hashPassword(password, salt);
        await pool.query(
          `INSERT INTO users (email, firebase_uid, password_hash, password_salt) VALUES ($1, $2, $3, $4) ON CONFLICT (email) DO UPDATE SET password_hash = $3, password_salt = $4, firebase_uid = $2`,
          [normalizedEmail, firebaseUser.uid, hash, salt]
        );
      }
    } catch (dbError: any) {
      console.warn(`[AUTH SIGNIN] Password verification via DB failed (non-critical): ${dbError.message}`);
    }

    let firestoreData: any = {};
    try {
      const db = getFirestore();
      const userDoc = await db.collection('users').doc(firebaseUser.uid).get();
      if (userDoc.exists) {
        firestoreData = userDoc.data() || {};
      }
      await db.collection('users').doc(firebaseUser.uid).update({
        lastLogin: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      }).catch(() => {});
    } catch (firestoreError: any) {
      console.warn(`[AUTH SIGNIN] Firestore unavailable (non-critical): ${firestoreError.message}`);
    }

    const result = {
      success: true,
      uid: firebaseUser.uid,
      emailVerified: firebaseUser.emailVerified || firestoreData.emailVerified || false,
      selfieVerified: firestoreData.selfieVerified || false,
      invitedBy: firestoreData.invitedBy,
      onboardingComplete: firestoreData.onboardingComplete || false,
    };
    console.log(`[AUTH SIGNIN] Success for uid: ${firebaseUser.uid}`);
    return result;
  } catch (error: any) {
    console.error(`[AUTH SIGNIN] UNEXPECTED ERROR: ${error.code} - ${error.message}`);
    return { success: false, message: error.message || 'Failed to sign in' };
  }
}

export async function sendVerificationEmail(
  uid: string
): Promise<{ success: boolean; message: string }> {
  console.log(`[AUTH] sendVerificationEmail called for uid: ${uid}`);
  try {
    const auth = getAuth();
    const user = await auth.getUser(uid);
    console.log(`[AUTH] User found: ${user.email}, emailVerified: ${user.emailVerified}`);

    const verificationLink = await auth.generateEmailVerificationLink(user.email!);
    console.log(`[AUTH] Verification link generated for ${user.email}`);

    return { success: true, message: 'Verification email sent. Check your inbox.' };
  } catch (error: any) {
    console.error(`[AUTH] sendVerificationEmail error:`, error.code, error.message);
    return { success: false, message: error.message || 'Failed to send verification email' };
  }
}

export async function verifyEmail(
  uid: string,
  token: string
): Promise<{ success: boolean; message?: string }> {
  console.log(`[AUTH] verifyEmail called for uid: ${uid}`);
  try {
    const auth = getAuth();
    await auth.updateUser(uid, { emailVerified: true });

    const db = getFirestore();
    await db.collection('users').doc(uid).update({
      emailVerified: true,
      updatedAt: new Date().toISOString(),
    });

    console.log(`[AUTH] Email verified for uid: ${uid}`);
    return { success: true };
  } catch (error: any) {
    console.error(`[AUTH] verifyEmail error:`, error.code, error.message);
    return { success: false, message: error.message || 'Verification failed' };
  }
}

export async function checkEmailVerification(
  uid: string
): Promise<{ success: boolean; emailVerified: boolean; message?: string }> {
  try {
    const auth = getAuth();
    const user = await auth.getUser(uid);
    console.log(`[AUTH] checkEmailVerification uid: ${uid}, verified: ${user.emailVerified}`);

    if (user.emailVerified) {
      const db = getFirestore();
      await db.collection('users').doc(uid).update({
        emailVerified: true,
        updatedAt: new Date().toISOString(),
      }).catch(() => {});
    }

    return { success: true, emailVerified: user.emailVerified };
  } catch (error: any) {
    console.error(`[AUTH] checkEmailVerification error:`, error.code, error.message);
    return { success: false, emailVerified: false, message: error.message };
  }
}

export async function submitSelfie(
  uid: string,
  selfieData: string
): Promise<{ success: boolean; message?: string }> {
  console.log(`[AUTH] submitSelfie called for uid: ${uid}`);
  try {
    try {
      const db = getFirestore();
      await db.collection('users').doc(uid).set({
        selfieSubmitted: true,
        selfieSubmittedAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      }, { merge: true });
    } catch (firestoreError: any) {
      console.warn(`[AUTH] submitSelfie Firestore write failed (non-critical): ${firestoreError.message}`);
    }

    console.log(`[AUTH] Selfie submitted for uid: ${uid}`);
    return { success: true, message: 'Selfie submitted for verification.' };
  } catch (error: any) {
    console.error(`[AUTH] submitSelfie error:`, error.code, error.message);
    return { success: false, message: error.message || 'Failed to submit selfie' };
  }
}

export async function getUserStatus(
  uid: string
): Promise<{ success: boolean; emailVerified?: boolean; selfieVerified?: boolean; selfieSubmitted?: boolean; message?: string }> {
  try {
    const auth = getAuth();
    const firebaseUser = await auth.getUser(uid);

    let userData: any = {};
    try {
      const db = getFirestore();
      const userDoc = await db.collection('users').doc(uid).get();
      userData = userDoc.exists ? userDoc.data() : {};
    } catch (firestoreError: any) {
      console.warn(`[AUTH] getUserStatus Firestore read failed (non-critical): ${firestoreError.message}`);
    }

    return {
      success: true,
      emailVerified: firebaseUser.emailVerified,
      selfieVerified: userData?.selfieVerified || false,
      selfieSubmitted: userData?.selfieSubmitted || false,
    };
  } catch (error: any) {
    console.error(`[AUTH] getUserStatus error:`, error.code, error.message);
    return { success: false, message: error.message };
  }
}

export async function generateInviteCode(
  uid: string
): Promise<{ success: boolean; inviteCode?: string; message?: string }> {
  try {
    const db = getFirestore();
    const userDoc = await db.collection('users').doc(uid).get();
    if (!userDoc.exists) {
      return { success: false, message: 'User not found.' };
    }

    const userData = userDoc.data();
    if (!userData?.selfieVerified) {
      return { success: false, message: 'Only verified users can generate invite codes.' };
    }

    const code = crypto.randomBytes(4).toString('hex').toUpperCase();
    await db.collection('inviteCodes').doc(code).set({
      createdBy: uid,
      createdAt: new Date().toISOString(),
    });

    console.log(`[AUTH] Invite code generated by uid ${uid}: ${code}`);
    return { success: true, inviteCode: code };
  } catch (error: any) {
    console.error(`[AUTH] generateInviteCode error:`, error.message);
    return { success: false, message: error.message };
  }
}

export async function validateInviteCode(
  code: string
): Promise<{ valid: boolean; inviterUid?: string; message?: string }> {
  try {
    const db = getFirestore();
    const inviteDoc = await db.collection('inviteCodes').doc(code.toUpperCase()).get();

    if (!inviteDoc.exists) {
      return { valid: false, message: 'Invalid invite code.' };
    }

    const inviteData = inviteDoc.data();
    if (inviteData?.usedBy) {
      return { valid: false, message: 'This invite code has already been used.' };
    }

    return { valid: true, inviterUid: inviteData?.createdBy };
  } catch (error: any) {
    return { valid: false, message: error.message };
  }
}

export async function useInviteCode(
  code: string,
  usedByUid: string
): Promise<{ success: boolean; message?: string }> {
  try {
    const db = getFirestore();
    const inviteRef = db.collection('inviteCodes').doc(code.toUpperCase());
    const inviteDoc = await inviteRef.get();

    if (!inviteDoc.exists || inviteDoc.data()?.usedBy) {
      return { success: false, message: 'Invalid or already used invite code.' };
    }

    await inviteRef.update({ usedBy: usedByUid });

    const inviteData = inviteDoc.data();
    await db.collection('users').doc(usedByUid).update({
      invitedBy: inviteData?.createdBy,
      updatedAt: new Date().toISOString(),
    });

    console.log(`[AUTH] Invite code ${code} used by ${usedByUid}`);
    return { success: true };
  } catch (error: any) {
    return { success: false, message: error.message };
  }
}

export async function createOrUpdateUserProfile(
  uid: string,
  profile: {
    displayName?: string;
    vehicle?: string;
    nomadStyle?: string;
    photoURL?: string;
    inviteCode?: string;
    onboardingComplete?: boolean;
  }
): Promise<{ success: boolean; message?: string }> {
  console.log(`[AUTH] createOrUpdateUserProfile for uid: ${uid}`, JSON.stringify(profile));
  try {
    if (profile.displayName) {
      const auth = getAuth();
      await auth.updateUser(uid, { displayName: profile.displayName }).catch((e: any) => {
        console.warn(`[AUTH] Firebase Auth updateUser failed: ${e.message}`);
      });
    }

    try {
      const db = getFirestore();
      await db.collection('users').doc(uid).set(
        { ...profile, updatedAt: new Date().toISOString() },
        { merge: true }
      );
    } catch (firestoreError: any) {
      console.warn(`[AUTH] createOrUpdateUserProfile Firestore write failed (non-critical): ${firestoreError.message}`);
    }

    return { success: true };
  } catch (error: any) {
    console.error(`[AUTH] createOrUpdateUserProfile error:`, error.message);
    return { success: false, message: error.message };
  }
}

export async function getUserProfile(uid: string): Promise<any> {
  try {
    const auth = getAuth();
    const firebaseUser = await auth.getUser(uid);

    let userData: any = {};
    try {
      const db = getFirestore();
      const userDoc = await db.collection('users').doc(uid).get();
      userData = userDoc.exists ? userDoc.data() : {};
    } catch (firestoreError: any) {
      console.warn(`[AUTH] getUserProfile Firestore read failed (non-critical): ${firestoreError.message}`);
    }

    return {
      id: firebaseUser.uid,
      email: firebaseUser.email,
      emailVerified: firebaseUser.emailVerified,
      selfieVerified: userData?.selfieVerified || false,
      selfieSubmitted: userData?.selfieSubmitted || false,
      displayName: userData?.displayName || firebaseUser.displayName,
      vehicle: userData?.vehicle,
      nomadStyle: userData?.nomadStyle,
      photoURL: userData?.photoURL || firebaseUser.photoURL,
      onboardingComplete: userData?.onboardingComplete || false,
    };
  } catch (error: any) {
    console.error(`[AUTH] getUserProfile error:`, error.code, error.message);
    return null;
  }
}

export default {
  signUp,
  signIn,
  sendVerificationEmail,
  verifyEmail,
  checkEmailVerification,
  submitSelfie,
  getUserStatus,
  generateInviteCode,
  validateInviteCode,
  useInviteCode,
  createOrUpdateUserProfile,
  getUserProfile,
};

