/**
 * OpenWeather Integration Stub
 * Live weather data for routes and locations
 * 
 * To activate:
 * 1. Get API key from https://openweathermap.org/api
 * 2. Set OPENWEATHER_API_KEY in environment
 */

export interface WeatherData {
  location: string;
  temperature: number;
  feelsLike: number;
  humidity: number;
  windSpeed: number;
  windDirection: number;
  condition: 'clear' | 'clouds' | 'rain' | 'snow' | 'thunderstorm' | 'fog' | 'mist';
  description: string;
  icon: string;
  uvIndex?: number;
  visibility?: number;
  pressure?: number;
  sunrise?: Date;
  sunset?: Date;
}

export interface WeatherForecast {
  date: Date;
  high: number;
  low: number;
  condition: WeatherData['condition'];
  precipitationChance: number;
}

export interface WeatherAlert {
  id: string;
  type: 'warning' | 'watch' | 'advisory';
  severity: 'minor' | 'moderate' | 'severe' | 'extreme';
  title: string;
  description: string;
  startTime: Date;
  endTime: Date;
  areas: string[];
}

export interface RouteWeather {
  waypoint: { latitude: number; longitude: number; name: string };
  weather: WeatherData;
  estimatedArrival: Date;
}

let apiKey = '';

export const OpenWeatherService = {
  initialize: (key: string) => {
    apiKey = key;
    console.log('[OpenWeather] Initialized');
    return true;
  },

  isConfigured: () => !!apiKey,

  getCurrentWeather: async (
    latitude: number,
    longitude: number
  ): Promise<WeatherData> => {
    console.log('[OpenWeather] Fetching current weather for:', { latitude, longitude });
    return {
      location: 'Moab, UT',
      temperature: 78,
      feelsLike: 80,
      humidity: 25,
      windSpeed: 8,
      windDirection: 225,
      condition: 'clear',
      description: 'Sunny with light breeze',
      icon: 'sunny',
      uvIndex: 7,
      visibility: 10,
      pressure: 1015,
    };
  },

  getForecast: async (
    latitude: number,
    longitude: number,
    days: number = 5
  ): Promise<WeatherForecast[]> => {
    console.log('[OpenWeather] Fetching forecast for:', { latitude, longitude, days });
    const forecasts: WeatherForecast[] = [
      { date: new Date(), high: 82, low: 58, condition: 'clear' as const, precipitationChance: 5 },
      { date: new Date(Date.now() + 86400000), high: 79, low: 55, condition: 'clouds' as const, precipitationChance: 20 },
      { date: new Date(Date.now() + 172800000), high: 75, low: 52, condition: 'rain' as const, precipitationChance: 60 },
      { date: new Date(Date.now() + 259200000), high: 70, low: 48, condition: 'thunderstorm' as const, precipitationChance: 80 },
      { date: new Date(Date.now() + 345600000), high: 76, low: 51, condition: 'clear' as const, precipitationChance: 10 },
    ];
    return forecasts.slice(0, days);
  },

  getAlerts: async (latitude: number, longitude: number): Promise<WeatherAlert[]> => {
    console.log('[OpenWeather] Checking alerts for:', { latitude, longitude });
    return [];
  },

  getRouteWeather: async (
    route: Array<{ latitude: number; longitude: number; name: string }>
  ): Promise<RouteWeather[]> => {
    console.log('[OpenWeather] Fetching route weather for', route.length, 'waypoints');
    return route.map((waypoint, index) => ({
      waypoint,
      weather: {
        location: waypoint.name,
        temperature: 78 - index * 3,
        feelsLike: 80 - index * 3,
        humidity: 25 + index * 5,
        windSpeed: 8 + index * 2,
        windDirection: 225,
        condition: index < 2 ? 'clear' : index < 4 ? 'clouds' : 'rain',
        description: 'Weather along route',
        icon: 'sunny',
      },
      estimatedArrival: new Date(Date.now() + index * 3600000),
    }));
  },

  checkRouteSafety: async (
    route: Array<{ latitude: number; longitude: number }>
  ): Promise<{ safe: boolean; warnings: string[] }> => {
    console.log('[OpenWeather] Checking route safety');
    return { safe: true, warnings: [] };
  },
};

client/app/(onboarding)/invite-code.tsx.content:
import React, { useState, useRef } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  KeyboardAvoidingView,
  Platform,
  ScrollView,
  Animated,
  TextInput,
} from 'react-native';
import { useRouter } from '@/hooks/useRouterCompat';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { colors, typography, spacing, borderRadius, shadows, VALID_INVITE_CODES } from '@/constants/theme';
import { Button } from '@/components/ui/Button';
import { GlassCard } from '@/components/ui/GlassCard';
import { NatureBackground } from '@/components/ui/NatureBackground';

export default function InviteCodeScreen() {
  const router = useRouter();
  const insets = useSafeAreaInsets();
  const [inviteCode, setInviteCode] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showWaitlist, setShowWaitlist] = useState(false);
  const [email, setEmail] = useState('');
  const [waitlistSubmitted, setWaitlistSubmitted] = useState(false);

  const waitlistAnim = useRef(new Animated.Value(0)).current;
  const shakeAnim = useRef(new Animated.Value(0)).current;

  const handleVerifyCode = async () => {
    if (!inviteCode.trim()) {
      setError('Please enter an invite code');
      triggerShake();
      return;
    }

    setLoading(true);
    setError('');

    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 800));

    // Validate against VALID_INVITE_CODES
    const isValid = VALID_INVITE_CODES.includes(inviteCode.toUpperCase().trim());

    if (isValid) {
      // Success - proceed to next step
      router.push('/(onboarding)/phone-auth');
    } else {
      // Invalid code - show waitlist
      setError('Invalid invite code');
      triggerShake();
      setTimeout(() => {
        showWaitlistPanel();
      }, 500);
    }

    setLoading(false);
  };

  const triggerShake = () => {
    Animated.sequence([
      Animated.timing(shakeAnim, { toValue: 10, duration: 50, useNativeDriver: true }),
      Animated.timing(shakeAnim, { toValue: -10, duration: 50, useNativeDriver: true }),
      Animated.timing(shakeAnim, { toValue: 10, duration: 50, useNativeDriver: true }),
      Animated.timing(shakeAnim, { toValue: 0, duration: 50, useNativeDriver: true }),
    ]).start();
  };

  const showWaitlistPanel = () => {
    setShowWaitlist(true);
    Animated.spring(waitlistAnim, {
      toValue: 1,
      tension: 50,
      friction: 8,
      useNativeDriver: true,
    }).start();
  };

  const hideWaitlistPanel = () => {
    Animated.timing(waitlistAnim, {
      toValue: 0,
      duration: 200,
      useNativeDriver: true,
    }).start(() => {
      setShowWaitlist(false);
      setError('');
    });
  };

  const handleWaitlistSubmit = async () => {
    if (!email.trim()) return;

    // Simulate submission
    setLoading(true);
    await new Promise(resolve => setTimeout(resolve, 1000));
    setLoading(false);
    setWaitlistSubmitted(true);
  };

  return (
    <NatureBackground variant="forest" overlay overlayOpacity={0.45}>
      <KeyboardAvoidingView
        style={styles.container}
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
      >
        <ScrollView
          contentContainerStyle={[
            styles.scrollContent,
            { paddingTop: insets.top + spacing.lg, paddingBottom: insets.bottom + spacing.xl },
          ]}
          keyboardShouldPersistTaps="handled"
        >
          {/* Header */}
          <TouchableOpacity
            style={styles.backButton}
            onPress={() => router.back()}
          >
            <Ionicons name="arrow-back" size={24} color={colors.text.inverse} />
          </TouchableOpacity>

          {/* Progress Indicator */}
          <View style={styles.progressContainer}>
            <View style={[styles.progressBar, styles.progressActive]} />
            <View style={styles.progressBar} />
            <View style={styles.progressBar} />
            <View style={styles.progressBar} />
          </View>

          <Text style={styles.stepLabel}>Step 1 of 4</Text>

          {/* Title Section */}
          <View style={styles.titleSection}>
            <Text style={styles.logoText}>WilderGo</Text>
            <Text style={styles.title}>Secure Onboarding</Text>
            <Text style={styles.subtitle}>
              Enter your invite code to join our community of verified nomads
            </Text>
          </View>

          {/* Invite Code Input Card */}
          <GlassCard variant="medium" padding="lg" style={styles.inputCard}>
            <View style={styles.inputHeader}>
              <View style={styles.inputIconContainer}>
                <Ionicons name="ticket" size={24} color={colors.ember[500]} />
              </View>
              <Text style={styles.inputLabel}>Enter Invite Code</Text>
            </View>

            <Animated.View style={{ transform: [{ translateX: shakeAnim }] }}>
              <View style={[styles.codeInputContainer, error && styles.codeInputError]}>
                <TextInput
                  style={styles.codeInput}
                  placeholder="WILDER2024"
                  placeholderTextColor={colors.bark[300]}
                  value={inviteCode}
                  onChangeText={(text) => {
                    setInviteCode(text.toUpperCase());
                    setError('');
                  }}
                  autoCapitalize="characters"
                  autoCorrect={false}
                  maxLength={20}
                />
              </View>
            </Animated.View>

            {error && (
              <View style={styles.errorContainer}>
                <Ionicons name="alert-circle" size={16} color={colors.ember[500]} />
                <Text style={styles.errorText}>{error}</Text>
              </View>
            )}

            <View style={styles.hintContainer}>
              <Ionicons name="information-circle-outline" size={16} color={colors.bark[400]} />
              <Text style={styles.hintText}>
                Invite codes are provided by existing community members
              </Text>
            </View>
          </GlassCard>

          {/* Request Code Option */}
          <TouchableOpacity style={styles.requestCodeButton} onPress={showWaitlistPanel}>
            <Text style={styles.requestCodeText}>Don&apos;t have a code? </Text>
            <Text style={styles.requestCodeLink}>Request Access</Text>
          </TouchableOpacity>

          {/* CTA Button */}
          <View style={styles.ctaSection}>
            <Button
              title="Join the Convoy"
              onPress={handleVerifyCode}
              variant="ember"
              size="lg"
              fullWidth
              loading={loading}
              disabled={!inviteCode.trim() || loading}
              icon={<Ionicons name="arrow-forward" size={20} color={colors.text.inverse} />}
              iconPosition="right"
            />
          </View>

          {/* Trust Badges */}
          <View style={styles.trustSection}>
            <GlassCard variant="light" padding="sm" style={styles.trustBadge}>
              <Ionicons name="shield-checkmark" size={16} color={colors.moss[500]} />
              <Text style={styles.trustText}>Vetted Community</Text>
            </GlassCard>
            <GlassCard variant="light" padding="sm" style={styles.trustBadge}>
              <Ionicons name="lock-closed" size={16} color={colors.moss[500]} />
              <Text style={styles.trustText}>Privacy First</Text>
            </GlassCard>
          </View>
        </ScrollView>

        {/* Waitlist Panel Overlay */}
        {showWaitlist && (
          <Animated.View
            style={[
              styles.waitlistOverlay,
              {
                opacity: waitlistAnim,
              },
            ]}
          >
            <TouchableOpacity
              style={styles.waitlistBackdrop}
              activeOpacity={1}
              onPress={hideWaitlistPanel}
            />
            <Animated.View
              style={[
                styles.waitlistPanel,
                {
                  transform: [
                    {
                      translateY: waitlistAnim.interpolate({
                        inputRange: [0, 1],
                        outputRange: [300, 0],
                      }),
                    },
                  ],
                },
              ]}
            >
              <GlassCard variant="frost" padding="xl">
                {/* Close Button */}
                <TouchableOpacity style={styles.closeButton} onPress={hideWaitlistPanel}>
                  <Ionicons name="close" size={24} color={colors.bark[500]} />
                </TouchableOpacity>

                {!waitlistSubmitted ? (
                  <>
                    {/* Waitlist Icon */}
                    <View style={styles.waitlistIconContainer}>
                      <View style={styles.waitlistIcon}>
                        <Ionicons name="hourglass-outline" size={36} color={colors.ember[500]} />
