                    </Text>

                    {/* Email Input */}
                    <View style={styles.waitlistInputContainer}>
                      <Ionicons name="mail-outline" size={20} color={colors.bark[400]} />
                      <TextInput
                        style={styles.waitlistInput}
                        placeholder="your@email.com"
                        placeholderTextColor={colors.bark[300]}
                        value={email}
                        onChangeText={setEmail}
                        keyboardType="email-address"
                        autoCapitalize="none"
                        autoCorrect={false}
                      />
                    </View>

                    <Button
                      title="Join Waitlist"
                      onPress={handleWaitlistSubmit}
                      variant="primary"
                      size="lg"
                      fullWidth
                      loading={loading}
                      disabled={!email.trim() || loading}
                    />

                    {/* Position in Line */}
                    <View style={styles.positionContainer}>
                      <Text style={styles.positionText}>
                        <Text style={styles.positionNumber}>1,247</Text> nomads ahead of you
                      </Text>
                    </View>
                  </>
                ) : (
                  <>
                    {/* Success State */}
                    <View style={styles.waitlistIconContainer}>
                      <View style={[styles.waitlistIcon, { backgroundColor: colors.moss[500] + '20' }]}>
                        <Ionicons name="checkmark-circle" size={40} color={colors.moss[500]} />
                      </View>
                    </View>

                    <Text style={styles.waitlistTitle}>You&apos;re on the List!</Text>
                    <Text style={styles.waitlistSubtitle}>
                      We&apos;ll send you an invite code as soon as a spot opens up. Keep your eyes on your inbox!
                    </Text>

                    <View style={styles.successInfo}>
                      <View style={styles.successRow}>
                        <Ionicons name="mail" size={18} color={colors.moss[500]} />
                        <Text style={styles.successText}>{email}</Text>
                      </View>
                      <View style={styles.successRow}>
                        <Ionicons name="trending-up" size={18} color={colors.ember[500]} />
                        <Text style={styles.successText}>Position #1,248</Text>
                      </View>
                    </View>

                    <Button
                      title="Got It"
                      onPress={hideWaitlistPanel}
                      variant="ghost"
                      size="md"
                      fullWidth
                    />
                  </>
                )}
              </GlassCard>
            </Animated.View>
          </Animated.View>
        )}
      </KeyboardAvoidingView>
    </NatureBackground>
  );
}

