/**
 * WilderGo Weather Layer
 * Visual overlay showing weather conditions for nomad planning
 * Features:
 * - Weather condition overlay
 * - Temperature display
 * - Wind indicators
 * - Weather alerts
 * - 5-day forecast preview
 */

import React, { useState, useMemo, useRef, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Animated,
  Platform,
  Modal,
  ScrollView,
  Dimensions,
} from 'react-native';
import { BlurView } from 'expo-blur';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import {
  colors,
  borderRadius,
  spacing,
  typography,
  shadows,
  blur,
} from '@/constants/theme';
import {
  WeatherData,
  WeatherAlert,
  WeatherCondition,
  weatherConditionConfig,
  getWeatherForLocation,
  getWeatherAlerts,
  getWeatherOverlayStyle,
} from '@/services/map/advancedMapService';

const { width: SCREEN_WIDTH } = Dimensions.get('window');

interface WeatherLayerProps {
  latitude: number;
  longitude: number;
  showOverlay?: boolean;
  onWeatherPress?: () => void;
}

// Weather widget shown on map
export const WeatherWidget: React.FC<WeatherLayerProps> = ({
  latitude,
  longitude,
  showOverlay = false,
  onWeatherPress,
}) => {
  const [expanded, setExpanded] = useState(false);
  const expandAnim = useRef(new Animated.Value(0)).current;
  const pulseAnim = useRef(new Animated.Value(1)).current;

  const weather = useMemo(
    () => getWeatherForLocation(latitude, longitude),
    [latitude, longitude]
  );

  const alerts = useMemo(
    () => getWeatherAlerts(latitude, longitude),
    [latitude, longitude]
  );

  const hasAlerts = alerts.length > 0;

  // Pulse animation for alerts
  useEffect(() => {
    if (hasAlerts) {
      const pulse = Animated.loop(
        Animated.sequence([
          Animated.timing(pulseAnim, {
            toValue: 1.1,
            duration: 800,
            useNativeDriver: true,
          }),
          Animated.timing(pulseAnim, {
            toValue: 1,
            duration: 800,
            useNativeDriver: true,
          }),
        ])
      );
      pulse.start();
      return () => pulse.stop();
    }
  }, [hasAlerts, pulseAnim]);

  // Expand/collapse animation
  useEffect(() => {
    Animated.spring(expandAnim, {
      toValue: expanded ? 1 : 0,
      useNativeDriver: false,
      tension: 100,
      friction: 12,
    }).start();
  }, [expanded, expandAnim]);

  if (!weather) return null;

  const config = weatherConditionConfig[weather.condition];
  const widgetHeight = expandAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [56, 200],
  });

  const ContainerWrapper = Platform.OS === 'ios' ? BlurView : View;
  const containerProps = Platform.OS === 'ios'
    ? { tint: 'light' as const, intensity: blur.medium }
    : {};

  return (
    <Animated.View style={[styles.widgetContainer, { height: widgetHeight }]}>
      <ContainerWrapper {...containerProps} style={styles.widget}>
        <TouchableOpacity
          style={styles.widgetHeader}
          onPress={() => setExpanded(!expanded)}
          activeOpacity={0.8}
        >
          <View style={styles.weatherMain}>
            <View style={[styles.weatherIconBg, { backgroundColor: config.color + '20' }]}>
              <Ionicons
                name={config.icon as keyof typeof Ionicons.glyphMap}
                size={24}
                color={config.color}
              />
            </View>
            <View style={styles.weatherInfo}>
              <Text style={styles.temperature}>{weather.temperature}°F</Text>
              <Text style={styles.condition}>{config.label}</Text>
            </View>
          </View>

          <View style={styles.weatherMeta}>
            <View style={styles.metaItem}>
              <Ionicons name="water-outline" size={14} color={colors.bark[400]} />
              <Text style={styles.metaText}>{weather.humidity}%</Text>
            </View>
            <View style={styles.metaItem}>
              <Ionicons name="leaf-outline" size={14} color={colors.bark[400]} />
              <Text style={styles.metaText}>{weather.windSpeed} mph</Text>
            </View>
          </View>

          {hasAlerts && (
            <Animated.View
              style={[
                styles.alertBadge,
                { transform: [{ scale: pulseAnim }] },
              ]}
            >
              <Ionicons name="warning" size={12} color={colors.text.inverse} />
            </Animated.View>
          )}

          <Ionicons
            name={expanded ? 'chevron-up' : 'chevron-down'}
            size={20}
            color={colors.bark[400]}
          />
        </TouchableOpacity>

        {/* Expanded content */}
        {expanded && (
          <Animated.View style={styles.expandedContent}>
            {/* Wind info */}
            <View style={styles.windInfo}>
              <Text style={styles.sectionLabel}>Wind</Text>
              <View style={styles.windDetails}>
                <View style={styles.windDirection}>
                  <Ionicons name="compass" size={20} color={colors.forestGreen[500]} />
                  <Text style={styles.windDirectionText}>{weather.windDirection}</Text>
                </View>
                <Text style={styles.windSpeed}>{weather.windSpeed} mph</Text>
              </View>
            </View>

            {/* Forecast preview */}
            {weather.forecast && (
              <View style={styles.forecastContainer}>
                <Text style={styles.sectionLabel}>5-Day Forecast</Text>
                <ScrollView horizontal showsHorizontalScrollIndicator={false}>
                  <View style={styles.forecastRow}>
                    {weather.forecast.map((day, index) => {
                      const dayConfig = weatherConditionConfig[day.condition];
                      return (
                        <View key={index} style={styles.forecastDay}>
                          <Text style={styles.forecastDayName}>{day.day}</Text>
                          <Ionicons
                            name={dayConfig.icon as keyof typeof Ionicons.glyphMap}
                            size={18}
                            color={dayConfig.color}
                          />
                          <Text style={styles.forecastHigh}>{day.high}°</Text>
                          <Text style={styles.forecastLow}>{day.low}°</Text>
                        </View>
                      );
                    })}
                  </View>
                </ScrollView>
              </View>
            )}

            {/* Alerts */}
            {hasAlerts && (
              <View style={styles.alertsContainer}>
                {alerts.map((alert) => (
                  <View
                    key={alert.id}
                    style={[
                      styles.alertItem,
                      {
                        backgroundColor:
                          alert.severity === 'severe' || alert.severity === 'extreme'
                            ? colors.emergency.redLight
                            : colors.sunsetOrange[50],
                      },
                    ]}
                  >
                    <Ionicons
                      name="warning"
                      size={16}
                      color={
                        alert.severity === 'severe' || alert.severity === 'extreme'
                          ? colors.emergency.red
                          : colors.sunsetOrange[500]
                      }
                    />
                    <View style={styles.alertContent}>
                      <Text style={styles.alertTitle}>{alert.title}</Text>
                      <Text style={styles.alertDescription} numberOfLines={2}>
                        {alert.description}
                      </Text>
                    </View>
                  </View>
                ))}
              </View>
            )}
          </Animated.View>
        )}
      </ContainerWrapper>
    </Animated.View>
  );
};

// Weather overlay for the entire map
interface WeatherOverlayProps {
  condition: WeatherCondition;
  visible: boolean;
}

export const WeatherOverlay: React.FC<WeatherOverlayProps> = ({
  condition,
  visible,
}) => {
  const opacityAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    Animated.timing(opacityAnim, {
      toValue: visible ? 1 : 0,
      duration: 500,
      useNativeDriver: true,
    }).start();
  }, [visible, opacityAnim]);

  const config = weatherConditionConfig[condition];

  return (
    <Animated.View
      style={[
        styles.overlay,
        { backgroundColor: config.overlayColor, opacity: opacityAnim },
      ]}
      pointerEvents="none"
    />
  );
};

// Toggle button for weather layer
interface WeatherToggleProps {
  isEnabled: boolean;
  onToggle: () => void;
  hasAlerts?: boolean;
}

export const WeatherToggle: React.FC<WeatherToggleProps> = ({
  isEnabled,
  onToggle,
  hasAlerts = false,
}) => {
  const pulseAnim = useRef(new Animated.Value(1)).current;

  useEffect(() => {
    if (hasAlerts) {
      const pulse = Animated.loop(
        Animated.sequence([
          Animated.timing(pulseAnim, {
            toValue: 1.15,
            duration: 600,
            useNativeDriver: true,
          }),
          Animated.timing(pulseAnim, {
            toValue: 1,
            duration: 600,
            useNativeDriver: true,
          }),
        ])
      );
      pulse.start();
      return () => pulse.stop();
    }
  }, [hasAlerts, pulseAnim]);

  return (
    <Animated.View style={{ transform: [{ scale: hasAlerts ? pulseAnim : 1 }] }}>
      <TouchableOpacity
        style={[
          styles.toggleButton,
          isEnabled && styles.toggleButtonActive,
        ]}
        onPress={onToggle}
        activeOpacity={0.8}
      >
        <Ionicons
          name="cloudy"
          size={20}
          color={isEnabled ? colors.text.inverse : colors.bark[500]}
        />
        {hasAlerts && (
          <View style={styles.alertDot} />
        )}
      </TouchableOpacity>
    </Animated.View>
  );
};

// Full weather details modal
interface WeatherDetailsModalProps {
  visible: boolean;
  weather: WeatherData | null;
  alerts: WeatherAlert[];
  onClose: () => void;
}

export const WeatherDetailsModal: React.FC<WeatherDetailsModalProps> = ({
  visible,
  weather,
  alerts,
  onClose,
}) => {
  if (!weather) return null;

  const config = weatherConditionConfig[weather.condition];

  return (
    <Modal visible={visible} animationType="slide" transparent>
      <View style={styles.modalContainer}>
        <View style={styles.modalBackdrop}>
          <LinearGradient
            colors={[config.color + '40', colors.background.primary]}
            start={{ x: 0, y: 0 }}
            end={{ x: 0, y: 0.3 }}
            style={styles.modalContent}
          >
            <View style={styles.modalHeader}>
              <Text style={styles.modalTitle}>Weather Details</Text>
              <TouchableOpacity onPress={onClose}>
                <Ionicons name="close" size={24} color={colors.bark[500]} />
              </TouchableOpacity>
            </View>

            <ScrollView style={styles.modalBody} showsVerticalScrollIndicator={false}>
              {/* Current conditions */}
              <View style={styles.currentConditions}>
                <View style={[styles.largeIconBg, { backgroundColor: config.color + '20' }]}>
                  <Ionicons
                    name={config.icon as keyof typeof Ionicons.glyphMap}
                    size={64}
                    color={config.color}
                  />
                </View>
                <Text style={styles.largeTemperature}>{weather.temperature}°F</Text>
                <Text style={styles.largeCondition}>{config.label}</Text>
                <Text style={styles.feelsLike}>Feels like {weather.feelsLike}°F</Text>
              </View>

              {/* Details grid */}
              <View style={styles.detailsGrid}>
                <View style={styles.detailItem}>
                  <Ionicons name="water-outline" size={24} color={colors.deepTeal[500]} />
                  <Text style={styles.detailValue}>{weather.humidity}%</Text>
                  <Text style={styles.detailLabel}>Humidity</Text>
                </View>
                <View style={styles.detailItem}>
                  <Ionicons name="leaf-outline" size={24} color={colors.forestGreen[500]} />
                  <Text style={styles.detailValue}>{weather.windSpeed} mph</Text>
                  <Text style={styles.detailLabel}>Wind</Text>
                </View>
                <View style={styles.detailItem}>
                  <Ionicons name="sunny-outline" size={24} color={colors.sunsetOrange[500]} />
                  <Text style={styles.detailValue}>{weather.uvIndex}</Text>
                  <Text style={styles.detailLabel}>UV Index</Text>
                </View>
                <View style={styles.detailItem}>
                  <Ionicons name="eye-outline" size={24} color={colors.bark[400]} />
                  <Text style={styles.detailValue}>{weather.visibility} mi</Text>
                  <Text style={styles.detailLabel}>Visibility</Text>
                </View>
              </View>

              {/* Forecast */}
              {weather.forecast && (
                <View style={styles.fullForecast}>
                  <Text style={styles.forecastTitle}>5-Day Forecast</Text>
                  {weather.forecast.map((day, index) => {
                    const dayConfig = weatherConditionConfig[day.condition];
                    return (
                      <View key={index} style={styles.fullForecastDay}>
                        <Text style={styles.fullForecastDayName}>{day.day}</Text>
                        <View style={styles.fullForecastIcon}>
                          <Ionicons
                            name={dayConfig.icon as keyof typeof Ionicons.glyphMap}
                            size={24}
                            color={dayConfig.color}
                          />
                        </View>
                        <Text style={styles.fullForecastCondition}>{dayConfig.label}</Text>
                        <View style={styles.fullForecastTemps}>
                          <Text style={styles.fullForecastHigh}>{day.high}°</Text>
                          <Text style={styles.fullForecastLow}>{day.low}°</Text>
                        </View>
                        <View style={styles.fullForecastPrecip}>
                          <Ionicons name="water" size={12} color={colors.deepTeal[400]} />
                          <Text style={styles.fullForecastPrecipText}>{day.precipChance}%</Text>
                        </View>
                      </View>
                    );
                  })}
                </View>
              )}

              {/* Alerts */}
              {alerts.length > 0 && (
                <View style={styles.fullAlerts}>
                  <Text style={styles.alertsTitle}>Active Alerts</Text>
                  {alerts.map((alert) => (
                    <View key={alert.id} style={styles.fullAlertItem}>
                      <View style={styles.fullAlertHeader}>
                        <Ionicons
                          name="warning"
                          size={20}
                          color={
                            alert.severity === 'severe' || alert.severity === 'extreme'
                              ? colors.emergency.red
                              : colors.sunsetOrange[500]
                          }
                        />
                        <Text style={styles.fullAlertTitle}>{alert.title}</Text>
                        <View
                          style={[
                            styles.severityBadge,
                            {
                              backgroundColor:
                                alert.severity === 'severe' || alert.severity === 'extreme'
                                  ? colors.emergency.redLight
                                  : colors.sunsetOrange[100],
                            },
                          ]}
                        >
                          <Text
                            style={[
                              styles.severityText,
                              {
                                color:
                                  alert.severity === 'severe' || alert.severity === 'extreme'
                                    ? colors.emergency.red
                                    : colors.sunsetOrange[600],
                              },
                            ]}
                          >
                            {alert.severity.toUpperCase()}
                          </Text>
                        </View>
                      </View>
                      <Text style={styles.fullAlertDescription}>{alert.description}</Text>
                    </View>
                  ))}
                </View>
              )}
            </ScrollView>
          </LinearGradient>
        </View>
      </View>
    </Modal>
  );
};

