export default function DiscoveryScreen() {
  const router = useRouter();
  const insets = useSafeAreaInsets();
  const { mode, setMode, theme, isPremium, isModeAllowed } = useMode();
  const { user } = useAuth();
  const [currentIndex, setCurrentIndex] = useState(0);
  const [showPaywall, setShowPaywall] = useState(false);
  const [showConnectModal, setShowConnectModal] = useState(false);
  const [selectedNomad, setSelectedNomad] = useState<FriendsProfile | null>(null);
  const [connectionSent, setConnectionSent] = useState(false);
  const [showPortfolioModal, setShowPortfolioModal] = useState<BuilderProfile | null>(null);
  const [showBookingModal, setShowBookingModal] = useState<BuilderProfile | null>(null);

  // Handler for messaging a builder
  const handleMessageBuilder = (builder: BuilderProfile) => {
    router.push('Messages');
  };

  // Handler for viewing all builders
  const handleViewAllBuilders = () => {
    // In a real app, navigate to a full builders directory
    console.log('View all builders');
  };

  // Button press animation
  const buttonScaleAnim = useRef(new Animated.Value(1)).current;

  const animateButtonPress = (callback?: () => void) => {
    Animated.sequence([
      Animated.timing(buttonScaleAnim, {
        toValue: 0.92,
        duration: 100,
        useNativeDriver: true,
      }),
      Animated.timing(buttonScaleAnim, {
        toValue: 1,
        duration: 100,
        useNativeDriver: true,
      }),
    ]).start(() => {
      if (callback) callback();
    });
  };

  const handleConnectNomad = (profile: FriendsProfile) => {
    setSelectedNomad(profile);
    setConnectionSent(false);
    setShowConnectModal(true);
  };

  const handleMessageNomad = (profile: FriendsProfile) => {
    router.push('/messages');
  };

  const sendConnectionRequest = () => {
    setConnectionSent(true);
    setTimeout(() => {
      setShowConnectModal(false);
      setSelectedNomad(null);
    }, 1500);
  };

  // Ember glow animation for route overlap
  const glowAnim = useRef(new Animated.Value(0.3)).current;
  const pulseAnim = useRef(new Animated.Value(1)).current;

  useEffect(() => {
    // Glow pulsing animation
    Animated.loop(
      Animated.sequence([
        Animated.parallel([
          Animated.timing(glowAnim, {
            toValue: 0.6,
            duration: 1500,
            useNativeDriver: true,
          }),
          Animated.timing(pulseAnim, {
            toValue: 1.1,
            duration: 1500,
            useNativeDriver: true,
          }),
        ]),
        Animated.parallel([
          Animated.timing(glowAnim, {
            toValue: 0.3,
            duration: 1500,
            useNativeDriver: true,
          }),
          Animated.timing(pulseAnim, {
            toValue: 1,
            duration: 1500,
            useNativeDriver: true,
          }),
        ]),
      ])
    ).start();
  }, [glowAnim, pulseAnim]);

  const position = useRef(new Animated.ValueXY()).current;
  const rotate = position.x.interpolate({
    inputRange: [-width / 2, 0, width / 2],
    outputRange: ['-10deg', '0deg', '10deg'],
    extrapolate: 'clamp',
  });

  const likeOpacity = position.x.interpolate({
    inputRange: [0, width / 4],
    outputRange: [0, 1],
    extrapolate: 'clamp',
  });

  const nopeOpacity = position.x.interpolate({
    inputRange: [-width / 4, 0],
    outputRange: [1, 0],
    extrapolate: 'clamp',
  });

  const nextCardScale = position.x.interpolate({
    inputRange: [-width / 2, 0, width / 2],
    outputRange: [1, 0.92, 1],
    extrapolate: 'clamp',
  });

  const panResponder = useRef(
    PanResponder.create({
      onStartShouldSetPanResponder: () => true,
      onMoveShouldSetPanResponder: () => true,
      onPanResponderMove: (_, gestureState) => {
        position.setValue({ x: gestureState.dx, y: gestureState.dy });
      },
      onPanResponderRelease: (_, gestureState) => {
        // Check velocity first - quick flicks work even with less distance
        const isQuickSwipeRight = gestureState.vx > SWIPE_VELOCITY_THRESHOLD;
        const isQuickSwipeLeft = gestureState.vx < -SWIPE_VELOCITY_THRESHOLD;

        if (gestureState.dx > SWIPE_THRESHOLD || isQuickSwipeRight) {
          swipeRight();
        } else if (gestureState.dx < -SWIPE_THRESHOLD || isQuickSwipeLeft) {
          swipeLeft();
        } else {
          resetPosition();
        }
      },
    })
  ).current;

  const swipeRight = () => {
    if (mode === 'dating' && !isModeAllowed('swipe')) {
      resetPosition();
      setShowPaywall(true);
      return;
    }

    Animated.timing(position, {
      toValue: { x: width + 100, y: 0 },
      duration: 200, // Faster animation for snappier feel
      useNativeDriver: false,
    }).start(() => onSwipeComplete('like'));
  };

  const swipeLeft = () => {
    Animated.timing(position, {
      toValue: { x: -width - 100, y: 0 },
      duration: 200, // Faster animation for snappier feel
      useNativeDriver: false,
    }).start(() => onSwipeComplete('nope'));
  };

  const resetPosition = () => {
    Animated.spring(position, {
      toValue: { x: 0, y: 0 },
      tension: 80, // Higher tension = faster spring back
      friction: 8,
      useNativeDriver: false,
    }).start();
  };

  const onSwipeComplete = (_action: 'like' | 'nope') => {
    setCurrentIndex((prev) => prev + 1);
    position.setValue({ x: 0, y: 0 });
  };

  const handleModeChange = (newMode: AppMode) => {
    // Allow all modes - show premium badge on dating but don't block access
    setMode(newMode);
    setCurrentIndex(0);
  };

  const getModeTitle = () => {
    switch (mode) {
      case 'dating':
        return 'Dating';
      case 'friends':
        return 'Friends';
      case 'builder':
        return 'Builders';
    }
  };

  const getBackgroundVariant = () => {
    switch (mode) {
      case 'dating':
        return 'sunset';
      case 'friends':
        return 'forest';
      case 'builder':
        return 'canyon';
      default:
        return 'forest';
    }
  };

  // Get current profile based on mode
  const getCurrentDatingProfile = () => datingProfiles[currentIndex % datingProfiles.length];
  const getNextDatingProfile = () => datingProfiles[(currentIndex + 1) % datingProfiles.length];
  const getCurrentFriendsProfile = () => friendsProfiles[currentIndex % friendsProfiles.length];
  const getNextFriendsProfile = () => friendsProfiles[(currentIndex + 1) % friendsProfiles.length];

  // Render Dating Mode - Swipe cards with route overlap
  const renderDatingMode = () => {
    const currentProfile = getCurrentDatingProfile();
    const nextProfile = getNextDatingProfile();

    return (
      <>
        {/* Cards Stack */}
        <View style={styles.cardsContainer}>
          {/* Next Card (underneath) */}
          <Animated.View
            style={[
              styles.card,
              styles.nextCard,
              { transform: [{ scale: nextCardScale }] },
            ]}
          >
            <DatingProfileCard
              profile={nextProfile}
              compact
            />
          </Animated.View>

          {/* Current Card (on top) */}
          <Animated.View
            style={[
              styles.card,
              {
                transform: [
                  { translateX: position.x },
                  { translateY: position.y },
                  { rotate },
                ],
              },
            ]}
            {...panResponder.panHandlers}
          >
            {/* Like Label */}
            <Animated.View
              style={[styles.labelContainer, styles.likeLabel, { opacity: likeOpacity }]}
            >
              <Text style={styles.likeLabelText}>MATCH</Text>
            </Animated.View>

            {/* Nope Label */}
            <Animated.View
              style={[styles.labelContainer, styles.nopeLabel, { opacity: nopeOpacity }]}
            >
              <Text style={[styles.labelText, { color: colors.clay[600] }]}>PASS</Text>
            </Animated.View>

            <DatingProfileCard
              profile={currentProfile}
              onLike={swipeRight}
              onPass={swipeLeft}
              onSuperLike={() => {}}
            />
          </Animated.View>
        </View>

        {/* Action Buttons */}
        <View style={styles.actionsContainer}>
          <TouchableOpacity
            style={[styles.actionButton, styles.nopeButton]}
            onPress={swipeLeft}
          >
            <Ionicons name="close" size={28} color={colors.clay[500]} />
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.actionButton, styles.superButton]}
            onPress={() => {}}
          >
            <Ionicons name="star" size={24} color={colors.ember[500]} />
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.actionButton, styles.likeButton]}
            onPress={swipeRight}
          >
            <Ionicons name="heart" size={28} color={colors.ember[500]} />
          </TouchableOpacity>
        </View>
      </>
    );
  };

  // Render Friends Mode - Scrollable list (distinct from Dating swipe cards)
  const renderFriendsMode = () => {
    return (
      <ScrollView
        style={styles.friendsScrollView}
        contentContainerStyle={[
          styles.friendsScrollContent,
          { paddingBottom: insets.bottom + 100 }
        ]}
        showsVerticalScrollIndicator={false}
        nestedScrollEnabled={true}
      >
        {/* Nearby Adventures - Activity Events */}
        <OutdoorEvents />

        {/* Nearby Nomads Header */}
        <View style={styles.friendsSectionHeader}>
          <Text style={styles.friendsSectionTitle}>Nearby Nomads</Text>
          <Text style={styles.friendsSectionSubtitle}>Connect based on shared activities</Text>
        </View>

        {/* Friends Grid - Scrollable List */}
        {friendsProfiles.map((profile) => (
          <View key={profile.id} style={styles.friendsCardWrapper}>
            <FriendsProfileCard
              profile={profile}
              onConnect={() => handleConnectNomad(profile)}
              onMessage={() => handleMessageNomad(profile)}
            />
          </View>
        ))}
      </ScrollView>
    );
  };

  // Render Builder Mode - Professional Directory (no swiping)
  const renderBuilderMode = () => {
    return (
      <ScrollView
        style={styles.builderScrollView}
        contentContainerStyle={[
          styles.builderScrollContent,
          { paddingBottom: insets.bottom + 100 }
        ]}
        showsVerticalScrollIndicator={false}
      >
        {/* Vetted Builders Section */}
        <View style={styles.buildersSection}>
          <View style={styles.sectionHeader}>
            <Text style={styles.sectionTitle}>Vetted Builders</Text>
            <TouchableOpacity onPress={handleViewAllBuilders}>
              <Text style={styles.viewAllText}>View All</Text>
            </TouchableOpacity>
          </View>

          {builderProfiles.map((builder) => (
            <BuilderProfileCard
              key={builder.id}
              profile={builder}
              onViewPortfolio={() => setShowPortfolioModal(builder)}
              onBookConsult={() => setShowBookingModal(builder)}
              onMessage={() => handleMessageBuilder(builder)}
            />
          ))}
        </View>

        {/* Quick Connect Section */}
        <View style={styles.quickConnectSection}>
          <Text style={styles.sectionTitle}>Quick Connect</Text>
          <ScrollView
            horizontal
            showsHorizontalScrollIndicator={false}
            contentContainerStyle={styles.quickConnectList}
          >
            {builderProfiles.map((builder) => (
              <BuilderCompactCard
                key={builder.id}
                profile={builder}
                onPress={() => setShowBookingModal(builder)}
              />
            ))}
          </ScrollView>
        </View>
      </ScrollView>
    );
  };

  return (
    <View style={styles.screenContainer}>
      <View style={[styles.container, { paddingTop: insets.top }]}>
        {/* Header */}
        <View style={styles.header}>
          <View style={styles.headerLeft}>
            <Logo size="small" variant="dark" />
            <Text style={styles.headerTitle}>{getModeTitle()}</Text>
          </View>
          <View style={styles.headerRight}>
            <GhostModeStatus onPress={() => setShowPaywall(true)} />
          </View>
        </View>

        {/* Pending Verification Banner */}
        {user && !user.selfieVerified ? (
          <View style={styles.verificationBanner}>
            <Ionicons name="time-outline" size={18} color="#7A5C00" />
            <View style={styles.verificationBannerText}>
              <Text style={styles.verificationBannerTitle}>Pending Verification</Text>
              <Text style={styles.verificationBannerSubtitle}>
                {user.selfieSubmitted
                  ? 'Your account will be verified within 24 hours.'
                  : 'Submit a selfie to get verified and unlock all features.'}
              </Text>
            </View>
          </View>
        ) : null}

        {/* Mode Toggle */}
        <View style={styles.toggleContainer}>
          <ModeToggle
            activeMode={mode}
            onModeChange={handleModeChange}
            showPremiumBadge={isPremium}
          />
        </View>

        {/* Your Passport - Editable Profile Summary */}
        <MiniPassport />

        {/* Mode-Specific Content */}
        {mode === 'dating' && renderDatingMode()}
        {mode === 'friends' && renderFriendsMode()}
        {mode === 'builder' && renderBuilderMode()}
      </View>

      {/* Premium Paywall */}
      <ConvoyPaywall
        visible={showPaywall}
        onClose={() => setShowPaywall(false)}
        onSubscribe={(success) => {
          if (success) {
            // Update premium status through context
          }
        }}
      />

      {/* Portfolio Modal */}
      <Modal
        visible={showPortfolioModal !== null}
        transparent
        animationType="fade"
        onRequestClose={() => setShowPortfolioModal(null)}
      >
        <View style={styles.modalOverlay}>
          <TouchableOpacity
            style={StyleSheet.absoluteFill}
            activeOpacity={1}
            onPress={() => setShowPortfolioModal(null)}
          />
          <View style={styles.portfolioModalContent}>
            <View style={styles.builderModalHeader}>
              <Text style={styles.builderModalTitle}>
                {showPortfolioModal?.businessName} Portfolio
              </Text>
              <TouchableOpacity onPress={() => setShowPortfolioModal(null)}>
                <Ionicons name="close" size={24} color={colors.bark[600]} />
              </TouchableOpacity>
            </View>

            <ScrollView horizontal showsHorizontalScrollIndicator={false} style={styles.portfolioScroll}>
              {showPortfolioModal?.portfolioImages?.map((image, index) => (
                <Image 
                  key={index}
                  source={{ uri: image }}
                  style={styles.portfolioImage}
                  contentFit="cover"
                />
              ))}
            </ScrollView>

            <Text style={styles.portfolioDescription}>
              {showPortfolioModal?.bio || 'Check out our recent builds and conversions.'}
            </Text>

            <TouchableOpacity
              style={styles.contactButton}
              onPress={() => {
                setShowPortfolioModal(null);
                if (showPortfolioModal) handleMessageBuilder(showPortfolioModal);
              }}
            >
              <Ionicons name="chatbubble" size={18} color={colors.text.inverse} />
              <Text style={styles.contactButtonText}>Contact Builder</Text>
            </TouchableOpacity>
          </View>
        </View>
      </Modal>

      {/* Booking Modal */}
      <Modal
        visible={showBookingModal !== null}
        transparent
        animationType="fade"
        onRequestClose={() => setShowBookingModal(null)}
      >
        <View style={styles.modalOverlay}>
          <TouchableOpacity
            style={StyleSheet.absoluteFill}
            activeOpacity={1}
            onPress={() => setShowBookingModal(null)}
          />
          <View style={styles.bookingModalContent}>
            <View style={styles.builderModalHeader}>
              <Text style={styles.builderModalTitle}>Ask for Help</Text>
              <TouchableOpacity onPress={() => setShowBookingModal(null)}>
                <Ionicons name="close" size={24} color={colors.bark[600]} />
              </TouchableOpacity>
            </View>

            {showBookingModal ? (
              <>
                <View style={styles.builderPreview}>
                  <Image 
                    source={{ uri: showBookingModal.imageUrl }}
                    style={styles.builderAvatar}
                    contentFit="cover"
                  />
                  <View>
                    <Text style={styles.builderName}>{showBookingModal.businessName}</Text>
                    <Text style={styles.builderLocation}>{showBookingModal.location}</Text>
                  </View>
                </View>

                <Text style={styles.bookingDescription}>
                  {showBookingModal.businessName} is a community helper ready to assist with your build questions.
                </Text>

                <View style={styles.bookingOptions}>
                  <TouchableOpacity 
                    style={styles.bookingOption}
                    onPress={() => {
                      setShowBookingModal(null);
                      handleMessageBuilder(showBookingModal);
                    }}
                  >
                    <Ionicons name="chatbubble-outline" size={24} color={colors.moss[600]} />
                    <Text style={styles.bookingOptionLabel}>Send Message</Text>
                    <Text style={styles.bookingOptionDesc}>Ask a quick question</Text>
                  </TouchableOpacity>

                  <TouchableOpacity 
                    style={styles.bookingOption}
                    onPress={() => setShowBookingModal(null)}
                  >
                    <Ionicons name="videocam-outline" size={24} color={colors.moss[600]} />
                    <Text style={styles.bookingOptionLabel}>Video Call</Text>
                    <Text style={styles.bookingOptionDesc}>Schedule a consultation</Text>
                  </TouchableOpacity>
                </View>
              </>
            ) : null}
          </View>
        </View>
      </Modal>

      {/* Connect Request Modal */}
      <Modal
        visible={showConnectModal}
        animationType="fade"
        transparent
        onRequestClose={() => setShowConnectModal(false)}
      >
        <View style={styles.modalOverlay}>
          {Platform.OS === 'ios' ? (
            <BlurView intensity={80} tint="dark" style={styles.connectModal}>
              <ConnectModalContent />
            </BlurView>
          ) : (
            <View style={[styles.connectModal, styles.connectModalAndroid]}>
              <ConnectModalContent />
            </View>
          )}
        </View>
      </Modal>
    </View>
  );

  function ConnectModalContent() {
    if (!selectedNomad) return null;

    return (
      <View style={styles.connectModalInner}>
        <TouchableOpacity 
          style={styles.closeModalBtn}
          onPress={() => setShowConnectModal(false)}
        >
          <Ionicons name="close" size={24} color="#FFFFFF" />
        </TouchableOpacity>

        <Image
          source={{ uri: selectedNomad.imageUrl }}
          style={styles.connectModalAvatar}
          contentFit="cover"
        />

        <Text style={styles.connectModalTitle}>
          {connectionSent ? 'Request Sent!' : `Connect with ${selectedNomad.name}?`}
        </Text>

        {connectionSent ? (
          <View style={styles.successCheckContainer}>
            <Ionicons name="checkmark-circle" size={60} color={colors.moss[500]} />
            <Text style={styles.successText}>
              {selectedNomad.name} will be notified of your connection request
            </Text>
          </View>
        ) : (
          <>
            <Text style={styles.connectModalSubtitle}>
              {selectedNomad.name} is currently in {selectedNomad.currentLocation}
            </Text>

            <View style={styles.sharedActivities}>
              <Text style={styles.sharedActivitiesLabel}>Shared Interests</Text>
              <View style={styles.sharedActivitiesList}>
                {selectedNomad.availableFor.slice(0, 3).map((activity, index) => (
                  <View key={index} style={styles.sharedActivityChip}>
                    <Text style={styles.sharedActivityText}>{activity}</Text>
                  </View>
                ))}
              </View>
            </View>

            <TouchableOpacity
              style={styles.sendConnectionBtn}
              onPress={sendConnectionRequest}
              activeOpacity={0.8}
            >
              <Ionicons name="people" size={20} color="#FFFFFF" />
              <Text style={styles.sendConnectionBtnText}>Send Connection Request</Text>
            </TouchableOpacity>

            <TouchableOpacity
              style={styles.messageInsteadBtn}
              onPress={() => {
                setShowConnectModal(false);
                handleMessageNomad(selectedNomad);
              }}
              activeOpacity={0.8}
            >
              <Ionicons name="chatbubble-outline" size={18} color={colors.moss[500]} />
              <Text style={styles.messageInsteadBtnText}>Message Instead</Text>
            </TouchableOpacity>
          </>
        )}
      </View>
    );
  }
}

