/**
 * WilderGo SOS Tab Icon
 * Animated tab icon that pulses when nearby help requests are active
 * Sunset Orange/Burnt Sienna visual language for high-urgency
 */

import React, { useEffect, useRef } from 'react';
import { View, StyleSheet, Animated } from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { colors, borderRadius, shadows } from '@/constants/theme';

interface SOSTabIconProps {
  focused: boolean;
  color: string;
  hasNearbyAlert?: boolean;
  alertPriority?: 'critical' | 'urgent' | 'assistance';
}

export const SOSTabIcon: React.FC<SOSTabIconProps> = ({
  focused,
  color,
  hasNearbyAlert = false,
  alertPriority = 'assistance',
}) => {
  const pulseScale = useRef(new Animated.Value(1)).current;
  const pulseOpacity = useRef(new Animated.Value(0)).current;
  const glowOpacity = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    if (hasNearbyAlert) {
      // Determine pulse speed based on priority
      const duration = alertPriority === 'critical' ? 500 : alertPriority === 'urgent' ? 800 : 1200;

      // Icon pulse animation
      const iconPulse = Animated.loop(
        Animated.sequence([
          Animated.timing(pulseScale, {
            toValue: 1.15,
            duration: duration / 2,
            useNativeDriver: true,
          }),
          Animated.timing(pulseScale, {
            toValue: 1,
            duration: duration / 2,
            useNativeDriver: true,
          }),
        ])
      );

      // Ring pulse animation
      const ringPulse = Animated.loop(
        Animated.sequence([
          Animated.parallel([
            Animated.timing(pulseOpacity, {
              toValue: 0.8,
              duration: 0,
              useNativeDriver: true,
            }),
            Animated.timing(pulseScale, {
              toValue: 1,
              duration: 0,
              useNativeDriver: true,
            }),
          ]),
          Animated.parallel([
            Animated.timing(pulseOpacity, {
              toValue: 0,
              duration: duration,
              useNativeDriver: true,
            }),
          ]),
        ])
      );

      // Glow animation
      const glow = Animated.loop(
        Animated.sequence([
          Animated.timing(glowOpacity, {
            toValue: 0.6,
            duration: duration,
            useNativeDriver: true,
          }),
          Animated.timing(glowOpacity, {
            toValue: 0.2,
            duration: duration,
            useNativeDriver: true,
          }),
        ])
      );

      iconPulse.start();
      ringPulse.start();
      glow.start();

      return () => {
        iconPulse.stop();
        ringPulse.stop();
        glow.stop();
      };
    } else {
      // Reset animations
      pulseScale.setValue(1);
      pulseOpacity.setValue(0);
      glowOpacity.setValue(0);
    }
  }, [hasNearbyAlert, alertPriority, pulseScale, pulseOpacity, glowOpacity]);

  const getPriorityColor = () => {
    switch (alertPriority) {
      case 'critical':
        return colors.emergency.red;
      case 'urgent':
        return colors.sunsetOrange[500];
      default:
        return colors.burntSienna[500];
    }
  };

  const iconName = focused ? 'warning' : 'warning-outline';
  const iconColor = focused ? colors.sunsetOrange[500] : color;

  return (
    <View style={styles.container}>
      {/* Animated Glow Ring */}
      {hasNearbyAlert && (
        <Animated.View
          style={[
            styles.glowRing,
            {
              opacity: glowOpacity,
              backgroundColor: getPriorityColor(),
            },
          ]}
        />
      )}

      {/* Pulse Ring */}
      {hasNearbyAlert && (
        <Animated.View
          style={[
            styles.pulseRing,
            {
              opacity: pulseOpacity,
              borderColor: getPriorityColor(),
              transform: [{ scale: pulseScale }],
            },
          ]}
        />
      )}

      {/* Icon Container */}
      <View style={[styles.iconContainer, focused && styles.iconContainerActive]}>
        <Animated.View style={{ transform: [{ scale: hasNearbyAlert ? pulseScale : 1 }] }}>
          <Ionicons
            name={iconName}
            size={24}
            color={hasNearbyAlert ? getPriorityColor() : iconColor}
          />
        </Animated.View>

        {/* Active Indicator */}
        {focused && (
          <View
            style={[
              styles.activeIndicator,
              { backgroundColor: hasNearbyAlert ? getPriorityColor() : colors.sunsetOrange[500] },
            ]}
          />
        )}

        {/* Alert Badge */}
        {hasNearbyAlert && (
          <View style={[styles.alertBadge, { backgroundColor: getPriorityColor() }]}>
            <Ionicons name="alert" size={8} color="#FFF" />
          </View>
        )}
      </View>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    width: 48,
    height: 36,
    justifyContent: 'center',
    alignItems: 'center',
    position: 'relative',
  },
  glowRing: {
    position: 'absolute',
    width: 44,
    height: 44,
    borderRadius: 22,
    opacity: 0.3,
  },
  pulseRing: {
    position: 'absolute',
    width: 40,
    height: 40,
    borderRadius: 20,
    borderWidth: 2,
  },
  iconContainer: {
    width: 48,
    height: 36,
    justifyContent: 'center',
    alignItems: 'center',
    borderRadius: borderRadius.lg,
    position: 'relative',
  },
  iconContainerActive: {
    backgroundColor: colors.glass.whiteSubtle,
  },
  activeIndicator: {
    position: 'absolute',
    bottom: -4,
    width: 4,
    height: 4,
    borderRadius: 2,
    ...shadows.glassSubtle,
  },
  alertBadge: {
    position: 'absolute',
    top: 0,
    right: 4,
    width: 14,
    height: 14,
    borderRadius: 7,
    justifyContent: 'center',
    alignItems: 'center',
    borderWidth: 1.5,
    borderColor: 'rgba(30, 24, 20, 0.95)',
  },
});

export default SOSTabIcon;

client/components/map/AIRoutePlanner.tsx.content:
/**
 * WilderGo AI Route Planner
 * Uses AI to analyze and suggest optimal social routes
 * Highlights routes with highest nomadic density and social overlap
 */

import React, { useState, useRef, useEffect, useCallback } from 'react';
import {
  View,
  StyleSheet,
  Text,
  TouchableOpacity,
  ScrollView,
  Animated,
  Dimensions,
  Platform,
} from 'react-native';
import { BlurView } from 'expo-blur';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { colors, typography, spacing, borderRadius } from '@/constants/theme';

// Stub hook for text generation (AI disabled in this environment)
function useTextGeneration(_options?: { onError?: (err: Error) => void }) {
  const [isLoading, setIsLoading] = useState(false);
  const generateText = useCallback(async (_prompt: string): Promise<string> => {
    setIsLoading(true);
    await new Promise(resolve => setTimeout(resolve, 1000));
    setIsLoading(false);
    return '';
  }, []);
  return { generateText, isLoading };
}
import { GlassCard } from '@/components/ui/GlassCard';
import { Button } from '@/components/ui/Button';
import { getSmartRouteSuggestions, SmartRouteSuggestion } from '@/services/map/mapService';
import { SmartRouteWeather } from '@/components/map/SmartRouteWeather';

const { height: SCREEN_HEIGHT } = Dimensions.get('window');

interface AIRoutePlannerProps {
  visible: boolean;
  onClose: () => void;
  onRouteSelect?: (route: SmartRouteSuggestion) => void;
  currentLocation?: { latitude: number; longitude: number };
  destination?: { latitude: number; longitude: number; name?: string };
}

export const AIRoutePlanner: React.FC<AIRoutePlannerProps> = ({
  visible,
  onClose,
  onRouteSelect,
  currentLocation,
}) => {
  const insets = useSafeAreaInsets();
  const translateY = useRef(new Animated.Value(SCREEN_HEIGHT)).current;
  const [selectedRoute, setSelectedRoute] = useState<SmartRouteSuggestion | null>(null);
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Scanning animation
  const scanRotation = useRef(new Animated.Value(0)).current;
  const scanPulse = useRef(new Animated.Value(0.3)).current;

  const routes = getSmartRouteSuggestions();

  // Newell AI integration
  const {
    generateText,
    isLoading: isGenerating,
  } = useTextGeneration({
    onError: (err) => {
      console.error('AI Route error:', err);
    },
  });

  useEffect(() => {
    if (visible) {
      Animated.spring(translateY, {
        toValue: 0,
        tension: 65,
        friction: 11,
        useNativeDriver: true,
      }).start();
    } else {
      Animated.timing(translateY, {
        toValue: SCREEN_HEIGHT,
        duration: 300,
        useNativeDriver: true,
      }).start();
    }
  }, [visible, translateY]);

  // Scanning animation
  useEffect(() => {
    if (isAnalyzing) {
      Animated.loop(
        Animated.timing(scanRotation, {
          toValue: 1,
          duration: 2000,
          useNativeDriver: true,
        })
      ).start();

      Animated.loop(
        Animated.sequence([
          Animated.timing(scanPulse, {
            toValue: 0.8,
            duration: 800,
            useNativeDriver: true,
          }),
          Animated.timing(scanPulse, {
            toValue: 0.3,
            duration: 800,
            useNativeDriver: true,
          }),
        ])
      ).start();
    }
  }, [isAnalyzing, scanRotation, scanPulse]);

  const handleRouteSelect = async (route: SmartRouteSuggestion) => {
    setSelectedRoute(route);
    setIsAnalyzing(true);

    // Generate AI insight for the route
    const prompt = `You are a friendly van life route advisor. Analyze this route and give a brief, enthusiastic recommendation (2-3 sentences max):

Route: ${route.name}
Description: ${route.description}
Social Overlap: ${route.overlapPercentage}%
Nomads in Area: ${route.nomadicDensity}
Highlights: ${route.highlights.join(', ')}
Travel Time: ${route.estimatedTravelTime}

Give a personalized, warm recommendation focusing on the social opportunities along this route. Be concise and friendly, like advice from an experienced nomad friend.`;

    try {
      const result = await generateText(prompt);
      setAiInsight(result || 'Great route choice! This path offers excellent social opportunities with fellow nomads.');
    } catch {
      setAiInsight('This route has high nomadic density - you\'ll meet plenty of fellow travelers!');
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleConfirmRoute = () => {
    if (selectedRoute) {
      onRouteSelect?.(selectedRoute);
      onClose();
    }
  };

  const spin = scanRotation.interpolate({
    inputRange: [0, 1],
    outputRange: ['0deg', '360deg'],
  });

  const SheetContent = Platform.OS === 'ios' ? BlurView : View;
  const sheetProps = Platform.OS === 'ios' ? { tint: 'dark' as const, intensity: 85 } : {};

  return (
    <Animated.View
      style={[
        styles.container,
        {
          transform: [{ translateY }],
          paddingBottom: insets.bottom,
        },
      ]}
      pointerEvents={visible ? 'auto' : 'none'}
    >
      <SheetContent
        {...sheetProps}
        style={[
          styles.sheet,
          Platform.OS !== 'ios' && styles.sheetFallback,
        ]}
      >
        {/* Header */}
        <View style={styles.header}>
          <View style={styles.headerLeft}>
            <View style={styles.aiIconContainer}>
              <Ionicons name="sparkles" size={20} color={colors.moss[400]} />
            </View>
            <View>
              <Text style={styles.headerTitle}>Smart Route</Text>
              <Text style={styles.headerSubtitle}>AI-Powered Route Planning</Text>
            </View>
          </View>
          <TouchableOpacity onPress={onClose} style={styles.closeButton}>
            <Ionicons name="close" size={24} color={colors.text.inverse} />
          </TouchableOpacity>
        </View>

        {/* Route List */}
        <ScrollView
          style={styles.routeList}
          showsVerticalScrollIndicator={false}
          contentContainerStyle={styles.routeListContent}
        >
          <Text style={styles.sectionTitle}>Suggested Routes</Text>
          <Text style={styles.sectionSubtitle}>
            Based on social overlap and nomadic density
          </Text>

          {routes.map((route) => (
            <TouchableOpacity
              key={route.id}
              onPress={() => handleRouteSelect(route)}
              activeOpacity={0.8}
            >
              <GlassCard
                variant={selectedRoute?.id === route.id ? 'medium' : 'light'}
                padding="lg"
                style={[
                  styles.routeCard,
                  selectedRoute?.id === route.id ? styles.routeCardSelected : undefined,
                ]}
              >
                <View style={styles.routeHeader}>
                  <View style={styles.routeNameContainer}>
                    <Text style={styles.routeName}>{route.name}</Text>
                    <View style={styles.overlapBadge}>
                      <Ionicons name="git-merge" size={12} color={colors.text.inverse} />
                      <Text style={styles.overlapBadgeText}>{route.overlapPercentage}%</Text>
                    </View>
                  </View>
                  <Text style={styles.routeDescription}>{route.description}</Text>
                </View>

                <View style={styles.routeStats}>
                  <View style={styles.statItem}>
                    <Ionicons name="people" size={16} color={colors.moss[500]} />
                    <Text style={styles.statText}>{route.nomadicDensity} nomads</Text>
                  </View>
                  <View style={styles.statItem}>
                    <Ionicons name="time" size={16} color={colors.driftwood[500]} />
                    <Text style={styles.statText}>{route.estimatedTravelTime}</Text>
                  </View>
                </View>

                <View style={styles.highlightsContainer}>
                  {route.highlights.map((highlight, i) => (
                    <View key={i} style={styles.highlightChip}>
                      <Ionicons name="checkmark-circle" size={12} color={colors.moss[500]} />
                      <Text style={styles.highlightText}>{highlight}</Text>
                    </View>
                  ))}
                </View>

                {route.weatherSummary ? (
                  <View style={styles.weatherSummaryRow}>
                    <View style={[
                      styles.weatherBadge,
                      route.weatherSummary.overallRating === 'excellent' && styles.weatherExcellent,
                      route.weatherSummary.overallRating === 'good' && styles.weatherGood,
                      route.weatherSummary.overallRating === 'fair' && styles.weatherFair,
                      route.weatherSummary.overallRating === 'poor' && styles.weatherPoor,
                    ]}>
                      <Ionicons 
                        name="partly-sunny" 
                        size={12} 
                        color={route.weatherSummary.overallRating === 'excellent' || route.weatherSummary.overallRating === 'good' 
                          ? colors.forestGreen[600] 
                          : route.weatherSummary.overallRating === 'fair' 
                            ? colors.sunsetOrange[600] 
                            : colors.emergency.primary
                        } 
                      />
                      <Text style={[
                        styles.weatherBadgeText,
                        route.weatherSummary.overallRating === 'excellent' && styles.weatherExcellentText,
                        route.weatherSummary.overallRating === 'good' && styles.weatherGoodText,
                        route.weatherSummary.overallRating === 'fair' && styles.weatherFairText,
                        route.weatherSummary.overallRating === 'poor' && styles.weatherPoorText,
                      ]}>
                        {route.weatherSummary.overallRating?.toUpperCase()}
                      </Text>
                    </View>
                    {route.weatherSummary.alerts > 0 ? (
                      <View style={styles.alertBadge}>
                        <Ionicons name="warning" size={10} color={colors.sunsetOrange[600]} />
                        <Text style={styles.alertBadgeText}>{route.weatherSummary.alerts}</Text>
                      </View>
                    ) : null}
                    <Text style={styles.departureWindowText} numberOfLines={1}>
                      Depart: {route.weatherSummary.bestDepartureWindow}
                    </Text>
                  </View>
                ) : null}

                {selectedRoute?.id === route.id && (
                  <View style={styles.selectedIndicator}>
                    <Ionicons name="checkmark-circle" size={20} color={colors.moss[500]} />
                  </View>
                )}
              </GlassCard>
            </TouchableOpacity>
          ))}
        </ScrollView>

        {/* AI Insight Panel */}
        {selectedRoute && (
          <View style={styles.insightPanel}>
            {isAnalyzing || isGenerating ? (
              <View style={styles.analyzingContainer}>
                <Animated.View style={[styles.scanIcon, { transform: [{ rotate: spin }] }]}>
                  <Ionicons name="scan" size={24} color={colors.moss[400]} />
                </Animated.View>
                <Animated.View style={[styles.scanPulse, { opacity: scanPulse }]} />
                <Text style={styles.analyzingText}>Analyzing route...</Text>
              </View>
            ) : aiInsight ? (
              <GlassCard variant="frost" padding="md" style={styles.insightCard}>
                <View style={styles.insightHeader}>
                  <Ionicons name="bulb" size={18} color={colors.ember[400]} />
                  <Text style={styles.insightTitle}>AI Insight</Text>
                </View>
                <Text style={styles.insightText}>{aiInsight}</Text>
              </GlassCard>
            ) : null}

            <Button
              title="Set as My Route"
              onPress={handleConfirmRoute}
              variant="ember"
              size="lg"
              fullWidth
              disabled={isAnalyzing || isGenerating}
              icon={<Ionicons name="navigate" size={20} color={colors.text.inverse} />}
            />
          </View>
        )}
      </SheetContent>
    </Animated.View>
  );
};

const styles = StyleSheet.create({
