/**
 * WilderGo Convoy Introduction Component
 * AI-powered welcome messages for new convoy members
 * Features:
 * - Personalized welcome generation
 * - Conversation starters
 * - Shared interests highlighting
 * - Activity suggestions
 */

import React, { useState, useEffect, useRef } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Animated,
  Platform,
  ActivityIndicator,
  ScrollView,
} from 'react-native';
import { BlurView } from 'expo-blur';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import { Image } from 'expo-image';
import {
  colors,
  borderRadius,
  spacing,
  typography,
  shadows,
  blur,
} from '@/constants/theme';
import {
  ConvoyMember,
  ConvoyIntroduction,
  generateConvoyIntroduction,
} from '@/services/ai/convoyAIService';

interface ConvoyIntroductionCardProps {
  newMember: ConvoyMember;
  existingMembers: ConvoyMember[];
  convoyName: string;
  onDismiss?: () => void;
  onStartConversation?: (starter: string) => void;
}

export const ConvoyIntroductionCard: React.FC<ConvoyIntroductionCardProps> = ({
  newMember,
  existingMembers,
  convoyName,
  onDismiss,
  onStartConversation,
}) => {
  const [introduction, setIntroduction] = useState<ConvoyIntroduction | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fadeAnim = useRef(new Animated.Value(0)).current;
  const slideAnim = useRef(new Animated.Value(50)).current;

  useEffect(() => {
    loadIntroduction();
  }, [newMember, existingMembers, convoyName]);

  useEffect(() => {
    if (introduction) {
      Animated.parallel([
        Animated.timing(fadeAnim, {
          toValue: 1,
          duration: 400,
          useNativeDriver: true,
        }),
        Animated.spring(slideAnim, {
          toValue: 0,
          tension: 65,
          friction: 10,
          useNativeDriver: true,
        }),
      ]).start();
    }
  }, [introduction, fadeAnim, slideAnim]);

  const loadIntroduction = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await generateConvoyIntroduction(newMember, existingMembers, convoyName);
      setIntroduction(result);
    } catch (err) {
      setError('Unable to generate introduction. Please try again.');
      console.error('Introduction generation failed:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const ContainerWrapper = Platform.OS === 'ios' ? BlurView : View;
  const containerProps = Platform.OS === 'ios'
    ? { tint: 'light' as const, intensity: blur.medium, style: styles.container }
    : { style: [styles.container, styles.containerFallback] };

  return (
    <ContainerWrapper {...containerProps}>
      {/* Header */}
      <View style={styles.header}>
        <View style={styles.headerLeft}>
          <View style={styles.aiIconContainer}>
            <LinearGradient
              colors={[colors.forestGreen[500], colors.forestGreen[600]]}
              style={styles.aiIcon}
            >
              <Ionicons name="sparkles" size={16} color={colors.text.inverse} />
            </LinearGradient>
          </View>
          <View>
            <Text style={styles.headerTitle}>AI Introduction</Text>
            <Text style={styles.headerSubtitle}>Powered by Newell AI</Text>
          </View>
        </View>
        {onDismiss && (
          <TouchableOpacity onPress={onDismiss}>
            <Ionicons name="close" size={24} color={colors.bark[400]} />
          </TouchableOpacity>
        )}
      </View>

      {isLoading ? (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="large" color={colors.forestGreen[500]} />
          <Text style={styles.loadingText}>Generating personalized introduction...</Text>
          <Text style={styles.loadingSubtext}>This takes a few seconds</Text>
        </View>
      ) : error ? (
        <View style={styles.errorContainer}>
          <Ionicons name="warning-outline" size={32} color={colors.sunsetOrange[500]} />
          <Text style={styles.errorText}>{error}</Text>
          <TouchableOpacity style={styles.retryButton} onPress={loadIntroduction}>
            <Text style={styles.retryButtonText}>Try Again</Text>
          </TouchableOpacity>
        </View>
      ) : introduction ? (
        <Animated.View
          style={[
            styles.content,
            {
              opacity: fadeAnim,
              transform: [{ translateY: slideAnim }],
            },
          ]}
        >
          {/* New member info */}
          <View style={styles.memberInfo}>
            <View style={styles.memberAvatar}>
              <Text style={styles.memberInitial}>{newMember.name.charAt(0)}</Text>
            </View>
            <View style={styles.memberDetails}>
              <Text style={styles.memberName}>{newMember.name}</Text>
              <Text style={styles.memberRig}>{newMember.rigType || 'Fellow Nomad'}</Text>
            </View>
            <View style={styles.newBadge}>
              <Text style={styles.newBadgeText}>NEW</Text>
            </View>
          </View>

          {/* Welcome message */}
          <View style={styles.welcomeSection}>
            <Text style={styles.welcomeMessage}>{introduction.welcomeMessage}</Text>
          </View>

          {/* Shared interests */}
