    Linking.openURL('mailto:support@wildergo.com?subject=WilderGo%20Support%20Request');
  };

  const handleReportBug = () => {
    Linking.openURL('mailto:reportbugs@wildergo.com?subject=WilderGo%20Bug%20Report');
  };

