            <Ionicons
              name={info.icon as keyof typeof Ionicons.glyphMap}
              size={28}
              color={info.color}
            />
          </View>
          <Text style={styles.categoryLabel}>{info.label}</Text>
          <Text style={styles.categoryDescription} numberOfLines={2}>
            {info.description}
          </Text>
        </View>
      </TouchableOpacity>
    );
  };

  return (
    <View style={styles.container}>
      <ScrollView
        style={styles.scrollView}
        contentContainerStyle={[
          styles.scrollContent,
          { paddingTop: insets.top + spacing.lg, paddingBottom: insets.bottom + 120 },
        ]}
        showsVerticalScrollIndicator={false}
      >
        {/* Header */}
        <View style={styles.header}>
          <View style={styles.sosIcon}>
            <Ionicons name="warning" size={32} color={colors.sunsetOrange[500]} />
          </View>
          <Text style={styles.headerTitle}>SOS</Text>
          <Text style={styles.headerSubtitle}>
            Get help from nearby nomads
