        </View>

        {/* Active Request Banner */}
        {activeRequests > 0 && (
          <TouchableOpacity
            style={styles.activeRequestBanner}
            onPress={onViewActiveRequest}
            activeOpacity={0.8}
          >
            <LinearGradient
              colors={[colors.sunsetOrange[500], colors.burntSienna[500]]}
              start={{ x: 0, y: 0 }}
              end={{ x: 1, y: 0 }}
              style={styles.activeRequestGradient}
