            </View>
            <Text style={styles.resourceTitle}>FAQs</Text>
            <Ionicons name="chevron-forward" size={16} color={colors.bark[400]} />
          </TouchableOpacity>

          <TouchableOpacity
            style={styles.resourceCard}
            onPress={() => setShowGuidelinesModal(true)}
            activeOpacity={0.7}
