              <Ionicons name="document-text" size={20} color={colors.ember[600]} />
            </View>
            <Text style={styles.resourceTitle}>Community Guidelines</Text>
            <Ionicons name="chevron-forward" size={16} color={colors.bark[400]} />
          </TouchableOpacity>

          <TouchableOpacity
            style={styles.resourceCard}
            onPress={handleContactSupport}
            activeOpacity={0.7}
            testID="button-contact-support"
          >
            <View style={[styles.resourceIcon, { backgroundColor: colors.burntSienna[500] + '20' }]}>
              <Ionicons name="mail" size={20} color={colors.burntSienna[600]} />
            </View>
            <Text style={styles.resourceTitle}>Contact Support</Text>
            <Ionicons name="chevron-forward" size={16} color={colors.bark[400]} />
          </TouchableOpacity>

          <TouchableOpacity
            style={styles.resourceCard}
            onPress={handleReportBug}
            activeOpacity={0.7}
            testID="button-report-bug"
          >
