                <Text style={styles.guidelineContent}>{guideline.content}</Text>
              </View>
            ))}
          </ScrollView>
        </View>
      </Modal>

      {/* Getting Started Modal */}
      <Modal
        visible={showGettingStartedModal}
        animationType="slide"
        presentationStyle="pageSheet"
        onRequestClose={() => setShowGettingStartedModal(false)}
      >
        <View style={[styles.modalContainer, { paddingTop: insets.top }]}>
          <View style={styles.modalHeader}>
            <Text style={styles.modalTitle}>Getting Started</Text>
            <TouchableOpacity
              onPress={() => setShowGettingStartedModal(false)}
              style={styles.modalCloseButton}
              hitSlop={{ top: 10, bottom: 10, left: 10, right: 10 }}
            >
              <Ionicons name="close" size={24} color={colors.bark[600]} />
            </TouchableOpacity>
          </View>
          <ScrollView 
            style={styles.modalContent}
            contentContainerStyle={{ paddingBottom: insets.bottom + spacing.xl }}
          >
            <Text style={styles.gettingStartedIntro}>
              Welcome to WilderGo! Here's how to get the most out of your adventure companion.
            </Text>
            {GETTING_STARTED_STEPS.map((step, index) => (
              <View key={index} style={styles.gettingStartedStep}>
                <View style={styles.gettingStartedIconContainer}>
                  <Ionicons name={step.icon} size={28} color={colors.moss[600]} />
                </View>
                <View style={styles.gettingStartedTextContainer}>
                  <Text style={styles.gettingStartedStepTitle}>{step.title}</Text>
                  <Text style={styles.gettingStartedStepContent}>{step.content}</Text>
                </View>
              </View>
            ))}
          </ScrollView>
        </View>
      </Modal>

      {/* FAQs Modal */}
      <Modal
        visible={showFAQsModal}
        animationType="slide"
        presentationStyle="pageSheet"
        onRequestClose={() => setShowFAQsModal(false)}
      >
        <View style={[styles.modalContainer, { paddingTop: insets.top }]}>
          <View style={styles.modalHeader}>
            <Text style={styles.modalTitle}>Frequently Asked Questions</Text>
            <TouchableOpacity
              onPress={() => setShowFAQsModal(false)}
              style={styles.modalCloseButton}
              hitSlop={{ top: 10, bottom: 10, left: 10, right: 10 }}
            >
              <Ionicons name="close" size={24} color={colors.bark[600]} />
            </TouchableOpacity>
          </View>
          <ScrollView 
            style={styles.modalContent}
            contentContainerStyle={{ paddingBottom: insets.bottom + spacing.xl }}
          >
            {FAQS.map((faq, index) => (
              <TouchableOpacity
                key={index}
                style={styles.faqItem}
                onPress={() => setExpandedFAQ(expandedFAQ === index ? null : index)}
                activeOpacity={0.7}
              >
                <View style={styles.faqQuestion}>
                  <Text style={styles.faqQuestionText}>{faq.question}</Text>
                  <Ionicons 
                    name={expandedFAQ === index ? 'chevron-up' : 'chevron-down'} 
                    size={20} 
                    color={colors.bark[500]} 
                  />
                </View>
                {expandedFAQ === index ? (
                  <Text style={styles.faqAnswer}>{faq.answer}</Text>
                ) : null}
              </TouchableOpacity>
            ))}
          </ScrollView>
        </View>
      </Modal>
    </View>
  );
};

