client/components/passport/TravelHistory.content:
/**
 * WilderGo Travel History
 * Visual timeline and map display of previous Pinned Spots
 * Features:
 * - Timeline view with spot cards
 * - Spot type filtering
 * - Rating stars
 * - Favorite toggle
 * - Days stayed tracking
 */

import React, { useState, useMemo, useRef, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  ScrollView,
  TouchableOpacity,
  Animated,
  Platform,
  Dimensions,
  Image,
} from 'react-native';
import { BlurView } from 'expo-blur';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import {
  colors,
  borderRadius,
  spacing,
  typography,
  shadows,
  blur,
} from '@/constants/theme';
import {
  PinnedSpot,
  SpotType,
  spotTypeConfig,
  getPinnedSpots,
  getTravelStats,
  updatePinnedSpot,
} from '@/services/passport/nomadPassportService';

const { width: SCREEN_WIDTH } = Dimensions.get('window');

interface TravelHistoryProps {
  userId: string;
  onSpotPress?: (spot: PinnedSpot) => void;
  onAddSpot?: () => void;
}

// Stats card showing travel summary
const TravelStatsCard: React.FC<{ userId: string }> = ({ userId }) => {
  const stats = useMemo(() => getTravelStats(userId), [userId]);
  const mostVisitedConfig = stats.mostVisitedType ? spotTypeConfig[stats.mostVisitedType] : null;

  const ContainerWrapper = Platform.OS === 'ios' ? BlurView : View;
  const containerProps = Platform.OS === 'ios'
    ? { tint: 'light' as const, intensity: blur.medium, style: styles.statsCard }
    : { style: [styles.statsCard, styles.statsCardFallback] };

  return (
    <ContainerWrapper {...containerProps}>
      <Text style={styles.statsTitle}>Your Journey</Text>

      <View style={styles.statsGrid}>
        <View style={styles.statItem}>
          <Text style={styles.statValue}>{stats.totalSpots}</Text>
          <Text style={styles.statLabel}>Spots</Text>
        </View>
        <View style={styles.statDivider} />
        <View style={styles.statItem}>
          <Text style={styles.statValue}>{stats.totalDays}</Text>
          <Text style={styles.statLabel}>Days</Text>
        </View>
        <View style={styles.statDivider} />
        <View style={styles.statItem}>
          <Text style={styles.statValue}>{stats.favoriteSpots}</Text>
          <Text style={styles.statLabel}>Favorites</Text>
        </View>
        <View style={styles.statDivider} />
        <View style={styles.statItem}>
          <View style={styles.ratingContainer}>
            <Text style={styles.statValue}>{stats.averageRating}</Text>
            <Ionicons name="star" size={14} color={colors.sunsetOrange[500]} />
          </View>
          <Text style={styles.statLabel}>Avg Rating</Text>
        </View>
      </View>

      {mostVisitedConfig && (
        <View style={styles.favoriteType}>
          <Ionicons name={mostVisitedConfig.icon as keyof typeof Ionicons.glyphMap} size={16} color={mostVisitedConfig.color} />
          <Text style={styles.favoriteTypeText}>Most visited: {mostVisitedConfig.label}</Text>
        </View>
      )}
    </ContainerWrapper>
  );
};

// Filter chips for spot types
interface FilterChipsProps {
  selectedType: SpotType | null;
  onSelectType: (type: SpotType | null) => void;
}

const FilterChips: React.FC<FilterChipsProps> = ({ selectedType, onSelectType }) => {
  const spotTypes = Object.entries(spotTypeConfig) as [SpotType, typeof spotTypeConfig[SpotType]][];

  return (
    <ScrollView
      horizontal
      showsHorizontalScrollIndicator={false}
      contentContainerStyle={styles.filterContainer}
    >
      <TouchableOpacity
        style={[
          styles.filterChip,
          !selectedType && styles.filterChipActive,
        ]}
        onPress={() => onSelectType(null)}
      >
        <Text style={[
          styles.filterChipText,
          !selectedType && styles.filterChipTextActive,
        ]}>
          All
        </Text>
      </TouchableOpacity>

      {spotTypes.map(([type, config]) => (
        <TouchableOpacity
          key={type}
          style={[
            styles.filterChip,
            selectedType === type && { backgroundColor: config.color + '20', borderColor: config.color },
          ]}
          onPress={() => onSelectType(type)}
        >
          <Ionicons
            name={config.icon as keyof typeof Ionicons.glyphMap}
            size={14}
            color={selectedType === type ? config.color : colors.bark[400]}
          />
          <Text style={[
            styles.filterChipText,
            selectedType === type && { color: config.color },
          ]}>
            {config.label}
          </Text>
        </TouchableOpacity>
      ))}
    </ScrollView>
  );
};

// Individual spot card in timeline
interface SpotCardProps {
  spot: PinnedSpot;
  isFirst: boolean;
  isLast: boolean;
  onPress: () => void;
  onToggleFavorite: () => void;
}

const SpotCard: React.FC<SpotCardProps> = ({
  spot,
  isFirst,
  isLast,
  onPress,
  onToggleFavorite,
}) => {
  const scaleAnim = useRef(new Animated.Value(1)).current;
  const config = spotTypeConfig[spot.type];
  const visitDate = new Date(spot.visitedAt);

  const handlePressIn = () => {
    Animated.spring(scaleAnim, {
      toValue: 0.98,
      useNativeDriver: true,
    }).start();
  };

  const handlePressOut = () => {
    Animated.spring(scaleAnim, {
      toValue: 1,
      friction: 4,
      useNativeDriver: true,
    }).start();
  };

  const ContainerWrapper = Platform.OS === 'ios' ? BlurView : View;
  const containerProps = Platform.OS === 'ios'
    ? { tint: 'light' as const, intensity: blur.light, style: styles.spotCard }
    : { style: [styles.spotCard, styles.spotCardFallback] };

  return (
    <View style={styles.timelineItem}>
      {/* Timeline connector */}
      <View style={styles.timelineConnector}>
        {!isFirst && <View style={styles.timelineLine} />}
        <View style={[styles.timelineDot, { backgroundColor: config.color }]}>
          <Ionicons name={config.icon as keyof typeof Ionicons.glyphMap} size={12} color={colors.text.inverse} />
        </View>
        {!isLast && <View style={styles.timelineLine} />}
      </View>

      {/* Card content */}
      <Animated.View style={{ flex: 1, transform: [{ scale: scaleAnim }] }}>
        <TouchableOpacity
          activeOpacity={0.9}
          onPress={onPress}
          onPressIn={handlePressIn}
          onPressOut={handlePressOut}
        >
          <ContainerWrapper {...containerProps}>
            <View style={styles.spotHeader}>
              <View style={styles.spotTitleRow}>
                <Text style={styles.spotName} numberOfLines={1}>{spot.name}</Text>
                <TouchableOpacity onPress={onToggleFavorite} hitSlop={{ top: 10, bottom: 10, left: 10, right: 10 }}>
                  <Ionicons
                    name={spot.isFavorite ? 'heart' : 'heart-outline'}
                    size={20}
                    color={spot.isFavorite ? colors.sunsetOrange[500] : colors.bark[400]}
                  />
                </TouchableOpacity>
              </View>

              <View style={styles.spotMeta}>
                <View style={[styles.spotTypeBadge, { backgroundColor: config.color + '20' }]}>
                  <Text style={[styles.spotTypeText, { color: config.color }]}>{config.label}</Text>
                </View>
                <Text style={styles.spotDate}>
                  {visitDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                </Text>
              </View>
            </View>

            <View style={styles.spotDetails}>
              <View style={styles.spotDetailItem}>
                <Ionicons name="calendar-outline" size={14} color={colors.bark[400]} />
                <Text style={styles.spotDetailText}>{spot.daysStayed} {spot.daysStayed === 1 ? 'day' : 'days'}</Text>
              </View>

              {spot.rating && (
                <View style={styles.spotDetailItem}>
                  <View style={styles.ratingStars}>
                    {[1, 2, 3, 4, 5].map((star) => (
                      <Ionicons
                        key={star}
                        name={star <= spot.rating! ? 'star' : 'star-outline'}
                        size={12}
                        color={star <= spot.rating! ? colors.sunsetOrange[500] : colors.bark[300]}
                      />
                    ))}
                  </View>
                </View>
              )}

              {spot.cellSignal !== undefined && (
                <View style={styles.spotDetailItem}>
                  <Ionicons name="cellular" size={14} color={colors.bark[400]} />
                  <Text style={styles.spotDetailText}>{spot.cellSignal}/5 bars</Text>
                </View>
              )}
            </View>

            {spot.notes && (
              <Text style={styles.spotNotes} numberOfLines={2}>{spot.notes}</Text>
            )}

            {spot.tags && spot.tags.length > 0 && (
              <View style={styles.tagContainer}>
                {spot.tags.slice(0, 3).map((tag, index) => (
                  <View key={index} style={styles.tag}>
                    <Text style={styles.tagText}>#{tag}</Text>
                  </View>
                ))}
              </View>
            )}
          </ContainerWrapper>
        </TouchableOpacity>
      </Animated.View>
    </View>
  );
};

// Main component
export const TravelHistory: React.FC<TravelHistoryProps> = ({
  userId,
  onSpotPress,
  onAddSpot,
}) => {
  const [selectedType, setSelectedType] = useState<SpotType | null>(null);
  const [spots, setSpots] = useState<PinnedSpot[]>([]);

  useEffect(() => {
    setSpots(getPinnedSpots(userId));
  }, [userId]);

  const filteredSpots = useMemo(() => {
    if (!selectedType) return spots;
    return spots.filter(s => s.type === selectedType);
  }, [spots, selectedType]);

  const handleToggleFavorite = (spotId: string) => {
    const spot = spots.find(s => s.id === spotId);
    if (spot) {
      updatePinnedSpot(spotId, { isFavorite: !spot.isFavorite });
      setSpots(getPinnedSpots(userId));
    }
  };

  return (
    <View style={styles.container}>
      {/* Stats card */}
      <TravelStatsCard userId={userId} />

      {/* Timeline */}
      <ScrollView
        style={styles.timelineContainer}
        contentContainerStyle={styles.timelineContent}
        showsVerticalScrollIndicator={false}
      >
        {filteredSpots.length === 0 ? (
          <View style={styles.emptyState}>
            <Ionicons name="trail-sign-outline" size={48} color={colors.bark[300]} />
            <Text style={styles.emptyTitle}>No spots yet</Text>
            <Text style={styles.emptyText}>
              Start pinning your favorite camping spots, BLM land, and adventures!
            </Text>
            {onAddSpot && (
              <TouchableOpacity style={styles.addButton} onPress={onAddSpot}>
                <LinearGradient
                  colors={[colors.forestGreen[500], colors.forestGreen[600]]}
                  start={{ x: 0, y: 0 }}
                  end={{ x: 1, y: 1 }}
                  style={styles.addButtonGradient}
                >
                  <Ionicons name="add" size={20} color={colors.text.inverse} />
                  <Text style={styles.addButtonText}>Pin Your First Spot</Text>
                </LinearGradient>
              </TouchableOpacity>
            )}
          </View>
        ) : (
          <>
            {filteredSpots.map((spot, index) => (
              <SpotCard
                key={spot.id}
                spot={spot}
                isFirst={index === 0}
                isLast={index === filteredSpots.length - 1}
                onPress={() => onSpotPress?.(spot)}
                onToggleFavorite={() => handleToggleFavorite(spot.id)}
              />
            ))}
          </>
        )}
      </ScrollView>

      {/* Floating add button */}
      {filteredSpots.length > 0 && onAddSpot && (
        <TouchableOpacity style={styles.fab} onPress={onAddSpot} activeOpacity={0.9}>
          <LinearGradient
