/**
 * SmartRouteScreen - Web Version
 * Uses a placeholder map view for web compatibility
 */

import React, { useState, useEffect, useCallback } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
  ActivityIndicator,
  Dimensions,
} from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { LinearGradient } from 'expo-linear-gradient';
import {
  getSmartRoute,
  getWeatherIconName,
  getRoadRiskColor,
  SmartRouteData,
  Coordinate,
} from '@/services/smartRouteService';
import { colors, typography, spacing, borderRadius } from '@/constants/theme';

const { width, height } = Dimensions.get('window');

const COLORS = {
  warmCream: '#F5EFE6',
  lightCream: '#FAF6F2',
  desertSand: '#E8C5A5',
  sandDark: '#D9B894',
  skyBlue: '#4A90E2',
  skyBlueLight: '#E3F0FF',
  skyBlueDark: '#3B7BC8',
  amber: '#F2A154',
  amberLight: '#FFF9F0',
  amberDark: '#D48A3A',
  forestGreenLight: '#E8F5E9',
  forestGreenDark: '#2D5A3D',
};

interface SmartRouteScreenProps {
  origin?: Coordinate;
  destination?: Coordinate;
  originName?: string;
  destinationName?: string;
  onClose?: () => void;
  onStartNavigation?: () => void;
}

export function SmartRouteScreen({
  origin = { latitude: 39.7392, longitude: -104.9903 },
  destination = { latitude: 40.0150, longitude: -105.2705 },
  originName = 'Denver, CO',
  destinationName = 'Boulder, CO',
  onClose,
  onStartNavigation,
}: SmartRouteScreenProps) {
  const insets = useSafeAreaInsets();
  const [smartRoute, setSmartRoute] = useState<SmartRouteData | null>(null);
  const [loading, setLoading] = useState(false);

  const loadSmartRoute = useCallback(async () => {
    setLoading(true);
    try {
      const route = await getSmartRoute(origin, destination);
      if (route.success) {
        setSmartRoute(route);
      }
    } catch (error) {
      console.error('Error loading Smart Route:', error);
    } finally {
      setLoading(false);
    }
  }, [origin, destination]);

  useEffect(() => {
    loadSmartRoute();
  }, [loadSmartRoute]);

  if (loading) {
    return (
      <View style={[styles.loadingContainer, { paddingTop: insets.top }]}>
        <ActivityIndicator size="large" color={colors.sunsetOrange[500]} />
        <Text style={styles.loadingText}>Calculating Smart Route...</Text>
        <Text style={styles.loadingSubtext}>Analyzing weather and road conditions</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <View style={[styles.header, { paddingTop: insets.top + spacing.sm }]}>
        <View style={styles.headerContent}>
          {onClose ? (
            <TouchableOpacity onPress={onClose} style={styles.closeButton} testID="button-close-route">
              <Ionicons name="close" size={24} color={colors.bark[700]} />
            </TouchableOpacity>
          ) : null}
          <View style={styles.headerText}>
            <Text style={styles.headerTitle}>Smart Route</Text>
            <Text style={styles.headerSubtitle}>AI-Powered Navigation</Text>
          </View>
          <TouchableOpacity onPress={loadSmartRoute} style={styles.refreshButton}>
            <Ionicons name="refresh" size={20} color={colors.sunsetOrange[500]} />
          </TouchableOpacity>
        </View>
      </View>

      <View style={styles.mapPlaceholder}>
        <LinearGradient
          colors={[COLORS.forestGreenLight, COLORS.skyBlueLight]}
          style={styles.mapGradient}
        >
          <View style={styles.mapContent}>
            <Ionicons name="map" size={48} color={colors.forestGreen[500]} />
            <Text style={styles.mapText}>Route Preview</Text>
            <Text style={styles.mapSubtext}>{originName} to {destinationName}</Text>
            <View style={styles.routeVisual}>
              <View style={[styles.routePoint, { backgroundColor: colors.forestGreen[500] }]}>
                <Text style={styles.routePointText}>A</Text>
              </View>
              <View style={styles.routeDash} />
              <View style={[styles.routePoint, { backgroundColor: COLORS.skyBlue }]}>
                <Text style={styles.routePointText}>M</Text>
              </View>
              <View style={styles.routeDash} />
              <View style={[styles.routePoint, { backgroundColor: colors.sunsetOrange[500] }]}>
                <Text style={styles.routePointText}>B</Text>
              </View>
            </View>
            <Text style={styles.webNote}>Use Expo Go app for full map experience</Text>
          </View>
        </LinearGradient>
      </View>

      {smartRoute ? (
        <ScrollView
          style={styles.infoCardContainer}
          contentContainerStyle={[styles.infoCard, { paddingBottom: insets.bottom + spacing.lg }]}
          showsVerticalScrollIndicator={false}
        >
          <View style={styles.routeInfo}>
            <View style={styles.routeEndpoints}>
              <View style={styles.endpointRow}>
                <View style={[styles.endpointDot, { backgroundColor: colors.forestGreen[500] }]} />
                <Text style={styles.endpointText} numberOfLines={1}>{originName}</Text>
              </View>
              <View style={styles.routeLine} />
              <View style={styles.endpointRow}>
                <View style={[styles.endpointDot, { backgroundColor: colors.sunsetOrange[500] }]} />
                <Text style={styles.endpointText} numberOfLines={1}>{destinationName}</Text>
              </View>
            </View>
            <View style={styles.routeStats}>
              <Text style={styles.distance}>{smartRoute.distance}</Text>
              <Text style={styles.duration}>{smartRoute.duration}</Text>
            </View>
          </View>

          <View style={[
            styles.roadRiskBadge,
            { backgroundColor: getRoadRiskColor(smartRoute.safety.level) }
          ]}>
            <View style={styles.roadRiskHeader}>
              <Ionicons name="shield-checkmark" size={24} color="#FFFFFF" />
              <Text style={styles.roadRiskLabel}>ROAD RISK</Text>
            </View>
            <Text style={styles.roadRiskLevel}>
              {smartRoute.safety.level.toUpperCase()}
            </Text>
            <View style={styles.roadRiskScoreContainer}>
              <Text style={styles.roadRiskScore}>{smartRoute.safety.score}</Text>
              <Text style={styles.roadRiskScoreMax}>/100</Text>
            </View>
          </View>

          <View style={styles.weatherSummary}>
            <View style={styles.sectionHeader}>
              <Ionicons name="partly-sunny" size={20} color={colors.sunsetOrange[500]} />
              <Text style={styles.sectionTitle}>Weather Forecast</Text>
            </View>
            <View style={styles.weatherRow}>
              <View style={styles.weatherPoint}>
                <View style={[styles.weatherIconContainer, { backgroundColor: COLORS.forestGreenLight }]}>
                  <Ionicons
                    name={getWeatherIconName(smartRoute.weather.start.condition) as keyof typeof Ionicons.glyphMap}
                    size={28}
                    color={COLORS.forestGreenDark}
                  />
                </View>
                <Text style={styles.weatherTemp}>{smartRoute.weather.start.temperature}°F</Text>
                <Text style={styles.weatherLabel}>Start</Text>
              </View>
              <View style={styles.weatherDivider} />
              <View style={styles.weatherPoint}>
                <View style={[styles.weatherIconContainer, { backgroundColor: COLORS.skyBlueLight }]}>
                  <Ionicons
                    name={getWeatherIconName(smartRoute.weather.middle.condition) as keyof typeof Ionicons.glyphMap}
                    size={28}
                    color={COLORS.skyBlueDark}
                  />
                </View>
                <Text style={styles.weatherTemp}>{smartRoute.weather.middle.temperature}°F</Text>
                <Text style={styles.weatherLabel}>Middle</Text>
              </View>
              <View style={styles.weatherDivider} />
              <View style={styles.weatherPoint}>
                <View style={[styles.weatherIconContainer, { backgroundColor: colors.sunsetOrange[100] }]}>
                  <Ionicons
                    name={getWeatherIconName(smartRoute.weather.end.condition) as keyof typeof Ionicons.glyphMap}
                    size={28}
                    color={colors.sunsetOrange[600]}
                  />
                </View>
                <Text style={styles.weatherTemp}>{smartRoute.weather.end.temperature}°F</Text>
                <Text style={styles.weatherLabel}>End</Text>
              </View>
            </View>
          </View>

          {smartRoute.safety.warnings.length > 0 ? (
            <View style={styles.warningsContainer}>
              <View style={styles.sectionHeader}>
                <Ionicons name="warning" size={20} color={colors.sunsetOrange[600]} />
                <Text style={styles.warningsTitle}>Warnings</Text>
              </View>
              {smartRoute.safety.warnings.map((warning, index) => (
                <View key={index} style={styles.warningItem}>
                  <View style={styles.warningBullet} />
                  <Text style={styles.warningText}>{warning}</Text>
                </View>
              ))}
            </View>
          ) : null}

          {smartRoute.safety.recommendations.length > 0 ? (
            <View style={styles.recommendationsContainer}>
              <View style={styles.sectionHeader}>
                <Ionicons name="bulb" size={20} color={COLORS.amberDark} />
                <Text style={styles.recommendationsTitle}>Recommendations</Text>
              </View>
              {smartRoute.safety.recommendations.slice(0, 3).map((rec, index) => (
                <View key={index} style={styles.recommendationItem}>
                  <View style={[styles.recommendationBullet, { backgroundColor: COLORS.amber }]} />
                  <Text style={styles.recommendationText}>{rec}</Text>
                </View>
              ))}
            </View>
          ) : null}

          <View style={styles.aiBadge}>
            <Ionicons name="sparkles" size={16} color={colors.sunsetOrange[500]} />
            <Text style={styles.aiBadgeText}>AI Optimized Route</Text>
          </View>

          <TouchableOpacity
            style={styles.startButton}
            onPress={onStartNavigation}
            activeOpacity={0.8}
            testID="button-start-navigation"
          >
            <LinearGradient
              colors={[colors.sunsetOrange[500], colors.sunsetOrange[600]]}
              style={styles.startButtonGradient}
              start={{ x: 0, y: 0 }}
              end={{ x: 1, y: 0 }}
            >
              <Ionicons name="navigate" size={20} color="#FFFFFF" />
              <Text style={styles.startButtonText}>Start Navigation</Text>
            </LinearGradient>
          </TouchableOpacity>
        </ScrollView>
      ) : null}
    </View>
  );
}

