/**
 * WilderGo Weather AI Service
 * Generates "Nomadic Outlook" summaries
 * Provides personalized weather-based advice for nomadic lifestyle
 * 
 * Note: AI text generation is disabled in this environment.
 * Using intelligent fallback logic instead.
 */

// Stub function that returns empty string - uses fallback logic instead
async function generateText(_options: { prompt: string }): Promise<string> {
  throw new Error('AI generation not available - using fallback');
}

export interface WeatherConditions {
  temperature: number; // Fahrenheit
  feelsLike: number;
  humidity: number;
  windSpeed: number; // mph
  windDirection: string;
  condition: string; // clear, cloudy, rain, storm, snow, windy, fog
  uvIndex: number;
  visibility: number; // miles
  forecast?: {
    day: string;
    high: number;
    low: number;
    condition: string;
    precipChance: number;
  }[];
}

export interface NomadicOutlook {
  summary: string;
  headline: string;
  advice: string[];
  activitySuggestions: string[];
  warnings: string[];
  overallRating: 'excellent' | 'good' | 'fair' | 'caution' | 'warning';
}

/**
 * Generate a "Nomadic Outlook" summary based on current weather conditions
 * Uses Newell AI to create personalized advice for van lifers and nomads
 */
export async function generateNomadicOutlook(
  weather: WeatherConditions,
  locationName?: string
): Promise<NomadicOutlook> {
  const forecastSummary = weather.forecast
    ? weather.forecast
        .slice(0, 3)
        .map((f) => `${f.day}: ${f.condition}, ${f.high}°/${f.low}°, ${f.precipChance}% rain`)
        .join('; ')
    : 'No forecast available';

  const prompt = `You are a helpful weather advisor for nomads, van lifers, and RV travelers. Generate a brief, friendly "Nomadic Outlook" summary based on these conditions${locationName ? ` at ${locationName}` : ''}:

Current Weather:
- Temperature: ${weather.temperature}°F (Feels like ${weather.feelsLike}°F)
- Condition: ${weather.condition}
- Wind: ${weather.windSpeed} mph from ${weather.windDirection}
- Humidity: ${weather.humidity}%
- UV Index: ${weather.uvIndex}
- Visibility: ${weather.visibility} miles

Upcoming Forecast: ${forecastSummary}

Respond in JSON format ONLY with this exact structure:
{
  "headline": "A catchy 3-5 word headline for today (e.g., 'Perfect Bonfire Night Ahead')",
  "summary": "A 1-2 sentence friendly summary of conditions and what nomads should expect. Be specific and helpful. Use casual, warm language.",
  "advice": ["3-4 specific tips for van lifers based on these conditions, e.g., 'Secure your awnings before tonight's winds' or 'Great day for solar charging'"],
  "activitySuggestions": ["2-3 outdoor activities that would be ideal for these conditions"],
  "warnings": ["Any important weather-related warnings for mobile living (empty array if none)"],
  "overallRating": "One of: excellent, good, fair, caution, warning - based on conditions for nomadic living"
}`;

  try {
    const response = await generateText({ prompt });

    // Parse the JSON response
    const jsonMatch = response.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      return {
        headline: parsed.headline || 'Weather Update',
        summary: parsed.summary || 'Check conditions before heading out.',
        advice: parsed.advice || [],
        activitySuggestions: parsed.activitySuggestions || [],
        warnings: parsed.warnings || [],
        overallRating: parsed.overallRating || 'good',
      };
    }

    // Fallback if parsing fails
    return generateFallbackOutlook(weather);
  } catch (error) {
    console.error('Error generating nomadic outlook:', error);
    return generateFallbackOutlook(weather);
  }
}

/**
 * Generate a fallback outlook when AI is unavailable
 */
function generateFallbackOutlook(weather: WeatherConditions): NomadicOutlook {
  const { temperature, windSpeed, condition, humidity } = weather;

  let headline = 'Decent Day Ahead';
  let summary = '';
  const advice: string[] = [];
  const activitySuggestions: string[] = [];
  const warnings: string[] = [];
  let overallRating: NomadicOutlook['overallRating'] = 'good';

  // Temperature-based advice
  if (temperature >= 75 && temperature <= 85) {
    headline = 'Perfect Nomad Weather';
    summary = 'Ideal conditions for outdoor activities and exploring.';
    overallRating = 'excellent';
    activitySuggestions.push('Hiking', 'Outdoor cooking');
  } else if (temperature > 90) {
    headline = 'Hot Day Ahead';
    summary = 'Stay hydrated and seek shade during peak hours.';
    advice.push('Park in shaded areas when possible');
    advice.push('Run your fans and consider finding higher elevation');
    overallRating = 'caution';
  } else if (temperature < 40) {
    headline = 'Chilly Conditions';
    summary = 'Bundle up and ensure your heating system is ready.';
    advice.push('Check your propane levels');
    advice.push('Insulate windows if camping overnight');
    overallRating = 'fair';
  }

  // Wind-based advice
  if (windSpeed > 25) {
    warnings.push('High winds expected—secure awnings and outdoor gear');
    headline = 'Windy Conditions';
    overallRating = 'caution';
  } else if (windSpeed > 15) {
    advice.push('Moderate winds—good day for ventilation but secure loose items');
  }

  // Condition-based advice
  if (condition === 'clear' || condition === 'sunny') {
    advice.push('Great day for solar charging');
    activitySuggestions.push('Stargazing tonight');
  } else if (condition === 'rain' || condition === 'storm') {
    warnings.push('Rain expected—check for leaks and low-lying areas');
    advice.push('Find level ground away from potential runoff');
    overallRating = condition === 'storm' ? 'warning' : 'caution';
  }

  // Humidity advice
  if (humidity > 70) {
    advice.push('High humidity—crack windows for ventilation to prevent condensation');
  }

  // Default suggestions if empty
  if (activitySuggestions.length === 0) {
    activitySuggestions.push('Explore local trails', 'Visit nearby attractions');
  }
  if (advice.length === 0) {
    advice.push('Check weather updates throughout the day');
  }

  if (!summary) {
    summary = `Current conditions are ${condition} with temps around ${temperature}°F. ${windSpeed > 10 ? 'Some wind to be aware of.' : 'Calm conditions.'}`;
  }

  return {
    headline,
    summary,
    advice: advice.slice(0, 4),
    activitySuggestions: activitySuggestions.slice(0, 3),
    warnings,
    overallRating,
  };
}

/**
 * Get a quick weather summary suitable for a HUD display
 */
export async function getQuickWeatherSummary(
  weather: WeatherConditions
): Promise<string> {
  const prompt = `Based on these weather conditions, give a ONE sentence (max 15 words) friendly summary for a nomad:
Temperature: ${weather.temperature}°F, Feels like: ${weather.feelsLike}°F
Condition: ${weather.condition}, Wind: ${weather.windSpeed} mph
Example: "Perfect for a bonfire tonight, but high winds expected tomorrow—secure your awnings"
Just respond with the sentence, nothing else.`;

  try {
    const response = await generateText({ prompt });
    // Clean up the response
    return response.trim().replace(/^["']|["']$/g, '');
  } catch (error) {
    console.log('Using fallback weather summary:', error);
    // Fallback summary
    if (weather.windSpeed > 20) {
      return 'Windy conditions ahead—secure your awnings and outdoor gear.';
    }
    if (weather.temperature > 85) {
      return 'Hot day ahead—find shade and stay hydrated.';
    }
    if (weather.condition === 'rain' || weather.condition === 'storm') {
      return 'Wet weather coming—check for leaks and avoid low areas.';
    }
    if (weather.temperature >= 65 && weather.temperature <= 80) {
      return 'Perfect weather for outdoor adventures today!';
    }
    return `${weather.condition.charAt(0).toUpperCase() + weather.condition.slice(1)} skies with temps around ${weather.temperature}°F.`;
  }
}

/**
 * Get rating color based on overall rating
 */
export function getOutlookRatingColor(rating: NomadicOutlook['overallRating']): string {
  switch (rating) {
    case 'excellent':
      return '#4A6B50'; // Forest green
    case 'good':
      return '#5A6658'; // Sage
    case 'fair':
      return '#D97706'; // Amber
    case 'caution':
      return '#E87A47'; // Orange
    case 'warning':
      return '#DC2626'; // Red
    default:
      return '#6B7280'; // Gray
  }
}

/**
 * Get rating icon based on overall rating
 */
export function getOutlookRatingIcon(rating: NomadicOutlook['overallRating']): string {
  switch (rating) {
    case 'excellent':
      return 'sunny';
    case 'good':
      return 'partly-sunny';
    case 'fair':
      return 'cloudy';
    case 'caution':
      return 'alert-circle';
    case 'warning':
      return 'warning';
    default:
      return 'help-circle';
  }
}

export default {
  generateNomadicOutlook,
  getQuickWeatherSummary,
  getOutlookRatingColor,
  getOutlookRatingIcon,
};

client/services/smartRouteService.ts.content:
/**
 * Smart Route Service
 * Provides route calculation with REAL weather and road risk data
 */

import { getCurrentWeather } from '@/services/weather/weatherService';

export interface Coordinate {
  latitude: number;
  longitude: number;
}

export interface WeatherPoint {
  temperature: number;
  condition: string;
  description: string;
  humidity: number;
  windSpeed: number;
}

export interface SafetyData {
  level: 'safe' | 'caution' | 'warning';
  score: number;
  warnings: string[];
  recommendations: string[];
}

export interface SmartRouteData {
  success: boolean;
  coordinates: Coordinate[];
  distance: string;
  duration: string;
  weather: {
    start: WeatherPoint;
    middle: WeatherPoint;
    end: WeatherPoint;
  };
  safety: SafetyData;
}

function generateRouteCoordinates(origin: Coordinate, destination: Coordinate, numPoints: number = 20): Coordinate[] {
  const coordinates: Coordinate[] = [];

  for (let i = 0; i <= numPoints; i++) {
    const ratio = i / numPoints;
    const curve = Math.sin(ratio * Math.PI) * 0.02;

    coordinates.push({
      latitude: origin.latitude + (destination.latitude - origin.latitude) * ratio + curve,
      longitude: origin.longitude + (destination.longitude - origin.longitude) * ratio,
    });
  }

  return coordinates;
}

function calculateDistance(origin: Coordinate, destination: Coordinate): number {
  const R = 3959;
  const dLat = (destination.latitude - origin.latitude) * Math.PI / 180;
  const dLon = (destination.longitude - origin.longitude) * Math.PI / 180;
  const a = 
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(origin.latitude * Math.PI / 180) * Math.cos(destination.latitude * Math.PI / 180) *
    Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

async function fetchRealWeather(latitude: number, longitude: number): Promise<WeatherPoint> {
  try {
    const weather = await getCurrentWeather(latitude, longitude);
    if (weather.success) {
      return {
        temperature: weather.temperature || 0,
        condition: weather.condition || 'Clear',
        description: weather.description || 'clear sky',
        humidity: weather.humidity || 50,
        windSpeed: weather.windSpeed || 0,
      };
    }
  } catch (error) {
    console.warn('Failed to fetch real weather, using fallback:', error);
  }
  return {
    temperature: 55,
    condition: 'Clear',
    description: 'Weather data unavailable',
    humidity: 50,
    windSpeed: 5,
  };
}

function generateSafetyData(weather: { start: WeatherPoint; middle: WeatherPoint; end: WeatherPoint }): SafetyData {
  const warnings: string[] = [];
  const recommendations: string[] = [];
  let score = 100;

  const allConditions = [weather.start.condition, weather.middle.condition, weather.end.condition];

  if (allConditions.includes('Snow')) {
    warnings.push('Snow expected along route - reduced visibility');
    recommendations.push('Carry tire chains and emergency supplies');
    score -= 25;
  }

  if (allConditions.includes('Rain')) {
    warnings.push('Rain forecasted - slippery roads possible');
    recommendations.push('Reduce speed and increase following distance');
    score -= 15;
  }

  if (allConditions.includes('Mist') || allConditions.includes('Fog')) {
    warnings.push('Foggy conditions expected - limited visibility');
    recommendations.push('Use low-beam headlights');
    score -= 10;
  }

  if (allConditions.includes('Thunderstorm')) {
    warnings.push('Thunderstorms along route - severe weather risk');
    recommendations.push('Consider delaying departure or finding shelter');
    score -= 30;
  }

  const temps = [weather.start.temperature, weather.middle.temperature, weather.end.temperature];
  const minTemp = Math.min(...temps);
  const maxTemp = Math.max(...temps);

  if (minTemp < 32) {
    warnings.push('Freezing temperatures - watch for black ice');
    recommendations.push('Check tire pressure and antifreeze levels');
    score -= 20;
  }

  if (maxTemp > 90) {
    warnings.push('High temperatures - risk of overheating');
    recommendations.push('Check coolant and carry extra water');
    score -= 10;
  }

  const maxWind = Math.max(weather.start.windSpeed, weather.middle.windSpeed, weather.end.windSpeed);
  if (maxWind > 20) {
    warnings.push(`High winds up to ${maxWind} mph - use caution with trailers`);
    recommendations.push('Secure loose items and reduce speed');
    score -= 15;
  }

  if (recommendations.length === 0) {
    recommendations.push('Safe driving conditions expected');
    recommendations.push('Take regular breaks every 2 hours');
  }

  let level: 'safe' | 'caution' | 'warning';
  if (score >= 80) {
    level = 'safe';
  } else if (score >= 50) {
    level = 'caution';
  } else {
    level = 'warning';
  }

  return {
    level,
    score: Math.max(0, score),
    warnings,
    recommendations,
  };
}

function decodePolyline(encoded: string): Coordinate[] {
  const coordinates: Coordinate[] = [];
  let index = 0;
  let lat = 0;
  let lng = 0;

  while (index < encoded.length) {
    let shift = 0;
    let result = 0;
    let byte: number;

    do {
      byte = encoded.charCodeAt(index++) - 63;
      result |= (byte & 0x1f) << shift;
      shift += 5;
    } while (byte >= 0x20);

    const dlat = result & 1 ? ~(result >> 1) : result >> 1;
    lat += dlat;

    shift = 0;
    result = 0;

    do {
      byte = encoded.charCodeAt(index++) - 63;
      result |= (byte & 0x1f) << shift;
      shift += 5;
    } while (byte >= 0x20);

    const dlng = result & 1 ? ~(result >> 1) : result >> 1;
    lng += dlng;

    coordinates.push({
      latitude: lat / 1e5,
      longitude: lng / 1e5,
    });
  }

  return coordinates;
}

async function fetchDirectionsRoute(origin: Coordinate, destination: Coordinate): Promise<{
  coordinates: Coordinate[];
  distance: string;
  duration: string;
} | null> {
  try {
    const apiKey = process.env.EXPO_PUBLIC_GOOGLE_MAPS_API_KEY;
    if (!apiKey) {
      console.warn('Google Maps API key not available, using fallback route');
      return null;
    }

    const url = `https://maps.googleapis.com/maps/api/directions/json?origin=${origin.latitude},${origin.longitude}&destination=${destination.latitude},${destination.longitude}&key=${apiKey}`;
    const response = await fetch(url);

    if (!response.ok) {
      console.warn('Directions API request failed:', response.status);
      return null;
    }

    const data = await response.json();

    if (!data.routes || data.routes.length === 0) {
      console.warn('Directions API returned no routes');
      return null;
    }

    const route = data.routes[0];
    const leg = route.legs[0];
    const encodedPolyline = route.overview_polyline?.points;

    if (!encodedPolyline) {
      console.warn('Directions API returned no polyline');
      return null;
    }

    const coordinates = decodePolyline(encodedPolyline);
    const distance = leg.distance?.text || '';
    const duration = leg.duration?.text || '';

    return { coordinates, distance, duration };
  } catch (error) {
    console.warn('Directions API error, using fallback route:', error);
    return null;
  }
}

export interface PlaceSuggestion {
  placeId: string;
  description: string;
  mainText: string;
  secondaryText: string;
}

export async function searchPlaces(query: string): Promise<PlaceSuggestion[]> {
  try {
    const apiKey = process.env.EXPO_PUBLIC_GOOGLE_MAPS_API_KEY;
    if (!apiKey || !query.trim()) return [];

    const url = `https://maps.googleapis.com/maps/api/place/autocomplete/json?input=${encodeURIComponent(query)}&types=geocode|establishment&components=country:us&key=${apiKey}`;
    const response = await fetch(url);

    if (!response.ok) return [];

    const data = await response.json();

    if (data.status !== 'OK' || !data.predictions) return [];

    return data.predictions.map((p: any) => ({
      placeId: p.place_id,
      description: p.description,
      mainText: p.structured_formatting?.main_text || p.description,
      secondaryText: p.structured_formatting?.secondary_text || '',
    }));
  } catch (error) {
    console.warn('Place search error:', error);
    return [];
  }
}

export async function getPlaceCoordinates(placeId: string, placeName?: string): Promise<{ coordinate: Coordinate; name: string } | null> {
  const apiKey = process.env.EXPO_PUBLIC_GOOGLE_MAPS_API_KEY;
  if (!apiKey) return null;

  try {
    const url = `https://maps.googleapis.com/maps/api/place/details/json?place_id=${placeId}&fields=geometry,name,formatted_address&key=${apiKey}`;
    console.log('[SmartRoute] Fetching place details for:', placeId);
    const response = await fetch(url);

    if (response.ok) {
      const data = await response.json();
      console.log('[SmartRoute] Place details status:', data.status);

      if (data.status === 'OK' && data.result?.geometry?.location) {
        return {
          coordinate: {
            latitude: data.result.geometry.location.lat,
            longitude: data.result.geometry.location.lng,
          },
          name: data.result.name || data.result.formatted_address || 'Destination',
        };
      }
    }
  } catch (error) {
    console.warn('[SmartRoute] Place details failed, trying geocode fallback:', error);
  }

  if (placeName) {
    try {
      const geocodeUrl = `https://maps.googleapis.com/maps/api/geocode/json?address=${encodeURIComponent(placeName)}&key=${apiKey}`;
      console.log('[SmartRoute] Trying geocode fallback for:', placeName);
      const response = await fetch(geocodeUrl);

      if (response.ok) {
        const data = await response.json();
        console.log('[SmartRoute] Geocode status:', data.status);

        if (data.status === 'OK' && data.results?.length > 0) {
          const result = data.results[0];
          return {
            coordinate: {
              latitude: result.geometry.location.lat,
              longitude: result.geometry.location.lng,
            },
            name: result.formatted_address?.split(',')[0] || placeName,
          };
        }
      }
    } catch (error) {
      console.warn('[SmartRoute] Geocode fallback also failed:', error);
    }
  }

  return null;
}

export async function getSmartRoute(origin: Coordinate, destination: Coordinate): Promise<SmartRouteData> {
  const directionsResult = await fetchDirectionsRoute(origin, destination);

  let coordinates: Coordinate[];
  let distance: string;
  let duration: string;

  if (directionsResult) {
    coordinates = directionsResult.coordinates;
    distance = directionsResult.distance;
    duration = directionsResult.duration;
  } else {
    coordinates = generateRouteCoordinates(origin, destination);
    const distanceMiles = calculateDistance(origin, destination);
    const durationHours = distanceMiles / 55;

    distance = distanceMiles < 1 
      ? `${Math.round(distanceMiles * 5280)} ft` 
      : `${distanceMiles.toFixed(1)} mi`;

    const hours = Math.floor(durationHours);
    const minutes = Math.round((durationHours - hours) * 60);
    duration = hours > 0 ? `${hours}h ${minutes}m` : `${minutes} min`;
  }

  const midCoord = coordinates[Math.floor(coordinates.length / 2)];

  const [startWeather, middleWeather, endWeather] = await Promise.all([
    fetchRealWeather(origin.latitude, origin.longitude),
    fetchRealWeather(midCoord.latitude, midCoord.longitude),
    fetchRealWeather(destination.latitude, destination.longitude),
  ]);

  const weather = {
    start: startWeather,
    middle: middleWeather,
    end: endWeather,
  };

  const safety = generateSafetyData(weather);

  return {
    success: true,
    coordinates,
    distance,
    duration,
    weather,
    safety,
  };
}

export function getWeatherIconName(condition: string): string {
  const iconMap: Record<string, string> = {
    'Clear': 'sunny',
    'Clouds': 'cloud',
    'Rain': 'rainy',
    'Snow': 'snow',
    'Thunderstorm': 'thunderstorm',
    'Drizzle': 'rainy',
    'Mist': 'water',
    'Fog': 'water',
  };
  return iconMap[condition] || 'partly-sunny';
}

export function getRoadRiskColor(level: string): string {
  switch (level) {
    case 'safe': return '#2D5A3D';
    case 'caution': return '#F2A154';
    case 'warning': return '#D94848';
    default: return '#2D5A3D';
  }
}

