  { id: 'backpacking', name: 'Backpacking', icon: 'bag-handle' },
  { id: 'yoga', name: 'Outdoor Yoga', icon: 'flower' },
];

export default function ActivitiesScreen() {
  const router = useRouter();
  const insets = useSafeAreaInsets();
  const [selectedActivities, setSelectedActivities] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);

  const toggleActivity = (id: string) => {
    setSelectedActivities(prev =>
      prev.includes(id)
        ? prev.filter(a => a !== id)
        : [...prev, id]
    );
  };

  const handleContinue = async () => {
    setLoading(true);
    await new Promise(resolve => setTimeout(resolve, 300));
    router.replace('/(tabs)/discovery');
    setLoading(false);
  };

  return (
    <View style={[styles.container, { backgroundColor: colors.background.primary }]}>
      <ScrollView
        contentContainerStyle={[
          styles.scrollContent,
          { paddingTop: insets.top + spacing.lg, paddingBottom: insets.bottom + spacing.xl },
        ]}
        showsVerticalScrollIndicator={false}
      >
        <TouchableOpacity
          style={styles.backButton}
          onPress={() => router.back()}
          testID="button-back"
        >
          <Ionicons name="arrow-back" size={24} color={colors.bark[700]} />
        </TouchableOpacity>

        <View style={styles.logoContainer}>
          <Logo size="small" variant="dark" />
        </View>

        <Text style={styles.title}>Which activities do you like?</Text>
        <Text style={styles.subtitle}>
          Tell us what you love so we can connect you with like-minded adventurers in your area
        </Text>

        <View style={styles.activitiesGrid}>
          {activities.map((activity) => {
            const isSelected = selectedActivities.includes(activity.id);
            return (
              <TouchableOpacity
                key={activity.id}
                style={[styles.activityChip, isSelected && styles.activityChipSelected]}
                onPress={() => toggleActivity(activity.id)}
                activeOpacity={0.7}
                testID={`button-activity-${activity.id}`}
              >
                <Ionicons
                  name={activity.icon}
                  size={20}
                  color={isSelected ? colors.text.inverse : colors.bark[500]}
                />
                <Text style={[styles.activityText, isSelected && styles.activityTextSelected]}>
                  {activity.name}
                </Text>
              </TouchableOpacity>
            );
          })}
        </View>

        {selectedActivities.length > 0 ? (
          <Text style={styles.selectedCount}>
            {selectedActivities.length} selected
          </Text>
        ) : null}
      </ScrollView>

      <View style={[styles.bottomSection, { paddingBottom: insets.bottom + spacing.lg }]}>
        <Button
          title={loading ? 'Getting started...' : 'Next'}
          onPress={handleContinue}
          variant="ember"
          size="lg"
          fullWidth
          disabled={loading}
          icon={<Ionicons name="arrow-forward" size={20} color={colors.text.inverse} />}
          testID="button-continue-activities"
        />
      </View>
    </View>
  );
}

