  invitedBy?: string;
  displayName?: string;
  vehicle?: string;
  nomadStyle?: string;
  photoURL?: string;
  onboardingComplete?: boolean;
}

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  signUp: (email: string, password: string) => Promise<{ success: boolean; message?: string }>;
  signIn: (email: string, password: string) => Promise<{ success: boolean; message?: string }>;
  resendVerification: () => Promise<{ success: boolean; message?: string }>;
  checkEmailVerified: () => Promise<boolean>;
  submitSelfie: (selfieData?: string) => Promise<{ success: boolean; message?: string }>;
  refreshUserStatus: () => Promise<void>;
  updateProfile: (profile: Partial<User>) => Promise<{ success: boolean; message?: string }>;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

const AUTH_STORAGE_KEY = '@wildergo_auth';

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadStoredAuth();
  }, []);

  const loadStoredAuth = async () => {
    try {
      const stored = await AsyncStorage.getItem(AUTH_STORAGE_KEY);
      if (stored) {
        const parsed = JSON.parse(stored);
        setUser(parsed);
      }
    } catch (error) {
      console.error('Error loading auth:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const saveUser = async (userData: User) => {
    setUser(userData);
    await AsyncStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(userData));
  };

  const signUp = useCallback(async (email: string, password: string) => {
    console.log(`[CLIENT SIGNUP] === Starting signup for: ${email} ===`);
    try {
      const baseUrl = getApiUrl();
      const url = new URL('/api/auth/signup', baseUrl).href;
      console.log(`[CLIENT SIGNUP] Sending POST to: ${url}`);
      console.log(`[CLIENT SIGNUP] Payload: { email: "${email}", password: "***" }`);

      const response = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });

      console.log(`[CLIENT SIGNUP] Response status: ${response.status} ${response.statusText}`);

      const data = await response.json();
      console.log(`[CLIENT SIGNUP] Response data:`, JSON.stringify(data));

      if (data.success && data.uid) {
        console.log(`[CLIENT SIGNUP] SUCCESS - uid: ${data.uid}`);
        const newUser: User = {
          uid: data.uid,
          email: email.toLowerCase().trim(),
          emailVerified: true,
          selfieVerified: true,
          selfieSubmitted: true,
          onboardingComplete: true,
        };
        await saveUser(newUser);
        console.log(`[CLIENT SIGNUP] User saved to AsyncStorage with onboardingComplete=true, auto-navigating to home`);
      } else {
        console.log(`[CLIENT SIGNUP] FAILED - message: ${data.message}`);
      }

      return data;
    } catch (error: any) {
      console.error(`[CLIENT SIGNUP] NETWORK ERROR:`, error.message);
      console.error(`[CLIENT SIGNUP] Error details:`, JSON.stringify(error, Object.getOwnPropertyNames(error)));
      return { success: false, message: 'Network error. Please try again.' };
    }
  }, []);

  const signIn = useCallback(async (email: string, password: string) => {
    console.log(`[CLIENT SIGNIN] === Starting signin for: ${email} ===`);
    try {
      const baseUrl = getApiUrl();
      const url = new URL('/api/auth/signin', baseUrl).href;
      console.log(`[CLIENT SIGNIN] Sending POST to: ${url}`);

      const response = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });

      console.log(`[CLIENT SIGNIN] Response status: ${response.status} ${response.statusText}`);

      const data = await response.json();
      console.log(`[CLIENT SIGNIN] Response data:`, JSON.stringify(data));

      if (data.success && data.uid) {
        console.log(`[CLIENT SIGNIN] SUCCESS - uid: ${data.uid}`);
        const newUser: User = {
          uid: data.uid,
          email: email.toLowerCase().trim(),
          emailVerified: true,
          selfieVerified: true,
          selfieSubmitted: true,
          invitedBy: data.invitedBy,
          onboardingComplete: true,
        };
        await saveUser(newUser);
        console.log(`[CLIENT SIGNIN] User saved to AsyncStorage with onboardingComplete=true, auto-navigating to home`);
      } else {
        console.log(`[CLIENT SIGNIN] FAILED - message: ${data.message}`);
      }

      return data;
    } catch (error: any) {
      console.error(`[CLIENT SIGNIN] NETWORK ERROR:`, error.message);
      console.error(`[CLIENT SIGNIN] Error details:`, JSON.stringify(error, Object.getOwnPropertyNames(error)));
      return { success: false, message: 'Network error. Please try again.' };
    }
  }, []);

  const resendVerification = useCallback(async () => {
    if (!user) return { success: false, message: 'Not authenticated' };

    try {
      const baseUrl = getApiUrl();
      const response = await fetch(new URL('/api/auth/send-verification', baseUrl).href, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ uid: user.uid }),
      });

      return await response.json();
    } catch (error: any) {
      return { success: false, message: 'Network error. Please try again.' };
    }
  }, [user]);

  const checkEmailVerified = useCallback(async () => {
    if (!user) return false;

    try {
      const baseUrl = getApiUrl();
      const response = await fetch(new URL(`/api/auth/check-verification/${user.uid}`, baseUrl).href);
      const data = await response.json();

      if (data.success && data.emailVerified) {
        const updatedUser = { ...user, emailVerified: true };
        await saveUser(updatedUser);
        return true;
      }

      return false;
    } catch (error) {
      return false;
    }
  }, [user]);

  const submitSelfie = useCallback(async (selfieData?: string) => {
    if (!user) return { success: false, message: 'Not authenticated' };

    try {
      const baseUrl = getApiUrl();
      const response = await fetch(new URL('/api/auth/submit-selfie', baseUrl).href, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ uid: user.uid, selfieData: selfieData || 'submitted' }),
      });

      const data = await response.json();

      if (data.success) {
        const updatedUser = { ...user, selfieSubmitted: true };
        await saveUser(updatedUser);
      }

      return data;
    } catch (error: any) {
      return { success: false, message: 'Network error. Please try again.' };
    }
  }, [user]);

  const refreshUserStatus = useCallback(async () => {
    if (!user) return;

    try {
      const baseUrl = getApiUrl();
      const response = await fetch(new URL(`/api/auth/user-status/${user.uid}`, baseUrl).href);
      const data = await response.json();

      if (data.success) {
        const updatedUser = {
          ...user,
          emailVerified: data.emailVerified || false,
          selfieVerified: data.selfieVerified || false,
          selfieSubmitted: data.selfieSubmitted || false,
        };
        await saveUser(updatedUser);
      }
    } catch (error) {
      console.error('Refresh status error:', error);
    }
  }, [user]);

  const updateProfile = useCallback(async (profile: Partial<User>) => {
    if (!user) {
      return { success: false, message: 'Not authenticated' };
    }

    try {
      const baseUrl = getApiUrl();
      const response = await fetch(new URL('/api/auth/update-profile', baseUrl).href, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ uid: user.uid, ...profile }),
      });

      const data = await response.json();

      if (data.success) {
        const updatedUser = { ...user, ...profile };
        await saveUser(updatedUser);
      }

      return data;
    } catch (error: any) {
      console.error('Update profile error:', error);
      return { success: false, message: 'Network error. Please try again.' };
    }
  }, [user]);

  const logout = useCallback(async () => {
    try {
      await AsyncStorage.removeItem(AUTH_STORAGE_KEY);
      setUser(null);
    } catch (error) {
      console.error('Logout error:', error);
    }
  }, []);

  return (
    <AuthContext.Provider
      value={{
        user,
        isLoading,
        isAuthenticated: !!user,
        signUp,
        signIn,
        resendVerification,
        checkEmailVerified,
        submitSelfie,
        refreshUserStatus,
        updateProfile,
        logout,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    return {
      user: null,
      isLoading: false,
      isAuthenticated: false,
      signUp: async () => ({ success: false, message: 'Auth provider not ready' }),
      signIn: async () => ({ success: false, message: 'Auth provider not ready' }),
      resendVerification: async () => ({ success: false, message: 'Auth provider not ready' }),
      checkEmailVerified: async () => false,
      submitSelfie: async () => ({ success: false, message: 'Auth provider not ready' }),
      refreshUserStatus: async () => {},
      updateProfile: async () => ({ success: false, message: 'Auth provider not ready' }),
      logout: async () => {},
    };
  }
  return context;
}

