  },
});

const bannerStyles = StyleSheet.create({
  container: {
    position: 'absolute',
    top: 0,
    left: spacing.md,
    right: spacing.md,
    zIndex: 1000,
  },
  banner: {
    borderRadius: borderRadius.xl,
