// Google Maps API functions
const GOOGLE_MAPS_API_KEY = process.env.EXPO_PUBLIC_GOOGLE_MAPS_API_KEY || '';

/**
 * Get route between two points
 * Returns route with distance, duration, and polyline
 */
export const getRoute = async (origin: { latitude: number; longitude: number }, destination: { latitude: number; longitude: number }) => {
  try {
    const url = `https://maps.googleapis.com/maps/api/directions/json?` +
      `origin=${origin.latitude},${origin.longitude}&` +
      `destination=${destination.latitude},${destination.longitude}&` +
      `key=${GOOGLE_MAPS_API_KEY}`;

    const response = await fetch(url);
    const data = await response.json();

    if (data.status === 'OK') {
      const route = data.routes[0];
      const leg = route.legs[0];

      return {
        success: true,
        distance: leg.distance.text,
        distanceValue: leg.distance.value,
        duration: leg.duration.text,
        durationValue: leg.duration.value,
        polyline: route.overview_polyline.points,
        steps: leg.steps.map((step: any) => ({
          instruction: step.html_instructions.replace(/<[^>]*>/g, ''),
          distance: step.distance.text,
          duration: step.duration.text,
          location: step.start_location
        })),
        startAddress: leg.start_address,
        endAddress: leg.end_address
      };
    } else {
      return { 
        success: false, 
        error: `Directions API error: ${data.status}` 
      };
    }
  } catch (error: any) {
    console.error('Error getting route:', error);
    return { 
      success: false, 
      error: error.message 
    };
  }
};

/**
 * Get multiple route options (fastest, shortest, etc.)
 */
export const getRouteOptions = async (origin: { latitude: number; longitude: number }, destination: { latitude: number; longitude: number }) => {
  try {
    const url = `https://maps.googleapis.com/maps/api/directions/json?` +
      `origin=${origin.latitude},${origin.longitude}&` +
      `destination=${destination.latitude},${destination.longitude}&` +
      `alternatives=true&` +
      `key=${GOOGLE_MAPS_API_KEY}`;

    const response = await fetch(url);
    const data = await response.json();

    if (data.status === 'OK') {
      return {
        success: true,
        routes: data.routes.map((route: any, index: number) => ({
          id: index,
          summary: route.summary,
          distance: route.legs[0].distance.text,
          duration: route.legs[0].duration.text,
          polyline: route.overview_polyline.points
        }))
      };
    } else {
      return { success: false, error: data.status };
    }
  } catch (error: any) {
    return { success: false, error: error.message };
  }
};

/**
 * Convert address to coordinates (geocoding)
 */
export const geocodeAddress = async (address: string) => {
  try {
    const url = `https://maps.googleapis.com/maps/api/geocode/json?` +
      `address=${encodeURIComponent(address)}&` +
      `key=${GOOGLE_MAPS_API_KEY}`;

    const response = await fetch(url);
    const data = await response.json();

    if (data.status === 'OK') {
      const location = data.results[0].geometry.location;
      return {
        success: true,
        latitude: location.lat,
        longitude: location.lng,
        formattedAddress: data.results[0].formatted_address,
        placeId: data.results[0].place_id
      };
    } else {
      return { success: false, error: data.status };
    }
  } catch (error: any) {
    return { success: false, error: error.message };
  }
};

/**
 * Convert coordinates to address (reverse geocoding)
 */
export const reverseGeocode = async (latitude: number, longitude: number) => {
  try {
    const url = `https://maps.googleapis.com/maps/api/geocode/json?` +
      `latlng=${latitude},${longitude}&` +
      `key=${GOOGLE_MAPS_API_KEY}`;

    const response = await fetch(url);
    const data = await response.json();

    if (data.status === 'OK') {
      return {
        success: true,
        address: data.results[0].formatted_address,
        city: data.results[0].address_components.find((c: any) => 
          c.types.includes('locality'))?.long_name || '',
        state: data.results[0].address_components.find((c: any) => 
          c.types.includes('administrative_area_level_1'))?.short_name || ''
      };
    } else {
      return { success: false, error: data.status };
    }
  } catch (error: any) {
    return { success: false, error: error.message };
  }
};

/**
 * Search for places (for location autocomplete)
 */
export const searchPlaces = async (searchText: string, location: { latitude: number; longitude: number } | null = null) => {
  try {
    let url = `https://maps.googleapis.com/maps/api/place/textsearch/json?` +
      `query=${encodeURIComponent(searchText)}&` +
      `key=${GOOGLE_MAPS_API_KEY}`;

    if (location) {
      url += `&location=${location.latitude},${location.longitude}&radius=50000`;
    }

    const response = await fetch(url);
    const data = await response.json();

    if (data.status === 'OK') {
      return {
        success: true,
        places: data.results.map((place: any) => ({
          name: place.name,
          address: place.formatted_address,
          latitude: place.geometry.location.lat,
          longitude: place.geometry.location.lng,
          placeId: place.place_id
        }))
      };
    } else {
      return { success: false, error: data.status };
    }
  } catch (error: any) {
    return { success: false, error: error.message };
  }
};

/**
 * Calculate distance between two points
 */
export const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
  const R = 3959;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = 
    Math.sin(dLat/2) * Math.sin(dLat/2) +
    Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  const distance = R * c;

  return {
    miles: Math.round(distance * 10) / 10,
    kilometers: Math.round(distance * 1.60934 * 10) / 10
  };
};

/**
 * Decode Google Maps polyline into coordinates array
 */
export const decodePolyline = (encoded: string) => {
  const poly: { latitude: number; longitude: number }[] = [];
  let index = 0;
  const len = encoded.length;
  let lat = 0;
  let lng = 0;

  while (index < len) {
    let b;
    let shift = 0;
    let result = 0;
    do {
      b = encoded.charCodeAt(index++) - 63;
      result |= (b & 0x1f) << shift;
      shift += 5;
    } while (b >= 0x20);
    const dlat = (result & 1) !== 0 ? ~(result >> 1) : result >> 1;
    lat += dlat;

    shift = 0;
    result = 0;
    do {
      b = encoded.charCodeAt(index++) - 63;
      result |= (b & 0x1f) << shift;
      shift += 5;
    } while (b >= 0x20);
    const dlng = (result & 1) !== 0 ? ~(result >> 1) : result >> 1;
    lng += dlng;

    poly.push({
      latitude: lat / 1e5,
      longitude: lng / 1e5
    });
  }
  return poly;
};

export const mapService = {
  getMarkersForMode,
  getMarkerConfig,
  getRouteOverlapGlow,
  calculateNomadicDensity,
  getSmartRouteSuggestions,
  // Google Maps functions
  getRoute,
  getRouteOptions,
  geocodeAddress,
  reverseGeocode,
  searchPlaces,
  calculateDistance,
  decodePolyline,
};

export default mapService;

