import React, { useRef, useEffect } from 'react';
import { View, Text, StyleSheet, ScrollView, Animated } from 'react-native';
import { AnimatedWeatherIcon } from './AnimatedWeatherIcons';
import { colors, typography, spacing, borderRadius } from '@/constants/theme';

interface RouteWeatherPoint {
  time: string;
  location: string;
  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'stormy' | 'windy' | 'foggy';
  temperature: number;
  distance: string;
}

interface RouteWeatherTimelineProps {
  weatherPoints: RouteWeatherPoint[];
}

export const RouteWeatherTimeline: React.FC<RouteWeatherTimelineProps> = ({
  weatherPoints,
}) => {
  const fadeAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    Animated.timing(fadeAnim, {
      toValue: 1,
      duration: 800,
      useNativeDriver: true,
    }).start();
  }, [fadeAnim]);

  return (
    <Animated.View style={[styles.container, { opacity: fadeAnim }]}>
      <View style={styles.header}>
        <Text style={styles.headerText}>Weather Along Route</Text>
      </View>

      <ScrollView 
        horizontal 
        showsHorizontalScrollIndicator={false}
        contentContainerStyle={styles.scrollContent}
      >
        {weatherPoints.map((point, index) => (
          <RouteWeatherCard
            key={index}
            point={point}
            index={index}
            isLast={index === weatherPoints.length - 1}
          />
        ))}
      </ScrollView>
    </Animated.View>
  );
};

interface RouteWeatherCardProps {
  point: RouteWeatherPoint;
  index: number;
  isLast: boolean;
}

const RouteWeatherCard: React.FC<RouteWeatherCardProps> = ({ point, index, isLast }) => {
  const scaleAnim = useRef(new Animated.Value(0.8)).current;

  useEffect(() => {
    Animated.spring(scaleAnim, {
      toValue: 1,
      delay: index * 100,
      tension: 50,
      friction: 7,
      useNativeDriver: true,
    }).start();
  }, [scaleAnim, index]);

  return (
    <Animated.View style={[styles.cardWrapper, { transform: [{ scale: scaleAnim }] }]}>
      <View style={styles.card}>
        <View style={styles.iconWrapper}>
          <AnimatedWeatherIcon
            condition={point.condition}
            size={40}
            color={colors.accent.terracotta}
          />
        </View>

        <Text style={styles.time}>{point.time}</Text>
        <Text style={styles.temperature}>{point.temperature}°F</Text>
        <Text style={styles.location} numberOfLines={1}>{point.location}</Text>
        <Text style={styles.distance}>{point.distance}</Text>
      </View>

      {!isLast && (
        <View style={styles.connector}>
          <View style={styles.connectorLine} />
        </View>
      )}
    </Animated.View>
  );
};

const styles = StyleSheet.create({
