    lightColor: colors.deepTeal[500],
    darkColor: colors.deepTeal[700],
    glow: 'rgba(27, 75, 82, 0.4)',
    description: 'Pro rig network',
  },
];

interface ModeToggleProps {
  activeMode: AppMode;
  onModeChange: (mode: AppMode) => void;
  showPremiumBadge?: boolean;
  compact?: boolean;
  showAnimatedIcons?: boolean;
}

export const ModeToggle: React.FC<ModeToggleProps> = ({
  activeMode,
  onModeChange,
  showPremiumBadge = false,
  compact = false,
  showAnimatedIcons = true,
}) => {
  const slideAnim = useRef(new Animated.Value(0)).current;
  const scaleAnim = useRef(new Animated.Value(1)).current;
  const glowAnim = useRef(new Animated.Value(0)).current;
  const liquidAnim = useRef(new Animated.Value(0)).current;
  const prevModeRef = useRef<AppMode | null>(null);
  const isInitialMount = useRef(true);

  const [showRipple, setShowRipple] = useState(false);
  const [rippleColor, setRippleColor] = useState(colors.forestGreen[600]);

  const buttonWidth = compact
    ? (Dimensions.get('window').width - spacing.xl * 2 - spacing.sm * 2) / 3
    : (Dimensions.get('window').width - spacing.xl * 2 - spacing.md * 2) / 3;

  const currentModeConfig = modes.find(m => m.key === activeMode) || modes[1];

  const handleModeChange = (mode: AppMode) => {
    if (mode === activeMode) return;

    const newModeConfig = modes.find(m => m.key === mode);
    if (newModeConfig) {
      setRippleColor(newModeConfig.color);
      setShowRipple(true);
    }

    onModeChange(mode);
  };

  useEffect(() => {
    const index = modes.findIndex((m) => m.key === activeMode);
    const targetPosition = index * buttonWidth;

    if (isInitialMount.current) {
      slideAnim.setValue(targetPosition);
      isInitialMount.current = false;
      prevModeRef.current = activeMode;
      return;
    }

    if (prevModeRef.current === activeMode) {
      slideAnim.setValue(targetPosition);
      return;
    }

    prevModeRef.current = activeMode;

    Animated.parallel([
      Animated.sequence([
        Animated.timing(scaleAnim, {
          toValue: 0.92,
          duration: 80,
          useNativeDriver: true,
        }),
        Animated.spring(scaleAnim, {
          toValue: 1,
          tension: 300,
          friction: 15,
          useNativeDriver: true,
        }),
      ]),
      Animated.spring(slideAnim, {
        toValue: targetPosition,
        useNativeDriver: true,
        tension: 170,
        friction: 20,
      }),
      Animated.sequence([
        Animated.timing(glowAnim, {
          toValue: 1,
          duration: 150,
          useNativeDriver: false,
        }),
        Animated.timing(glowAnim, {
          toValue: 0.6,
          duration: 300,
          useNativeDriver: false,
        }),
      ]),
      Animated.sequence([
        Animated.timing(liquidAnim, {
          toValue: 1,
          duration: 200,
          useNativeDriver: false,
        }),
        Animated.timing(liquidAnim, {
          toValue: 0,
          duration: 400,
          useNativeDriver: false,
        }),
      ]),
    ]).start();
  }, [activeMode, buttonWidth, slideAnim, scaleAnim, glowAnim, liquidAnim]);

  const ContainerWrapper = Platform.OS === 'ios' ? BlurView : View;
  const containerProps = Platform.OS === 'ios'
    ? { tint: 'light' as const, intensity: blur.heavy, style: styles.container }
    : { style: [styles.container, styles.containerFallback] };

  return (
    <View style={styles.wrapper}>
      <ContainerWrapper {...containerProps}>
        {/* Liquid glow overlay */}
        <Animated.View
          pointerEvents="none"
          style={[
            styles.liquidGlow,
            {
              backgroundColor: currentModeConfig.glow,
              opacity: liquidAnim,
            },
          ]}
        />

        {/* Animated slider pill with gradient */}
        <Animated.View
          pointerEvents="none"
          style={[
            styles.sliderContainer,
            {
              width: buttonWidth - (compact ? 4 : 6),
              transform: [
                { translateX: slideAnim },
                { scale: scaleAnim },
              ],
            },
          ]}
        >
          <LinearGradient
            colors={[currentModeConfig.lightColor, currentModeConfig.color, currentModeConfig.darkColor]}
            start={{ x: 0, y: 0 }}
            end={{ x: 1, y: 1 }}
            style={styles.slider}
          />
          {/* Glow effect */}
          <Animated.View
            style={[
              styles.sliderGlow,
              {
                backgroundColor: currentModeConfig.glow,
                shadowColor: currentModeConfig.color,
                opacity: glowAnim,
              },
            ]}
          />
        </Animated.View>

        {/* Mode buttons */}
        {modes.map((mode) => {
          const isActive = activeMode === mode.key;
          const isPremiumLocked = mode.key === 'dating' && !showPremiumBadge;

          return (
            <TouchableOpacity
              key={mode.key}
              style={[styles.button, { width: buttonWidth }]}
              onPress={() => handleModeChange(mode.key)}
              activeOpacity={0.7}
            >
              <View style={styles.buttonContent}>
                {showAnimatedIcons ? (
                  <AnimatedModeIcon
                    mode={mode.key}
                    size={16}
                    isActive={isActive}
                    color={isActive ? colors.text.inverse : mode.color}
                  />
                ) : (
                  <Text style={styles.emoji}>{mode.emoji}</Text>
                )}
                <Text
                  style={[
                    styles.buttonText,
                    isActive && styles.activeButtonText,
                  ]}
                >
                  {mode.label}
                </Text>
                {isPremiumLocked && (
                  <View style={styles.premiumBadge}>
                    <Ionicons name="star" size={8} color={colors.sunsetOrange[400]} />
                  </View>
                )}
              </View>
            </TouchableOpacity>
          );
        })}
      </ContainerWrapper>

      {/* Liquid Ripple Effect on Mode Change */}
      <LiquidRipple
        color={rippleColor}
        visible={showRipple}
        onComplete={() => setShowRipple(false)}
      />
    </View>
  );
};

// Enhanced Mode Switcher for header placement
export const ModeHeader: React.FC<ModeToggleProps & { title?: string }> = ({
  activeMode,
  onModeChange,
  title,
  showPremiumBadge,
  showAnimatedIcons,
}) => {
  const currentModeConfig = modes.find(m => m.key === activeMode) || modes[1];

  return (
    <View style={headerStyles.container}>
      {title && <Text style={headerStyles.title}>{title}</Text>}
      <ModeToggle
        activeMode={activeMode}
        onModeChange={onModeChange}
        showPremiumBadge={showPremiumBadge}
        showAnimatedIcons={showAnimatedIcons}
      />
      <View style={headerStyles.modeInfo}>
        <Text style={[headerStyles.modeDescription, { color: currentModeConfig.color }]}>
          {currentModeConfig.description}
        </Text>
      </View>
    </View>
  );
};

// Compact Mode Indicator (for tab bar or status)
interface ModeIndicatorProps {
  mode: AppMode;
  size?: 'small' | 'medium' | 'large';
  showLabel?: boolean;
}

export const ModeIndicator: React.FC<ModeIndicatorProps> = ({
  mode,
  size = 'medium',
  showLabel = false,
}) => {
  const modeConfig = modes.find(m => m.key === mode) || modes[1];
  const iconSize = size === 'small' ? 14 : size === 'medium' ? 18 : 24;

  return (
    <View style={indicatorStyles.container}>
      <View style={[indicatorStyles.badge, { backgroundColor: modeConfig.color + '20' }]}>
        <AnimatedModeIcon
          mode={mode}
          size={iconSize}
          isActive={true}
          color={modeConfig.color}
        />
        {showLabel && (
          <Text style={[indicatorStyles.label, { color: modeConfig.color }]}>
            {modeConfig.label}
          </Text>
        )}
      </View>
    </View>
  );
};

const styles = StyleSheet.create({
