import { useRouter } from '@/hooks/useRouterCompat';
import { colors, typography, spacing, borderRadius } from '@/constants/theme';

interface Message {
  id: string;
  text: string;
  sender: 'me' | 'them';
  timestamp: string;
}

const MOCK_MESSAGES: Record<string, Message[]> = {
  '1': [
    { id: 'm1', text: 'Hey! Are you heading to Glacier too?', sender: 'them', timestamp: '2:30 PM' },
    { id: 'm2', text: 'Yes! Planning to be there by Thursday', sender: 'me', timestamp: '2:32 PM' },
    { id: 'm3', text: 'Amazing! I found a great boondocking spot near the west entrance', sender: 'them', timestamp: '2:33 PM' },
    { id: 'm4', text: 'Send me the coords? My Starlink should work there', sender: 'me', timestamp: '2:35 PM' },
  ],
  '2': [
    { id: 'm1', text: 'Your van build looks incredible!', sender: 'them', timestamp: '11:00 AM' },
    { id: 'm2', text: 'Thanks! Took about 6 months. Happy to share the build list', sender: 'me', timestamp: '11:05 AM' },
  ],
  '3': [
    { id: 'm1', text: 'The stargazing at Big Bend was unreal last night', sender: 'them', timestamp: 'Yesterday' },
  ],
  '4': [
    { id: 'm1', text: 'Just finished my solar setup - 400W panels with a 200Ah battery', sender: 'them', timestamp: '2 days ago' },
    { id: 'm2', text: 'Nice! What charge controller did you go with?', sender: 'me', timestamp: '2 days ago' },
  ],
};

export default function DMChatScreen() {
  const params = useLocalSearchParams<{ id: string; name: string; avatar: string }>();
  const router = useRouter();
  const insets = useSafeAreaInsets();
  const [messages, setMessages] = useState<Message[]>(
    MOCK_MESSAGES[params.id || '1'] || []
  );
  const [inputText, setInputText] = useState('');
  const flatListRef = useRef<FlatList>(null);

  const handleSend = useCallback(() => {
    if (!inputText.trim()) return;
    const newMsg: Message = {
      id: `m${Date.now()}`,
      text: inputText.trim(),
      sender: 'me',
      timestamp: 'Just now',
    };
    setMessages(prev => [newMsg, ...prev]);
    setInputText('');
  }, [inputText]);

  const renderMessage = useCallback(({ item }: { item: Message }) => {
    const isMe = item.sender === 'me';
    return (
      <View style={[msgStyles.row, isMe ? msgStyles.rowMe : null]}>
        <View style={[msgStyles.bubble, isMe ? msgStyles.bubbleMe : msgStyles.bubbleThem]}>
          <Text style={[msgStyles.text, isMe ? msgStyles.textMe : null]}>{item.text}</Text>
          <Text style={[msgStyles.time, isMe ? msgStyles.timeMe : null]}>{item.timestamp}</Text>
        </View>
      </View>
    );
  }, []);

  const contactName = params.name || 'Chat';

  return (
    <View style={[styles.container, { paddingTop: insets.top }]}>
      <View style={styles.header}>
        {Platform.OS === 'ios' ? (
          <BlurView intensity={80} tint="light" style={styles.headerBlur}>
            <HeaderContent name={contactName} avatar={params.avatar} onBack={() => router.back()} />
          </BlurView>
        ) : (
          <View style={styles.headerFallback}>
            <HeaderContent name={contactName} avatar={params.avatar} onBack={() => router.back()} />
          </View>
        )}
      </View>

      <KeyboardAvoidingView
        style={styles.flex}
        behavior="padding"
        keyboardVerticalOffset={0}
      >
        <FlatList
          ref={flatListRef}
          data={messages}
          renderItem={renderMessage}
          keyExtractor={(item) => item.id}
          inverted={messages.length > 0}
          contentContainerStyle={[styles.messagesList, { paddingBottom: 80 }]}
          ListEmptyComponent={
            <View style={styles.emptyState}>
              <Ionicons name="chatbubble-ellipses-outline" size={48} color={colors.bark[300]} />
              <Text style={styles.emptyText}>Start a conversation with {contactName}</Text>
            </View>
          }
          showsVerticalScrollIndicator={false}
        />

        <View style={[styles.inputWrapper, { paddingBottom: Math.max(insets.bottom, 12) }]}>
          <View style={styles.inputRow}>
            <TextInput
              style={styles.input}
              value={inputText}
              onChangeText={setInputText}
              placeholder="Type a message..."
              placeholderTextColor={colors.bark[400]}
              multiline
              maxLength={500}
              testID="input-dm-message"
            />
            <TouchableOpacity
              style={[styles.sendBtn, !inputText.trim() ? styles.sendBtnDisabled : null]}
              onPress={handleSend}
              disabled={!inputText.trim()}
              testID="button-send-dm"
            >
              <Ionicons name="send" size={20} color={inputText.trim() ? colors.text.inverse : colors.bark[400]} />
            </TouchableOpacity>
          </View>
        </View>
      </KeyboardAvoidingView>
    </View>
  );
}

function HeaderContent({ name, avatar, onBack }: { name: string; avatar?: string; onBack: () => void }) {
  return (
    <View style={headerStyles.content}>
      <TouchableOpacity onPress={onBack} style={headerStyles.backBtn} testID="button-dm-back">
        <Ionicons name="chevron-back" size={24} color={colors.bark[800]} />
      </TouchableOpacity>
      {avatar ? (
        <Image source={{ uri: avatar }} style={headerStyles.avatar} />
      ) : (
        <View style={headerStyles.avatarPlaceholder}>
