import { QueryClient, QueryFunction } from "@tanstack/react-query";
import { Platform } from "react-native";
import Constants from "expo-constants";

export function getApiUrl(): string {
  if (Platform.OS === 'web' && typeof window !== 'undefined') {
    const loc = window.location;
    if (loc.hostname === 'localhost' || loc.hostname === '127.0.0.1') {
      return 'http://localhost:5000/';
    }
    return `${loc.protocol}//${loc.host}/`;
  }

  let host = process.env.EXPO_PUBLIC_DOMAIN;

  if (!host) {
    host = process.env.EXPO_PUBLIC_API_URL;
  }

  if (!host) {
    const configApiUrl = Constants.expoConfig?.extra?.apiBaseUrl;
    if (configApiUrl) {
      return configApiUrl.endsWith('/') ? configApiUrl : configApiUrl + '/';
    }
  }

  if (!host) {
    const hostUri = Constants.expoConfig?.extra?.expoGo?.debuggerHost
      || Constants.expoConfig?.extra?.expoClient?.hostUri;
    if (hostUri) {
      host = hostUri.split('/')[0];
    }
  }

  if (!host) {
    console.warn("No API URL configured. Set EXPO_PUBLIC_DOMAIN or EXPO_PUBLIC_API_URL.");
    return 'https://localhost:5000/';
  }

  if (host.startsWith('http://') || host.startsWith('https://')) {
    let url = new URL(host);
    url.port = '';
    return url.href;
  }

  let url = new URL(`https://${host}`);
  url.port = '';

  return url.href;
}

async function throwIfResNotOk(res: Response) {
  if (!res.ok) {
    const text = (await res.text()) || res.statusText;
    throw new Error(`${res.status}: ${text}`);
  }
}

export async function apiRequest(
  method: string,
  route: string,
  data?: unknown | undefined,
): Promise<Response> {
  const baseUrl = getApiUrl();
  const url = new URL(route, baseUrl);

  const res = await fetch(url, {
    method,
    headers: data ? { "Content-Type": "application/json" } : {},
    body: data ? JSON.stringify(data) : undefined,
    credentials: "include",
  });

  await throwIfResNotOk(res);
  return res;
}

type UnauthorizedBehavior = "returnNull" | "throw";
export const getQueryFn: <T>(options: {
  on401: UnauthorizedBehavior;
}) => QueryFunction<T> =
  ({ on401: unauthorizedBehavior }) =>
  async ({ queryKey }) => {
    const baseUrl = getApiUrl();
    const url = new URL(queryKey.join("/") as string, baseUrl);

    const res = await fetch(url, {
      credentials: "include",
    });

    if (unauthorizedBehavior === "returnNull" && res.status === 401) {
      return null;
    }

    await throwIfResNotOk(res);
    return await res.json();
  };

export const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      queryFn: getQueryFn({ on401: "throw" }),
      refetchInterval: false,
      refetchOnWindowFocus: false,
      staleTime: Infinity,
      retry: false,
    },
    mutations: {
      retry: false,
    },
  },
});

