const OPENWEATHER_API_KEY = process.env.EXPO_PUBLIC_OPENWEATHER_API_KEY || '';
const BASE_URL = 'https://api.openweathermap.org/data/2.5';

if (!OPENWEATHER_API_KEY) {
  console.warn('[WeatherService] EXPO_PUBLIC_OPENWEATHER_API_KEY is not set - weather features will not work');
}

export interface WeatherData {
  success: boolean;
  temperature?: number;
  feelsLike?: number;
  condition?: string;
  description?: string;
  icon?: string;
  humidity?: number;
  windSpeed?: number;
  windDirection?: number;
  visibility?: number;
  cloudCover?: number;
  sunrise?: Date;
  sunset?: Date;
  error?: string;
}

export interface ForecastDay {
  date: string;
  temperature: number;
  tempMin?: number;
  tempMax?: number;
  condition: string;
  description: string;
  icon: string;
  humidity: number;
  windSpeed: number;
  rain: number;
}

export interface HourlyForecast {
  time: string;
  hour: number;
  temperature: number;
  condition: string;
  description: string;
  icon: string;
  humidity: number;
  windSpeed: number;
  precipitation: number;
}

export interface HourlyForecastData {
  success: boolean;
  hourly?: HourlyForecast[];
  error?: string;
}

export interface DetailedForecastData {
  success: boolean;
  current?: WeatherData;
  hourly?: HourlyForecast[];
  daily?: ForecastDay[];
  locationName?: string;
  error?: string;
}

export interface ForecastData {
  success: boolean;
  forecasts?: ForecastDay[];
  error?: string;
}

export interface WeatherAlert {
  type: 'warning' | 'advisory';
  title: string;
  description: string;
}

export interface AlertsData {
  success: boolean;
  alerts?: WeatherAlert[];
  currentWeather?: WeatherData;
  error?: string;
}

export interface RouteWeatherData {
  success: boolean;
  start?: WeatherData;
  middle?: WeatherData;
  end?: WeatherData;
  overallCondition?: string;
  error?: string;
}

export const getCurrentWeather = async (latitude: number, longitude: number): Promise<WeatherData> => {
  try {
    if (!OPENWEATHER_API_KEY) {
      return { success: false, error: 'OpenWeather API key not configured' };
    }
    const url = `${BASE_URL}/weather?lat=${latitude}&lon=${longitude}&appid=${OPENWEATHER_API_KEY}&units=imperial`;
    const response = await fetch(url);

    if (!response.ok) {
      return { success: false, error: `Weather unavailable (${response.status})` };
    }

    const data = await response.json();

    return {
      success: true,
      temperature: Math.round(data.main.temp),
      feelsLike: Math.round(data.main.feels_like),
      condition: data.weather[0].main,
      description: data.weather[0].description,
      icon: data.weather[0].icon,
      humidity: data.main.humidity,
      windSpeed: Math.round(data.wind.speed),
      windDirection: data.wind.deg,
      visibility: data.visibility,
      cloudCover: data.clouds.all,
      sunrise: new Date(data.sys.sunrise * 1000),
      sunset: new Date(data.sys.sunset * 1000)
    };
  } catch (error: any) {
    console.log('Weather fetch issue:', error?.message?.substring(0, 60));
    return { 
      success: false, 
      error: error.message 
    };
  }
};

export const getForecast = async (latitude: number, longitude: number): Promise<ForecastData> => {
  try {
    if (!OPENWEATHER_API_KEY) {
      return { success: false, error: 'OpenWeather API key not configured' };
    }
    const url = `${BASE_URL}/forecast?lat=${latitude}&lon=${longitude}&appid=${OPENWEATHER_API_KEY}&units=imperial`;
    const response = await fetch(url);

    if (!response.ok) {
      return { success: false, error: `Forecast unavailable (${response.status})` };
    }

    const data = await response.json();

    const dailyForecasts: ForecastDay[] = [];
    const days: { [key: string]: any[] } = {};

    data.list.forEach((item: any) => {
      const date = new Date(item.dt * 1000).toLocaleDateString();
      if (!days[date]) {
        days[date] = [];
      }
      days[date].push(item);
    });

    Object.keys(days).forEach(date => {
      const dayData = days[date];
      const noonIndex = Math.floor(dayData.length / 2);
      const forecast = dayData[noonIndex];

      dailyForecasts.push({
        date: date,
        temperature: Math.round(forecast.main.temp),
        condition: forecast.weather[0].main,
        description: forecast.weather[0].description,
        icon: forecast.weather[0].icon,
        humidity: forecast.main.humidity,
        windSpeed: Math.round(forecast.wind.speed),
        rain: forecast.rain ? forecast.rain['3h'] : 0
      });
    });

    return {
      success: true,
      forecasts: dailyForecasts.slice(0, 5)
    };
  } catch (error: any) {
    console.log('Forecast fetch issue:', error?.message?.substring(0, 60));
    return { 
      success: false, 
      error: error.message 
    };
  }
};

export const getWeatherAlerts = async (latitude: number, longitude: number): Promise<AlertsData> => {
  try {
    const weather = await getCurrentWeather(latitude, longitude);

    if (!weather.success) return { success: false, error: weather.error };

    const alerts: WeatherAlert[] = [];

    if (weather.condition === 'Thunderstorm') {
      alerts.push({
        type: 'warning',
        title: 'Thunderstorm Warning',
        description: 'Thunderstorms in the area. Exercise caution.'
      });
    }

    if (weather.condition === 'Snow') {
      alerts.push({
        type: 'advisory',
        title: 'Snow Advisory',
        description: 'Snowy conditions. Roads may be slippery.'
      });
    }

    if (weather.windSpeed && weather.windSpeed > 25) {
      alerts.push({
        type: 'advisory',
        title: 'High Wind Advisory',
        description: `Wind speeds reaching ${weather.windSpeed} mph.`
      });
    }

    return {
      success: true,
      alerts: alerts,
      currentWeather: weather
    };
  } catch (error: any) {
    return { success: false, error: error.message };
  }
};

interface RouteCoordinate {
  latitude: number;
  longitude: number;
}

export const getRouteWeather = async (routeCoordinates: RouteCoordinate[]): Promise<RouteWeatherData> => {
  try {
    if (!routeCoordinates || routeCoordinates.length < 2) {
      return { success: false, error: 'Invalid route coordinates' };
    }

    const startPoint = routeCoordinates[0];
    const middlePoint = routeCoordinates[Math.floor(routeCoordinates.length / 2)];
    const endPoint = routeCoordinates[routeCoordinates.length - 1];

    const [startWeather, middleWeather, endWeather] = await Promise.all([
      getCurrentWeather(startPoint.latitude, startPoint.longitude),
      getCurrentWeather(middlePoint.latitude, middlePoint.longitude),
      getCurrentWeather(endPoint.latitude, endPoint.longitude)
    ]);

    return {
      success: true,
      start: startWeather,
      middle: middleWeather,
      end: endWeather,
      overallCondition: getMostSevereCondition([
        startWeather.condition || 'Clear',
        middleWeather.condition || 'Clear',
        endWeather.condition || 'Clear'
      ])
    };
  } catch (error: any) {
    console.log('Route weather fetch issue:', error?.message?.substring(0, 60));
    return { 
      success: false, 
      error: error.message 
    };
  }
};

const getMostSevereCondition = (conditions: string[]): string => {
  const severity: { [key: string]: number } = {
    'Thunderstorm': 5,
    'Tornado': 5,
    'Snow': 4,
    'Rain': 3,
    'Drizzle': 2,
    'Clouds': 1,
    'Clear': 0
  };

  let mostSevere = 'Clear';
  let highestSeverity = 0;

  conditions.forEach(condition => {
    const level = severity[condition] || 0;
    if (level > highestSeverity) {
      highestSeverity = level;
      mostSevere = condition;
    }
  });

  return mostSevere;
};

export const getWeatherIconUrl = (iconCode: string): string => {
  return `https://openweathermap.org/img/wn/${iconCode}@2x.png`;
};

export const getWindDirection = (degrees: number): string => {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];
  const index = Math.round(degrees / 45) % 8;
  return directions[index];
};

export const getDetailedForecast = async (
  latitude: number, 
  longitude: number
): Promise<DetailedForecastData> => {
  try {
    if (!OPENWEATHER_API_KEY) {
      return { success: false, error: 'OpenWeather API key not configured' };
    }
    const forecastUrl = `${BASE_URL}/forecast?lat=${latitude}&lon=${longitude}&appid=${OPENWEATHER_API_KEY}&units=imperial`;

    const [currentWeather, forecastResponse] = await Promise.all([
      getCurrentWeather(latitude, longitude),
      fetch(forecastUrl)
    ]);

    if (!forecastResponse.ok) {
      return { success: false, error: `Forecast unavailable (${forecastResponse.status})` };
    }

    const forecastData = await forecastResponse.json();
    const locationName = forecastData.city?.name || 'Current Location';

    const hourlyForecasts: HourlyForecast[] = forecastData.list.slice(0, 12).map((item: any) => {
      const date = new Date(item.dt * 1000);
      return {
        time: date.toLocaleTimeString('en-US', { hour: 'numeric', hour12: true }),
        hour: date.getHours(),
        temperature: Math.round(item.main.temp),
        condition: item.weather[0].main,
        description: item.weather[0].description,
        icon: item.weather[0].icon,
        humidity: item.main.humidity,
        windSpeed: Math.round(item.wind.speed),
        precipitation: item.pop ? Math.round(item.pop * 100) : 0
      };
    });

    const dailyMap: { [key: string]: any[] } = {};
    forecastData.list.forEach((item: any) => {
      const dateKey = new Date(item.dt * 1000).toLocaleDateString('en-US', { 
        weekday: 'short', 
        month: 'short', 
        day: 'numeric' 
      });
      if (!dailyMap[dateKey]) {
        dailyMap[dateKey] = [];
      }
      dailyMap[dateKey].push(item);
    });

    const dailyForecasts: ForecastDay[] = Object.entries(dailyMap).slice(0, 5).map(([date, items]) => {
      const temps = items.map((i: any) => i.main.temp);
      const midItem = items[Math.floor(items.length / 2)];

      return {
        date,
        temperature: Math.round(midItem.main.temp),
        tempMin: Math.round(Math.min(...temps)),
        tempMax: Math.round(Math.max(...temps)),
        condition: midItem.weather[0].main,
        description: midItem.weather[0].description,
        icon: midItem.weather[0].icon,
        humidity: midItem.main.humidity,
        windSpeed: Math.round(midItem.wind.speed),
        rain: midItem.rain ? midItem.rain['3h'] || 0 : 0
      };
    });

    return {
      success: true,
      current: currentWeather.success ? currentWeather : undefined,
      hourly: hourlyForecasts,
      daily: dailyForecasts,
      locationName
    };

  } catch (error: any) {
    console.log('Detailed forecast fetch issue:', error?.message?.substring(0, 60));
    return {
      success: false,
      error: error.message
    };
  }
};

client/components/map/WeatherHUD.tsx.content:
/**
 * Weather HUD Panel
 * Liquid Glass panel showing Real-Feel temperature and weather shifts
 * Premium outdoor aesthetic with high-intensity blur
 */

import React, { useEffect, useRef, useMemo } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Animated,
  Platform,
} from 'react-native';
import { BlurView } from 'expo-blur';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import {
  colors,
  borderRadius,
  spacing,
  typography,
  shadows,
  blur,
} from '@/constants/theme';
import {
  WeatherData,
  weatherConditionConfig,
  getWeatherForLocation,
} from '@/services/map/advancedMapService';

interface WeatherHUDProps {
  latitude: number;
  longitude: number;
  onExpand?: () => void;
  compact?: boolean;
}

export const WeatherHUD: React.FC<WeatherHUDProps> = ({
  latitude,
  longitude,
  onExpand,
  compact = false,
}) => {
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const shiftIndicatorAnim = useRef(new Animated.Value(0)).current;

  const weather = useMemo(
    () => getWeatherForLocation(latitude, longitude),
    [latitude, longitude]
  );

  // Calculate weather shift (comparing to forecast)
  const weatherShift = useMemo(() => {
    if (!weather?.forecast || weather.forecast.length === 0) {
      return null;
    }

    const tomorrow = weather.forecast[0];
    const tempDiff = tomorrow.high - weather.temperature;
    const isWarming = tempDiff > 0;
    const shiftMagnitude = Math.abs(tempDiff);

    let shiftLabel = 'Stable';
    if (shiftMagnitude > 15) {
      shiftLabel = isWarming ? 'Warming significantly' : 'Cooling significantly';
    } else if (shiftMagnitude > 8) {
      shiftLabel = isWarming ? 'Warming' : 'Cooling';
    } else if (shiftMagnitude > 3) {
      shiftLabel = isWarming ? 'Slight warming' : 'Slight cooling';
    }

    return {
      isWarming,
      magnitude: shiftMagnitude,
      label: shiftLabel,
      nextCondition: tomorrow.condition,
    };
  }, [weather]);

  useEffect(() => {
    Animated.timing(fadeAnim, {
      toValue: 1,
      duration: 500,
      useNativeDriver: true,
    }).start();

    // Animate shift indicator
    if (weatherShift && weatherShift.magnitude > 5) {
      Animated.loop(
        Animated.sequence([
          Animated.timing(shiftIndicatorAnim, {
            toValue: 1,
            duration: 1200,
            useNativeDriver: true,
          }),
          Animated.timing(shiftIndicatorAnim, {
            toValue: 0,
            duration: 1200,
            useNativeDriver: true,
          }),
        ])
      ).start();
    }
  }, [fadeAnim, shiftIndicatorAnim, weatherShift]);

  if (!weather) return null;

  const config = weatherConditionConfig[weather.condition];

  // Calculate feel difference
  const feelDiff = weather.feelsLike - weather.temperature;
  const feelDescription = Math.abs(feelDiff) <= 2
    ? 'Feels accurate'
    : feelDiff > 0
    ? `Feels ${Math.abs(feelDiff)}° warmer`
    : `Feels ${Math.abs(feelDiff)}° cooler`;

  const renderContent = () => (
    <View style={[styles.content, compact && styles.contentCompact]}>
      {/* Current Weather Row */}
      <View style={styles.currentRow}>
        <View style={[styles.iconContainer, { backgroundColor: config.color + '20' }]}>
          <Ionicons
            name={config.icon as keyof typeof Ionicons.glyphMap}
            size={compact ? 20 : 28}
            color={config.color}
          />
        </View>

        <View style={styles.tempContainer}>
          <Text style={[styles.temperature, compact && styles.temperatureCompact]}>
            {weather.temperature}°
          </Text>
          <Text style={styles.condition}>{config.label}</Text>
        </View>

        {!compact && (
          <View style={styles.feelsLikeContainer}>
            <Text style={styles.feelsLikeLabel}>Real-Feel</Text>
            <Text style={[styles.feelsLikeTemp, { color: config.color }]}>
              {weather.feelsLike}°F
            </Text>
            <Text style={styles.feelsLikeDesc}>{feelDescription}</Text>
          </View>
        )}
      </View>

      {/* Weather Metrics */}
      {!compact && (
        <View style={styles.metricsRow}>
          <View style={styles.metric}>
            <Ionicons name="water-outline" size={16} color={colors.deepTeal[500]} />
            <Text style={styles.metricValue}>{weather.humidity}%</Text>
            <Text style={styles.metricLabel}>Humidity</Text>
          </View>
          <View style={styles.metricDivider} />
          <View style={styles.metric}>
            <Ionicons name="leaf-outline" size={16} color={colors.forestGreen[500]} />
            <Text style={styles.metricValue}>{weather.windSpeed} mph</Text>
            <Text style={styles.metricLabel}>{weather.windDirection}</Text>
          </View>
          <View style={styles.metricDivider} />
          <View style={styles.metric}>
            <Ionicons name="sunny-outline" size={16} color={colors.sunsetOrange[500]} />
            <Text style={styles.metricValue}>{weather.uvIndex}</Text>
            <Text style={styles.metricLabel}>UV Index</Text>
          </View>
        </View>
      )}

      {/* Weather Shift Indicator */}
      {weatherShift && weatherShift.magnitude > 3 && (
        <Animated.View
          style={[
            styles.shiftContainer,
            compact && styles.shiftContainerCompact,
            {
              opacity: shiftIndicatorAnim.interpolate({
                inputRange: [0, 1],
                outputRange: [0.7, 1],
              }),
            },
          ]}
        >
          <LinearGradient
            colors={
              weatherShift.isWarming
                ? [colors.sunsetOrange[500] + '20', colors.sunsetOrange[500] + '10']
                : [colors.deepTeal[500] + '20', colors.deepTeal[500] + '10']
            }
            start={{ x: 0, y: 0 }}
            end={{ x: 1, y: 0 }}
            style={styles.shiftGradient}
          >
            <Ionicons
              name={weatherShift.isWarming ? 'trending-up' : 'trending-down'}
              size={16}
              color={weatherShift.isWarming ? colors.sunsetOrange[500] : colors.deepTeal[500]}
            />
            <Text
              style={[
                styles.shiftText,
                {
                  color: weatherShift.isWarming
                    ? colors.sunsetOrange[600]
                    : colors.deepTeal[600],
                },
              ]}
            >
              {weatherShift.label}
            </Text>
            {weatherShift.nextCondition !== weather.condition && (
              <>
                <Ionicons name="arrow-forward" size={12} color={colors.bark[400]} />
                <Ionicons
                  name={weatherConditionConfig[weatherShift.nextCondition].icon as keyof typeof Ionicons.glyphMap}
                  size={14}
                  color={weatherConditionConfig[weatherShift.nextCondition].color}
                />
              </>
            )}
          </LinearGradient>
        </Animated.View>
      )}

      {/* Expand Button */}
      {onExpand && (
        <TouchableOpacity style={styles.expandButton} onPress={onExpand}>
          <Text style={styles.expandText}>Full Forecast</Text>
          <Ionicons name="chevron-forward" size={16} color={colors.bark[400]} />
        </TouchableOpacity>
      )}
    </View>
  );

  return (
    <Animated.View style={[styles.container, compact && styles.containerCompact, { opacity: fadeAnim }]}>
      {Platform.OS === 'ios' ? (
        <BlurView
          tint="light"
          intensity={blur.heavy}
          style={[styles.blurContainer, compact && styles.blurContainerCompact]}
        >
          {renderContent()}
        </BlurView>
      ) : (
        <View style={[styles.androidContainer, compact && styles.androidContainerCompact]}>
          {renderContent()}
        </View>
      )}
    </Animated.View>
  );
};

// Mini weather indicator for map control bar
interface MiniWeatherIndicatorProps {
  latitude: number;
  longitude: number;
  onPress: () => void;
}

export const MiniWeatherIndicator: React.FC<MiniWeatherIndicatorProps> = ({
  latitude,
  longitude,
  onPress,
}) => {
  const weather = useMemo(
    () => getWeatherForLocation(latitude, longitude),
    [latitude, longitude]
  );

  if (!weather) return null;

  const config = weatherConditionConfig[weather.condition];

  return (
    <TouchableOpacity style={styles.miniContainer} onPress={onPress} activeOpacity={0.8}>
      {Platform.OS === 'ios' ? (
        <BlurView tint="light" intensity={blur.medium} style={styles.miniBlur}>
          <View style={styles.miniContent}>
            <Ionicons
              name={config.icon as keyof typeof Ionicons.glyphMap}
              size={16}
              color={config.color}
            />
            <Text style={styles.miniTemp}>{weather.temperature}°</Text>
          </View>
        </BlurView>
      ) : (
        <View style={styles.miniAndroid}>
          <Ionicons
            name={config.icon as keyof typeof Ionicons.glyphMap}
            size={16}
            color={config.color}
          />
          <Text style={styles.miniTemp}>{weather.temperature}°</Text>
        </View>
      )}
    </TouchableOpacity>
  );
};

