import React, { forwardRef } from 'react';
import { Platform, StyleSheet } from 'react-native';
import MapView, { Marker, PROVIDER_GOOGLE, Region } from 'react-native-maps';
import { colors } from '@/constants/theme';

export interface MapMarkerData {
  id: string;
  type: 'traveler' | 'campfire' | 'match' | 'builder' | 'pin';
  latitude?: number;
  longitude?: number;
  lat?: number;
  lng?: number;
  name: string;
  subtitle?: string;
  isDroppedPin?: boolean;
}

interface NativeMapProps {
  region: Region;
  onRegionChange: (region: Region) => void;
  markers: MapMarkerData[];
  onMarkerPress: (marker: MapMarkerData) => void;
  showUserLocation: boolean;
  ghostModeMarker?: {
    latitude: number;
    longitude: number;
  } | null;
}

export const NativeMap = forwardRef<MapView, NativeMapProps>(({
  region,
  onRegionChange,
  markers,
  onMarkerPress,
  showUserLocation,
  ghostModeMarker,
}, ref) => {
  return (
    <MapView
      ref={ref}
      style={styles.map}
      provider={Platform.OS === 'android' ? PROVIDER_GOOGLE : undefined}
      initialRegion={region}
      onRegionChangeComplete={onRegionChange}
      showsUserLocation={showUserLocation}
      showsMyLocationButton={false}
      showsCompass={false}
      mapType="terrain"
    >
      {markers.map((marker) => {
        const lat = marker.latitude ?? marker.lat ?? 0;
        const lng = marker.longitude ?? marker.lng ?? 0;

        return (
          <Marker
            key={marker.id}
            coordinate={{ latitude: lat, longitude: lng }}
            title={marker.name}
            description={marker.subtitle}
            onPress={() => onMarkerPress(marker)}
            pinColor={
              marker.isDroppedPin || marker.type === 'pin' ? '#E74C3C' :
              marker.type === 'match' ? colors.ember[500] :
              marker.type === 'campfire' ? colors.sunsetOrange[500] :
              marker.type === 'builder' ? colors.driftwood[500] :
              colors.forestGreen[500]
            }
          />
        );
      })}

      {ghostModeMarker && (
        <Marker
          coordinate={ghostModeMarker}
          title="You (Ghost Mode)"
          pinColor="#666666"
          opacity={0.5}
        />
      )}
    </MapView>
  );
});

const styles = StyleSheet.create({
  map: {
    flex: 1,
    width: '100%',
    height: '100%',
  },
});

export default NativeMap;

