import React from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Dimensions,
} from 'react-native';
import { Image } from 'expo-image';
import { Feather } from '@expo/vector-icons';
import { typography, spacing, borderRadius } from '@/constants/theme';

const { width: SCREEN_WIDTH } = Dimensions.get('window');

const CARD_BG = '#FFFFFF';
const SECTION_BG = '#F5EFE6';
const ACCENT_AMBER = '#F59E0B';
const ACCENT_TEAL = '#4ECDC4';
const ACCENT_MOSS = '#4ADE80';
const TEXT_PRIMARY = '#2A2A2A';
const TEXT_SECONDARY = '#4A5568';

interface BuilderProfile {
  id: string;
  name?: string;
  businessName: string;
  ownerName?: string;
  imageUrl: string;
  coverImageUrl?: string;
  location: string;
  expertise: string[];
  rating: number;
  reviewCount: number;
  verified: boolean;
  yearsExperience?: number;
  buildsCompleted?: number;
  consultationRate: number;
  availability?: string;
  portfolioImages?: string[];
  specialties: {
    name: string;
    icon: string;
  }[];
  bio?: string;
  certifications?: string[];
  responseTime?: string;
}

interface BuilderProfileCardProps {
  profile: BuilderProfile;
  onBookCall?: () => void;
  onBookConsult?: () => void;
  onViewPortfolio?: () => void;
  onMessage?: () => void;
  featured?: boolean;
}

const specialtyIconMap: Record<string, string> = {
  'Solar': 'sun',
  'Electrical': 'zap',
  'Plumbing': 'droplet',
  'HVAC': 'thermometer',
  'Diesel Heaters': 'wind',
  'Insulation': 'layers',
  'Flooring': 'grid',
  'Cabinetry': 'box',
  'Windows': 'square',
  'Roof Raises': 'arrow-up',
  'Custom Builds': 'tool',
  'Conversions': 'refresh-cw',
  'Full Build': 'tool',
  'Woodwork': 'box',
  'Design': 'pen-tool',
  'Lithium': 'battery-charging',
  'Off-Grid': 'zap',
};

export const BuilderProfileCard: React.FC<BuilderProfileCardProps> = ({
  profile,
  onBookConsult,
  onViewPortfolio,
  onMessage,
  featured = false,
}) => {
  const renderStars = (rating: number) => (
    <View style={styles.starsContainer}>
      {[1, 2, 3, 4, 5].map((star) => (
        <Feather
          key={star}
          name={star <= rating ? 'star' : 'star'}
          size={13}
          color={star <= rating ? ACCENT_AMBER : 'rgba(0,0,0,0.15)'}
        />
      ))}
    </View>
  );

  return (
    <View style={[styles.container, featured ? styles.featuredContainer : null]}>
      {featured ? (
        <View style={styles.featuredBadge}>
          <Feather name="award" size={11} color="#FFF" />
          <Text style={styles.featuredText}>Featured</Text>
        </View>
      ) : null}

      {profile.coverImageUrl ? (
        <View style={styles.coverContainer}>
          <Image source={{ uri: profile.coverImageUrl }} style={styles.coverImage} contentFit="cover" />
          <View style={styles.coverOverlay} />
        </View>
      ) : null}

      <View style={styles.profileSection}>
        <View style={styles.avatarContainer}>
          <Image source={{ uri: profile.imageUrl }} style={styles.avatar} contentFit="cover" />
          {profile.verified ? (
            <View style={styles.verifiedBadge}>
              <Feather name="check" size={10} color="#FFF" />
            </View>
          ) : null}
        </View>
        <View style={styles.profileInfo}>
          <View style={styles.nameRow}>
            <Text style={styles.businessName}>{profile.businessName}</Text>
            {profile.verified ? (
              <View style={styles.verifiedTag}>
                <Feather name="shield" size={10} color={ACCENT_MOSS} />
                <Text style={styles.verifiedTagText}>Verified</Text>
              </View>
            ) : null}
          </View>
          <Text style={styles.ownerName}>by {profile.ownerName || profile.name}</Text>
          <View style={styles.locationRow}>
            <Feather name="map-pin" size={11} color={TEXT_SECONDARY} />
            <Text style={styles.location}>{profile.location}</Text>
          </View>
        </View>
      </View>

      <View style={styles.statsRow}>
        <View style={styles.statItem}>
          <View style={styles.ratingContainer}>
            {renderStars(profile.rating)}
            <Text style={styles.ratingText}>{profile.rating.toFixed(1)}</Text>
          </View>
          <Text style={styles.statLabel}>{profile.reviewCount} reviews</Text>
        </View>
        <View style={styles.statDivider} />
        {profile.yearsExperience ? (
          <>
            <View style={styles.statItem}>
              <Text style={styles.statValue}>{profile.yearsExperience}+</Text>
              <Text style={styles.statLabel}>Years</Text>
            </View>
            <View style={styles.statDivider} />
          </>
        ) : null}
        {profile.buildsCompleted ? (
          <View style={styles.statItem}>
            <Text style={styles.statValue}>{profile.buildsCompleted}</Text>
            <Text style={styles.statLabel}>Builds</Text>
          </View>
        ) : null}
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>EXPERTISE</Text>
        <View style={styles.expertiseGrid}>
          {profile.specialties.map((specialty, i) => (
            <View key={i} style={styles.expertiseChip}>
