import { useEffect, useCallback } from 'react';
import { Stack, useRouter, useSegments, useRootNavigationState } from 'expo-router';
import { StatusBar } from 'expo-status-bar';
import { View, ActivityIndicator, LogBox } from 'react-native';
import * as SplashScreen from 'expo-splash-screen';

LogBox.ignoreLogs([
  'Error configuring Purchases',
  'Invalid API key',
  'native store is not available',
]);
import { useFonts, RussoOne_400Regular } from '@expo-google-fonts/russo-one';
import { Inter_400Regular, Inter_500Medium, Inter_600SemiBold, Inter_700Bold } from '@expo-google-fonts/inter';
import {
  Outfit_400Regular,
  Outfit_500Medium,
  Outfit_600SemiBold,
  Outfit_700Bold,
  Outfit_800ExtraBold,
} from '@expo-google-fonts/outfit';
import { colors } from '@/constants/theme';
import { AuthProvider, useAuth } from '@/contexts/AuthContext';

SplashScreen.preventAutoHideAsync();

function AuthenticatedLayout() {
  const { user, isLoading } = useAuth();
  const segments = useSegments();
  const router = useRouter();
  const navigationState = useRootNavigationState();

  useEffect(() => {
    if (isLoading) return;
    if (!navigationState?.key) return;

    const inOnboarding = segments[0] === '(onboarding)';
    const inTabs = segments[0] === '(tabs)';
    const isIndex = !segments[0] || segments[0] === 'index';

    if (!user) {
      if (!inOnboarding) {
        router.replace('/(onboarding)/welcome' as any);
      }
    } else if (user.onboardingComplete) {
      if (!inTabs) {
        router.replace('/(tabs)/discovery' as any);
      }
    } else {
      if (!inOnboarding) {
        router.replace('/(onboarding)/welcome' as any);
      }
    }
  }, [user, isLoading, segments, navigationState?.key]);

  if (isLoading) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: colors.background.primary }}>
        <ActivityIndicator size="large" color={colors.ember[500]} />
      </View>
    );
  }

  const isAuthenticated = !!user;

  return (
    <Stack
      screenOptions={{
        headerShown: false,
        contentStyle: { backgroundColor: colors.background.primary },
        animation: 'slide_from_right',
      }}
    >
      <Stack.Screen name="index" />
      <Stack.Screen
        name="(onboarding)"
        options={{
          gestureEnabled: false,
        }}
      />
      {isAuthenticated ? (
        <Stack.Screen
          name="(tabs)"
          options={{
            gestureEnabled: false,
          }}
        />
      ) : null}
      {isAuthenticated ? (
        <Stack.Screen
          name="ai-assistant"
          options={{
            presentation: 'modal',
            animation: 'slide_from_bottom',
          }}
        />
      ) : null}
      {isAuthenticated ? (
        <Stack.Screen
          name="dm-chat"
          options={{
            animation: 'slide_from_right',
          }}
        />
      ) : null}
    </Stack>
  );
}

export default function RootLayout() {
  const [fontsLoaded] = useFonts({
    RussoOne_400Regular,
    Inter_400Regular,
    Inter_500Medium,
    Inter_600SemiBold,
    Inter_700Bold,
    Outfit_400Regular,
    Outfit_500Medium,
    Outfit_600SemiBold,
    Outfit_700Bold,
    Outfit_800ExtraBold,
  });

  const onLayoutRootView = useCallback(async () => {
    if (fontsLoaded) {
      await SplashScreen.hideAsync();
    }
  }, [fontsLoaded]);

  useEffect(() => {
    onLayoutRootView();
  }, [onLayoutRootView]);

  if (!fontsLoaded) {
    return null;
  }

  return (
    <AuthProvider>
      <View style={{ flex: 1 }} onLayout={onLayoutRootView}>
        <StatusBar style="light" />
        <AuthenticatedLayout />
      </View>
    </AuthProvider>
  );
}

