                style={[
                  sliderStyles.presetText,
                  value === preset && { color },
                ]}
              >
                {preset}
              </Text>
            </TouchableOpacity>
          ))}
        </View>
      </ScrollView>
    </View>
  );
};

interface ToggleRowProps {
