                  <View style={modalStyles.notificationLeft}>
                    <Ionicons name={item.icon as any} size={20} color={colors.forestGreen[600]} />
                    <Text style={modalStyles.notificationLabel}>{item.label}</Text>
                  </View>
                  <View style={[
                    modalStyles.toggle, 
                    notificationSettings[item.key as keyof typeof notificationSettings] && modalStyles.toggleActive
                  ]}>
                    <View style={[
                      modalStyles.toggleDot, 
                      notificationSettings[item.key as keyof typeof notificationSettings] && modalStyles.toggleDotActive
                    ]} />
                  </View>
                </TouchableOpacity>
              ))}
            </ScrollView>
          </View>
        </Modal>

        {/* Help & Support Modal */}
        <Modal
          visible={showHelpModal}
          animationType="slide"
          presentationStyle="pageSheet"
          onRequestClose={() => setShowHelpModal(false)}
        >
          <View style={[modalStyles.container, { paddingBottom: insets.bottom }]}>
            <View style={modalStyles.header}>
              <Text style={modalStyles.title}>Help & Support</Text>
              <TouchableOpacity onPress={() => setShowHelpModal(false)}>
                <Ionicons name="close" size={24} color={colors.bark[600]} />
              </TouchableOpacity>
            </View>
            <ScrollView style={modalStyles.content} contentContainerStyle={modalStyles.scrollContent}>
              {[
                { label: 'Getting Started', icon: 'rocket', description: 'Learn the basics' },
                { label: 'FAQs', icon: 'help-circle', description: 'Common questions' },
                { label: 'Contact Support', icon: 'mail', description: 'Get in touch' },
                { label: 'Report a Bug', icon: 'bug', description: 'Help us improve' },
                { label: 'Community Guidelines', icon: 'document-text', description: 'Our rules' },
              ].map((item, idx) => (
                <TouchableOpacity key={idx} style={modalStyles.helpItem}>
                  <View style={modalStyles.helpIconContainer}>
                    <Ionicons name={item.icon as any} size={22} color={colors.forestGreen[600]} />
                  </View>
                  <View style={modalStyles.helpContent}>
                    <Text style={modalStyles.helpLabel}>{item.label}</Text>
                    <Text style={modalStyles.helpDescription}>{item.description}</Text>
                  </View>
                  <Ionicons name="chevron-forward" size={18} color={colors.bark[400]} />
                </TouchableOpacity>
              ))}
            </ScrollView>
          </View>
        </Modal>

        {/* Sign Out Confirmation Modal */}
        <Modal
          visible={isSignedOut}
          animationType="fade"
          transparent={true}
          onRequestClose={() => setIsSignedOut(false)}
        >
          <View style={modalStyles.signOutOverlay}>
            <View style={modalStyles.signOutCard}>
              <Ionicons name="log-out" size={48} color={colors.sunsetOrange[500]} />
              <Text style={modalStyles.signOutTitle}>Sign Out?</Text>
              <Text style={modalStyles.signOutDescription}>
                You will need to sign in again to access your Nomad Passport.
              </Text>
              <View style={modalStyles.signOutButtons}>
                <TouchableOpacity
                  style={modalStyles.signOutCancel}
                  onPress={() => setIsSignedOut(false)}
                >
                  <Text style={modalStyles.signOutCancelText}>Cancel</Text>
                </TouchableOpacity>
                <TouchableOpacity
                  style={modalStyles.signOutConfirm}
                  onPress={async () => {
                    setIsSigningOut(true);
                    setIsSignedOut(false);

                    try { logoutRevenueCat().catch(() => {}); } catch (e) {}
                    try { await AsyncStorage.removeItem('@wildergo_auth'); } catch (e) {}
                    if (Platform.OS === 'web' && typeof window !== 'undefined') {
                      try { window.localStorage.clear(); } catch (e) {}
                    }

                    await logout();
                    setIsSigningOut(false);
                    setShowSignOutConfirm(false);
                  }}
                  disabled={isSigningOut}
                  testID="button-confirm-sign-out"
                >
                  <Text style={modalStyles.signOutConfirmText}>
                    {isSigningOut ? 'Signing Out...' : 'Sign Out'}
                  </Text>
                </TouchableOpacity>
              </View>
            </View>
          </View>
        </Modal>

        {/* Paywall Modal */}
        <Modal
          visible={showPaywallModal}
          animationType="slide"
          presentationStyle="fullScreen"
          onRequestClose={() => setShowPaywallModal(false)}
        >
          <View style={{ flex: 1 }}>
            <TouchableOpacity
              style={styles.paywallCloseButton}
              onPress={() => setShowPaywallModal(false)}
            >
              <Ionicons name="close" size={28} color={colors.text.inverse} />
            </TouchableOpacity>
            <PaywallScreen 
              onComplete={() => {
                setPremium(true);
                setShowPaywallModal(false);
              }} 
              showSkip={false}
            />
          </View>
        </Modal>

        {/* Subscription Management Modal */}
        <Modal
          visible={showSubscriptionModal}
          animationType="slide"
          presentationStyle="pageSheet"
          onRequestClose={() => setShowSubscriptionModal(false)}
        >
          <View style={[modalStyles.container, { paddingBottom: insets.bottom }]}>
            <View style={modalStyles.header}>
              <Text style={modalStyles.title}>Manage Subscription</Text>
              <TouchableOpacity onPress={() => setShowSubscriptionModal(false)}>
                <Ionicons name="close" size={24} color={colors.bark[600]} />
              </TouchableOpacity>
            </View>
            <ScrollView style={modalStyles.content} contentContainerStyle={modalStyles.scrollContent}>
              {/* Current Plan */}
              <View style={styles.subscriptionPlanCard}>
                <LinearGradient
                  colors={[colors.ember[500], colors.sunsetOrange[500]]}
                  start={{ x: 0, y: 0 }}
                  end={{ x: 1, y: 1 }}
                  style={styles.subscriptionPlanGradient}
                >
                  <View style={styles.subscriptionPlanHeader}>
                    <Ionicons name="diamond" size={28} color="#FFFFFF" />
                    <View style={styles.subscriptionPlanInfo}>
                      <Text style={styles.subscriptionPlanTitle}>WilderGo Premium</Text>
                      <Text style={styles.subscriptionPlanPrice}>$4.99/month</Text>
                    </View>
                    <View style={styles.subscriptionActiveBadge}>
                      <Text style={styles.subscriptionActiveText}>Active</Text>
                    </View>
                  </View>
                </LinearGradient>
              </View>

              <Text style={styles.subscriptionSectionTitle}>Your Premium Benefits</Text>

              {[
                { icon: 'map', label: 'Unlimited Route Planning', description: 'Plan as many routes as you need' },
                { icon: 'calendar', label: 'Event Access', description: 'RSVP to exclusive community events' },
                { icon: 'warning', label: 'Priority Emergency Response', description: 'Get help faster when you need it' },
                { icon: 'people', label: 'Builder Consultations', description: 'Connect with rig building experts' },
                { icon: 'analytics', label: 'Advanced Analytics', description: 'Track your journey in detail' },
              ].map((benefit, idx) => (
                <View key={idx} style={styles.subscriptionBenefitItem}>
                  <View style={styles.subscriptionBenefitIcon}>
                    <Ionicons name={benefit.icon as any} size={20} color={colors.forestGreen[600]} />
                  </View>
                  <View style={styles.subscriptionBenefitText}>
                    <Text style={styles.subscriptionBenefitLabel}>{benefit.label}</Text>
                    <Text style={styles.subscriptionBenefitDescription}>{benefit.description}</Text>
                  </View>
                  <Ionicons name="checkmark-circle" size={20} color={colors.moss[500]} />
                </View>
              ))}

              <View style={styles.subscriptionDivider} />

              {/* Cancel Subscription */}
              <TouchableOpacity 
                style={styles.cancelSubscriptionButton}
                onPress={() => {
                  setPremium(false);
                  setShowSubscriptionModal(false);
                }}
