});

client/services/ai/buildDiagnosticServic.content:
/**
 * WilderGo Build Diagnostic Service
 * AI-powered rig diagnostic and troubleshooting:
 * - Analyze rig issues based on symptoms
 * - Provide repair recommendations
 * - Suggest nearby resources
 * - Image-based damage assessment
 * 
 * Note: AI text generation is disabled in this environment.
 * Using intelligent fallback logic instead.
 */

// Stub functions that throw to trigger fallback logic
async function generateText(_options: { prompt: string }): Promise<string> {
  throw new Error('AI generation not available - using fallback');
}

async function analyzeImage(_options: { imageUrl: string; prompt: string }): Promise<string> {
  throw new Error('AI image analysis not available - using fallback');
}

import { RigSpecifications } from '@/services/passport/nomadPassportService';

export type IssueSeverity = 'minor' | 'moderate' | 'urgent' | 'critical';
export type IssueCategory =
  | 'electrical'
  | 'plumbing'
  | 'mechanical'
  | 'solar'
  | 'climate'
  | 'structural'
  | 'connectivity'
  | 'other';

export interface DiagnosticInput {
  symptoms: string;
  category?: IssueCategory;
  rigSpecs?: Partial<RigSpecifications>;
  additionalContext?: string;
}

export interface DiagnosticResult {
  diagnosis: string;
  severity: IssueSeverity;
  possibleCauses: string[];
  immediateSteps: string[];
  toolsNeeded: string[];
  estimatedDifficulty: 'DIY easy' | 'DIY moderate' | 'DIY advanced' | 'Professional needed';
  estimatedCost: string;
  safetyWarnings: string[];
  canContinueDriving: boolean;
  relatedSystems: string[];
}

export interface ImageDiagnosticResult {
  assessment: string;
  identifiedIssues: string[];
  severity: IssueSeverity;
  recommendations: string[];
  urgentAction: boolean;
}

/**
 * Generate AI-powered diagnostic based on symptom description
 */
export async function diagnoseBuildIssue(
  input: DiagnosticInput
): Promise<DiagnosticResult> {
  const { symptoms, category, rigSpecs, additionalContext } = input;

  // Build context about the rig
  let rigContext = '';
  if (rigSpecs) {
    rigContext = `
Rig Details:
- Type: ${rigSpecs.rigType || 'Unknown'}
- Solar: ${rigSpecs.solarWattage ? `${rigSpecs.solarWattage}W` : 'Unknown'}
- Battery: ${rigSpecs.batteryCapacity ? `${rigSpecs.batteryCapacity}Ah ${rigSpecs.batteryType || ''}` : 'Unknown'}
- Water: Fresh ${rigSpecs.freshWaterCapacity || '?'}gal, Grey ${rigSpecs.greyWaterCapacity || '?'}gal
- AC: ${rigSpecs.hasAC ? `Yes (${rigSpecs.acType || 'type unknown'})` : 'No'}
- Heater: ${rigSpecs.hasHeater ? `Yes (${rigSpecs.heaterType || 'type unknown'})` : 'No'}
- Generator: ${rigSpecs.hasGenerator ? 'Yes' : 'No'}
- Starlink: ${rigSpecs.starlinkActive ? 'Active' : 'No'}`;
  }

  const prompt = `You are an expert van/RV mechanic and off-grid systems specialist helping diagnose rig issues for nomads. Analyze the following problem and provide a detailed diagnosis.

SYMPTOMS REPORTED:
${symptoms}

${category ? `ISSUE CATEGORY: ${category}` : ''}
${rigContext}
${additionalContext ? `ADDITIONAL CONTEXT: ${additionalContext}` : ''}

Respond in JSON format with these fields:
{
  "diagnosis": "Clear explanation of what's likely wrong (2-3 sentences)",
  "severity": "minor|moderate|urgent|critical",
  "possibleCauses": ["List 2-4 possible causes, most likely first"],
  "immediateSteps": ["4-6 step-by-step troubleshooting instructions"],
  "toolsNeeded": ["List specific tools needed"],
  "estimatedDifficulty": "DIY easy|DIY moderate|DIY advanced|Professional needed",
  "estimatedCost": "Cost range for parts/repair",
  "safetyWarnings": ["Any safety concerns to be aware of"],
  "canContinueDriving": true or false,
  "relatedSystems": ["Other systems that might be affected"]
}

Be practical and specific. Assume the person is remote and may have limited access to parts. Prioritize safety.`;

  try {
    const response = await generateText({ prompt });

    // Parse JSON response
    const jsonMatch = response.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      return {
        diagnosis: parsed.diagnosis || 'Unable to determine specific issue.',
        severity: validateSeverity(parsed.severity),
        possibleCauses: parsed.possibleCauses || ['Unknown cause'],
        immediateSteps: parsed.immediateSteps || ['Consult a professional'],
        toolsNeeded: parsed.toolsNeeded || [],
        estimatedDifficulty: validateDifficulty(parsed.estimatedDifficulty),
        estimatedCost: parsed.estimatedCost || 'Varies',
        safetyWarnings: parsed.safetyWarnings || [],
        canContinueDriving: parsed.canContinueDriving ?? true,
        relatedSystems: parsed.relatedSystems || [],
      };
    }

    // Fallback
    return getDefaultDiagnostic(symptoms);
  } catch (error) {
    console.error('AI Diagnostic failed:', error);
    return getDefaultDiagnostic(symptoms);
  }
}

/**
 * Analyze an image of rig damage/issue
 */
export async function analyzeRigImage(
  imageUri: string,
  context?: string
): Promise<ImageDiagnosticResult> {
  const prompt = `You are an expert van/RV mechanic. Analyze this image of a rig issue and provide a diagnostic assessment.

${context ? `Context provided: ${context}` : ''}

Please identify:
1. What the image shows (component, system, etc.)
2. Any visible damage, wear, or issues
3. Severity of the issue
4. Recommended actions

Respond in JSON format:
{
  "assessment": "Brief description of what you see",
  "identifiedIssues": ["List specific issues visible"],
  "severity": "minor|moderate|urgent|critical",
  "recommendations": ["2-4 recommended actions"],
  "urgentAction": true or false (needs immediate attention)
}`;

  try {
    const response = await analyzeImage({
      imageUrl: imageUri,
      prompt,
    });

    // Parse JSON response
    const jsonMatch = response.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      return {
        assessment: parsed.assessment || 'Unable to assess image.',
        identifiedIssues: parsed.identifiedIssues || [],
        severity: validateSeverity(parsed.severity),
        recommendations: parsed.recommendations || ['Take to a professional for inspection'],
        urgentAction: parsed.urgentAction ?? false,
      };
    }

    return {
      assessment: response.slice(0, 200) || 'Image analyzed. Please consult a professional.',
      identifiedIssues: [],
      severity: 'moderate',
      recommendations: ['Consult a professional for a detailed assessment'],
      urgentAction: false,
    };
  } catch (error) {
    console.error('Image analysis failed:', error);
    return {
      assessment: 'Unable to analyze image. Please try again or describe the issue in text.',
      identifiedIssues: [],
      severity: 'moderate',
      recommendations: ['Try uploading a clearer image', 'Describe the issue in detail'],
      urgentAction: false,
    };
  }
}

/**
 * Get quick troubleshooting tips for common issues
 */
export async function getQuickTips(
  category: IssueCategory
): Promise<string[]> {
  const categoryTips: Record<IssueCategory, string[]> = {
    electrical: [
      'Check all fuse boxes - both vehicle and house batteries',
      'Verify battery terminals are clean and tight',
      'Test ground connections',
      'Use a multimeter to check voltage at various points',
    ],
    plumbing: [
      'Check for visible leaks under all connections',
      'Verify water pump is primed and receiving power',
      'Inspect tank vent lines for blockages',
      'Test accumulator tank pressure if applicable',
    ],
    mechanical: [
      'Check fluid levels (oil, coolant, transmission, brake)',
      'Inspect belts for wear or damage',
      'Listen for unusual sounds when engine is running',
      'Check for warning lights on dashboard',
    ],
    solar: [
      'Clean panels of dust and debris',
      'Check all wiring connections at panels and charge controller',
      'Verify charge controller settings match battery type',
      'Monitor production during peak sun hours',
    ],
    climate: [
      'Clean or replace air filters',
      'Check refrigerant levels (AC) or propane supply (heater)',
      'Verify thermostat is functioning',
      'Inspect ducting for blockages or leaks',
    ],
    structural: [
      'Inspect seals around windows and doors',
      'Check roof for soft spots or damage',
      'Look for water stains indicating leaks',
      'Verify all mounting hardware is secure',
    ],
    connectivity: [
      'Restart all devices (router, Starlink, phone)',
      'Check antenna positioning and obstructions',
      'Verify cell signal strength in the area',
      'Check for software/firmware updates',
    ],
    other: [
      'Document the issue with photos and notes',
      'Check online forums for similar issues',
      'Consult your rig manual for guidance',
      'Reach out to the community for advice',
    ],
  };

  return categoryTips[category] || categoryTips.other;
}

// Validation helpers
function validateSeverity(severity: string): IssueSeverity {
  const validSeverities: IssueSeverity[] = ['minor', 'moderate', 'urgent', 'critical'];
  return validSeverities.includes(severity as IssueSeverity)
    ? (severity as IssueSeverity)
    : 'moderate';
}

function validateDifficulty(difficulty: string): DiagnosticResult['estimatedDifficulty'] {
  const validDifficulties: DiagnosticResult['estimatedDifficulty'][] = [
    'DIY easy',
    'DIY moderate',
    'DIY advanced',
    'Professional needed',
  ];
  return validDifficulties.includes(difficulty as DiagnosticResult['estimatedDifficulty'])
    ? (difficulty as DiagnosticResult['estimatedDifficulty'])
    : 'DIY moderate';
}

function getDefaultDiagnostic(symptoms: string): DiagnosticResult {
  return {
    diagnosis: `Based on the symptoms described (${symptoms.slice(0, 50)}...), we recommend a thorough inspection. The AI diagnostic was unable to complete analysis.`,
    severity: 'moderate',
    possibleCauses: ['Multiple possible causes - further inspection needed'],
    immediateSteps: [
      'Document the issue with photos and notes',
      'Check for any obvious damage or loose connections',
      'Consult your rig manual for related troubleshooting',
      'Reach out to the WilderGo builder community for advice',
    ],
    toolsNeeded: ['Flashlight', 'Basic tool kit', 'Multimeter (if electrical)'],
    estimatedDifficulty: 'DIY moderate',
    estimatedCost: 'Varies based on actual issue',
    safetyWarnings: ['If unsure, consult a professional'],
    canContinueDriving: true,
    relatedSystems: [],
  };
}

export const buildDiagnosticService = {
  diagnoseBuildIssue,
  analyzeRigImage,
  getQuickTips,
};

export default buildDiagnosticService;

client/components/convoy/SharedItinerary.content:
/**
 * WilderGo Shared Itinerary Component
 * Convoy members can pin suggested stops (fuel, water, campsites)
 * Features glassmorphism design with drag-to-reorder
 */

import React, { useState, useRef } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
  Modal,
  TextInput,
  Animated,
  Platform,
} from 'react-native';
import { BlurView } from 'expo-blur';
import { Ionicons } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { colors, typography, spacing, borderRadius, shadows, blur } from '@/constants/theme';
import { GlassCard } from '@/components/ui/GlassCard';

export type StopType = 'fuel' | 'water' | 'campsite' | 'food' | 'scenic' | 'repair' | 'other';

export interface ItineraryStop {
  id: string;
  type: StopType;
  name: string;
  description?: string;
  latitude: number;
  longitude: number;
  suggestedBy: {
    id: string;
    name: string;
    avatar?: string;
  };
  votes: number;
  userVoted: boolean;
  estimatedTime?: string;
  notes?: string;
  addedAt: string;
  isPinned: boolean;
}

const stopTypeConfig: Record<StopType, { icon: keyof typeof Ionicons.glyphMap; color: string; label: string }> = {
  fuel: { icon: 'flash', color: colors.sunsetOrange[500], label: 'Fuel' },
  water: { icon: 'water', color: colors.deepTeal[500], label: 'Water' },
  campsite: { icon: 'bonfire', color: colors.forestGreen[600], label: 'Campsite' },
  food: { icon: 'restaurant', color: colors.burntSienna[500], label: 'Food' },
  scenic: { icon: 'camera', color: colors.desertSand[700], label: 'Scenic' },
  repair: { icon: 'construct', color: colors.deepTeal[600], label: 'Repair' },
  other: { icon: 'location', color: colors.bark[500], label: 'Other' },
};

interface SharedItineraryProps {
  stops: ItineraryStop[];
  currentUserId: string;
  onAddStop: (stop: Omit<ItineraryStop, 'id' | 'votes' | 'userVoted' | 'addedAt'>) => void;
  onVoteStop: (stopId: string) => void;
  onPinStop: (stopId: string) => void;
  onRemoveStop: (stopId: string) => void;
  onViewOnMap: (latitude: number, longitude: number) => void;
}

export const SharedItinerary: React.FC<SharedItineraryProps> = ({
  stops,
  currentUserId,
  onAddStop,
  onVoteStop,
  onPinStop,
  onRemoveStop,
  onViewOnMap,
}) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [expanded, setExpanded] = useState(false);
  const expandAnim = useRef(new Animated.Value(0)).current;

  const pinnedStops = stops.filter(s => s.isPinned);
  const suggestedStops = stops.filter(s => !s.isPinned).sort((a, b) => b.votes - a.votes);

  const toggleExpand = () => {
    Animated.spring(expandAnim, {
      toValue: expanded ? 0 : 1,
      useNativeDriver: false,
      tension: 100,
      friction: 10,
    }).start();
    setExpanded(!expanded);
  };

  const maxHeight = expandAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [180, 500],
  });

  return (
    <View style={styles.container}>
      {/* Header */}
      <TouchableOpacity onPress={toggleExpand} activeOpacity={0.8}>
        <GlassCard variant="frost" padding="md" style={styles.headerCard}>
          <View style={styles.headerContent}>
            <View style={styles.headerLeft}>
              <View style={styles.iconContainer}>
                <Ionicons name="map" size={20} color={colors.forestGreen[600]} />
              </View>
              <View>
                <Text style={styles.headerTitle}>Shared Itinerary</Text>
                <Text style={styles.headerSubtitle}>
                  {pinnedStops.length} stops • {suggestedStops.length} suggested
                </Text>
              </View>
            </View>
            <View style={styles.headerRight}>
              <TouchableOpacity
                style={styles.addButton}
                onPress={() => setShowAddModal(true)}
              >
                <Ionicons name="add" size={20} color={colors.text.inverse} />
              </TouchableOpacity>
              <Animated.View style={{
                transform: [{
                  rotate: expandAnim.interpolate({
                    inputRange: [0, 1],
                    outputRange: ['0deg', '180deg'],
                  }),
                }],
              }}>
                <Ionicons name="chevron-down" size={20} color={colors.bark[500]} />
              </Animated.View>
            </View>
          </View>
        </GlassCard>
      </TouchableOpacity>

      {/* Expandable Content */}
      <Animated.View style={[styles.expandableContent, { maxHeight }]}>
        <ScrollView
          showsVerticalScrollIndicator={false}
          contentContainerStyle={styles.stopsScrollContent}
          nestedScrollEnabled
        >
          {/* Pinned Stops */}
          {pinnedStops.length > 0 && (
            <View style={styles.section}>
              <View style={styles.sectionHeader}>
                <Ionicons name="pin" size={14} color={colors.sunsetOrange[500]} />
                <Text style={styles.sectionTitle}>Confirmed Stops</Text>
              </View>
              {pinnedStops.map((stop, index) => (
                <StopCard
                  key={stop.id}
                  stop={stop}
                  index={index + 1}
                  currentUserId={currentUserId}
                  onVote={() => onVoteStop(stop.id)}
                  onPin={() => onPinStop(stop.id)}
                  onRemove={() => onRemoveStop(stop.id)}
                  onViewOnMap={() => onViewOnMap(stop.latitude, stop.longitude)}
                />
              ))}
            </View>
          )}

          {/* Suggested Stops */}
          {suggestedStops.length > 0 && (
            <View style={styles.section}>
              <View style={styles.sectionHeader}>
                <Ionicons name="bulb" size={14} color={colors.desertSand[700]} />
                <Text style={styles.sectionTitle}>Suggested</Text>
              </View>
              {suggestedStops.map((stop) => (
                <StopCard
                  key={stop.id}
                  stop={stop}
                  currentUserId={currentUserId}
                  onVote={() => onVoteStop(stop.id)}
                  onPin={() => onPinStop(stop.id)}
                  onRemove={() => onRemoveStop(stop.id)}
                  onViewOnMap={() => onViewOnMap(stop.latitude, stop.longitude)}
                />
              ))}
            </View>
          )}

          {stops.length === 0 && (
            <View style={styles.emptyState}>
              <Ionicons name="compass-outline" size={48} color={colors.bark[300]} />
              <Text style={styles.emptyText}>No stops added yet</Text>
              <Text style={styles.emptySubtext}>
                Add fuel stations, water fills, or campsites for the convoy
              </Text>
            </View>
          )}
        </ScrollView>
      </Animated.View>

      {/* Add Stop Modal */}
      <AddStopModal
        visible={showAddModal}
        onClose={() => setShowAddModal(false)}
        onAdd={(stop) => {
          onAddStop({
            ...stop,
            suggestedBy: { id: currentUserId, name: 'You' },
            isPinned: false,
          });
          setShowAddModal(false);
        }}
      />
    </View>
  );
};

// Individual Stop Card
interface StopCardProps {
  stop: ItineraryStop;
  index?: number;
  currentUserId: string;
  onVote: () => void;
  onPin: () => void;
  onRemove: () => void;
  onViewOnMap: () => void;
}

const StopCard: React.FC<StopCardProps> = ({
  stop,
  index,
  currentUserId,
  onVote,
  onPin,
  onRemove,
  onViewOnMap,
}) => {
  const config = stopTypeConfig[stop.type];
  const isOwner = stop.suggestedBy.id === currentUserId;

  return (
    <GlassCard variant="light" padding="sm" style={styles.stopCard}>
      <View style={styles.stopContent}>
        {/* Index badge for pinned stops */}
        {index && (
          <View style={[styles.indexBadge, { backgroundColor: config.color }]}>
            <Text style={styles.indexText}>{index}</Text>
          </View>
        )}

        {/* Type Icon */}
        <View style={[styles.typeIcon, { backgroundColor: config.color + '20' }]}>
          <Ionicons name={config.icon} size={18} color={config.color} />
        </View>

        {/* Stop Info */}
        <View style={styles.stopInfo}>
          <View style={styles.stopHeader}>
            <Text style={styles.stopName} numberOfLines={1}>{stop.name}</Text>
            <View style={[styles.typeBadge, { backgroundColor: config.color + '15' }]}>
              <Text style={[styles.typeLabel, { color: config.color }]}>{config.label}</Text>
            </View>
          </View>
          {stop.description && (
            <Text style={styles.stopDescription} numberOfLines={1}>
              {stop.description}
            </Text>
          )}
          <View style={styles.stopMeta}>
            <Text style={styles.suggestedBy}>
              by {stop.suggestedBy.name}
            </Text>
            {stop.estimatedTime && (
              <>
                <View style={styles.metaDot} />
                <Text style={styles.estimatedTime}>{stop.estimatedTime}</Text>
              </>
            )}
          </View>
        </View>

        {/* Actions */}
        <View style={styles.stopActions}>
          {/* Vote Button */}
          <TouchableOpacity
            style={[styles.voteButton, stop.userVoted && styles.voteButtonActive]}
            onPress={onVote}
          >
            <Ionicons
              name={stop.userVoted ? 'arrow-up' : 'arrow-up-outline'}
              size={14}
              color={stop.userVoted ? colors.text.inverse : colors.forestGreen[600]}
            />
            <Text style={[styles.voteCount, stop.userVoted && styles.voteCountActive]}>
              {stop.votes}
            </Text>
          </TouchableOpacity>

          {/* Map Button */}
          <TouchableOpacity style={styles.mapButton} onPress={onViewOnMap}>
            <Ionicons name="navigate" size={14} color={colors.deepTeal[500]} />
          </TouchableOpacity>

          {/* Pin/Remove Buttons (for owner or convoy leaders) */}
          {!stop.isPinned && (
            <TouchableOpacity style={styles.pinButton} onPress={onPin}>
              <Ionicons name="pin-outline" size={14} color={colors.sunsetOrange[500]} />
            </TouchableOpacity>
          )}
        </View>
      </View>
    </GlassCard>
  );
};

// Add Stop Modal
interface AddStopModalProps {
  visible: boolean;
  onClose: () => void;
  onAdd: (stop: Omit<ItineraryStop, 'id' | 'votes' | 'userVoted' | 'addedAt' | 'suggestedBy' | 'isPinned'>) => void;
}

const AddStopModal: React.FC<AddStopModalProps> = ({ visible, onClose, onAdd }) => {
  const insets = useSafeAreaInsets();
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [selectedType, setSelectedType] = useState<StopType>('campsite');
  const [notes, setNotes] = useState('');

  const handleAdd = () => {
    if (!name.trim()) return;

    onAdd({
      type: selectedType,
      name: name.trim(),
      description: description.trim() || undefined,
      latitude: 38.5733, // Would be from location picker
      longitude: -109.5498,
      notes: notes.trim() || undefined,
    });

    // Reset form
    setName('');
    setDescription('');
    setSelectedType('campsite');
    setNotes('');
  };

  return (
    <Modal
      visible={visible}
      animationType="slide"
      presentationStyle="pageSheet"
      onRequestClose={onClose}
    >
      <View style={[modalStyles.container, { paddingBottom: insets.bottom }]}>
        {/* Header */}
        <View style={modalStyles.header}>
          <TouchableOpacity onPress={onClose}>
            <Text style={modalStyles.cancelText}>Cancel</Text>
          </TouchableOpacity>
          <Text style={modalStyles.title}>Add Stop</Text>
          <TouchableOpacity onPress={handleAdd} disabled={!name.trim()}>
            <Text style={[modalStyles.addText, !name.trim() && modalStyles.addTextDisabled]}>
              Add
            </Text>
          </TouchableOpacity>
        </View>

        <ScrollView
          style={modalStyles.content}
          contentContainerStyle={modalStyles.scrollContent}
          showsVerticalScrollIndicator={false}
        >
          {/* Stop Type Selector */}
          <Text style={modalStyles.sectionLabel}>Type</Text>
          <View style={modalStyles.typeGrid}>
            {(Object.keys(stopTypeConfig) as StopType[]).map((type) => {
              const config = stopTypeConfig[type];
              const isSelected = selectedType === type;
              return (
                <TouchableOpacity
                  key={type}
                  style={[
                    modalStyles.typeButton,
                    isSelected && { backgroundColor: config.color + '20', borderColor: config.color },
                  ]}
                  onPress={() => setSelectedType(type)}
                >
                  <Ionicons
                    name={config.icon}
                    size={20}
                    color={isSelected ? config.color : colors.bark[400]}
                  />
                  <Text style={[
                    modalStyles.typeButtonText,
                    isSelected && { color: config.color },
                  ]}>
                    {config.label}
                  </Text>
                </TouchableOpacity>
              );
            })}
          </View>

          {/* Name Input */}
          <Text style={modalStyles.sectionLabel}>Name</Text>
          <TextInput
            style={modalStyles.input}
            placeholder="e.g., Shell Gas Station, Hidden Spring..."
            placeholderTextColor={'rgba(0, 0, 0, 0.4)'}
            value={name}
            onChangeText={setName}
          />

          {/* Description Input */}
          <Text style={modalStyles.sectionLabel}>Description (optional)</Text>
          <TextInput
            style={modalStyles.input}
            placeholder="Brief description..."
            placeholderTextColor={'rgba(0, 0, 0, 0.4)'}
            value={description}
            onChangeText={setDescription}
          />

          {/* Location Picker Placeholder */}
          <Text style={modalStyles.sectionLabel}>Location</Text>
          <TouchableOpacity style={modalStyles.locationPicker}>
            <Ionicons name="location" size={20} color={colors.forestGreen[600]} />
            <Text style={modalStyles.locationText}>Tap to select on map</Text>
            <Ionicons name="chevron-forward" size={16} color={colors.bark[400]} />
          </TouchableOpacity>

          {/* Notes Input */}
          <Text style={modalStyles.sectionLabel}>Notes for convoy (optional)</Text>
          <TextInput
            style={[modalStyles.input, modalStyles.notesInput]}
            placeholder="Any tips or important info..."
            placeholderTextColor={'rgba(0, 0, 0, 0.4)'}
            value={notes}
            onChangeText={setNotes}
            multiline
            numberOfLines={3}
          />
        </ScrollView>
      </View>
    </Modal>
  );
};

// Compact Itinerary Bar (for showing in chat)
interface ItineraryBarProps {
  nextStop?: ItineraryStop;
  totalStops: number;
  onPress: () => void;
}

export const ItineraryBar: React.FC<ItineraryBarProps> = ({ nextStop, totalStops, onPress }) => {
  if (!nextStop) return null;

  const config = stopTypeConfig[nextStop.type];

  return (
    <TouchableOpacity onPress={onPress} activeOpacity={0.8}>
      <GlassCard variant="frost" padding="sm" style={itineraryBarStyles.container}>
        <View style={itineraryBarStyles.content}>
          <View style={[itineraryBarStyles.icon, { backgroundColor: config.color + '20' }]}>
            <Ionicons name={config.icon} size={16} color={config.color} />
          </View>
          <View style={itineraryBarStyles.info}>
            <Text style={itineraryBarStyles.label}>Next Stop</Text>
            <Text style={itineraryBarStyles.name} numberOfLines={1}>{nextStop.name}</Text>
          </View>
          <View style={itineraryBarStyles.badge}>
            <Text style={itineraryBarStyles.badgeText}>{totalStops} stops</Text>
          </View>
          <Ionicons name="chevron-forward" size={16} color={colors.bark[400]} />
        </View>
      </GlassCard>
    </TouchableOpacity>
  );
};

