client/components/passport/MaintenanceTr.content:
/**
 * WilderGo Rig Maintenance Tracker
 * Log and track technical upkeep:
 * - Oil changes, tire rotations
 * - Battery health
 * - Solar panel maintenance
 * - Upcoming maintenance alerts
 */

import React, { useState, useMemo, useRef, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  ScrollView,
  TouchableOpacity,
  Animated,
  Platform,
  TextInput,
  Modal,
  KeyboardAvoidingView,
} from 'react-native';
import { BlurView } from 'expo-blur';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import {
  colors,
  borderRadius,
  spacing,
  typography,
  shadows,
  blur,
  maintenanceCategories,
} from '@/constants/theme';
import {
  MaintenanceRecord,
  getMaintenanceRecords,
  getUpcomingMaintenance,
  addMaintenanceRecord,
  getMaintenanceStats,
} from '@/services/passport/nomadPassportService';

interface MaintenanceTrackerProps {
  rigId: string;
  currentMileage?: number;
}

// Stats card
const MaintenanceStatsCard: React.FC<{ rigId: string }> = ({ rigId }) => {
  const stats = useMemo(() => getMaintenanceStats(rigId), [rigId]);
  const lastService = stats.lastServiceDate
    ? new Date(stats.lastServiceDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
    : 'N/A';

  const ContainerWrapper = Platform.OS === 'ios' ? BlurView : View;
  const containerProps = Platform.OS === 'ios'
    ? { tint: 'light' as const, intensity: blur.medium, style: styles.statsCard }
    : { style: [styles.statsCard, styles.statsCardFallback] };

  return (
    <ContainerWrapper {...containerProps}>
      <Text style={styles.statsTitle}>Maintenance Overview</Text>

      <View style={styles.statsGrid}>
        <View style={styles.statItem}>
          <Text style={styles.statValue}>{stats.totalRecords}</Text>
          <Text style={styles.statLabel}>Records</Text>
        </View>
        <View style={styles.statDivider} />
        <View style={styles.statItem}>
          <Text style={[styles.statValue, stats.upcomingCount > 0 && styles.statValueWarning]}>
            {stats.upcomingCount}
          </Text>
          <Text style={styles.statLabel}>Due Soon</Text>
        </View>
        <View style={styles.statDivider} />
        <View style={styles.statItem}>
          <Text style={styles.statValue}>${stats.totalSpent}</Text>
          <Text style={styles.statLabel}>Total Spent</Text>
        </View>
        <View style={styles.statDivider} />
        <View style={styles.statItem}>
          <Text style={styles.statValue}>{lastService}</Text>
          <Text style={styles.statLabel}>Last Service</Text>
        </View>
      </View>
    </ContainerWrapper>
  );
};

// Upcoming maintenance alerts
interface UpcomingAlertsProps {
  rigId: string;
  currentMileage: number;
}

const UpcomingAlerts: React.FC<UpcomingAlertsProps> = ({ rigId, currentMileage }) => {
  const upcoming = useMemo(
    () => getUpcomingMaintenance(rigId, currentMileage),
    [rigId, currentMileage]
  );

  if (upcoming.length === 0) return null;

  return (
    <View style={styles.alertsContainer}>
      <View style={styles.alertsHeader}>
        <Ionicons name="warning" size={20} color={colors.sunsetOrange[500]} />
        <Text style={styles.alertsTitle}>Due Soon</Text>
      </View>
      {upcoming.map((record) => {
        const category = maintenanceCategories.find(c => c.id === record.categoryId);
        return (
          <View key={record.id} style={styles.alertItem}>
            <Ionicons
              name={(category?.icon || 'construct') as keyof typeof Ionicons.glyphMap}
              size={16}
              color={colors.sunsetOrange[500]}
            />
            <View style={styles.alertContent}>
              <Text style={styles.alertText}>{record.categoryLabel}</Text>
              {record.nextDueMileage && (
                <Text style={styles.alertMeta}>
                  Due at {record.nextDueMileage.toLocaleString()} mi
                  {currentMileage >= record.nextDueMileage && ' (Overdue!)'}
                </Text>
              )}
              {record.nextDue && (
                <Text style={styles.alertMeta}>
                  Due {new Date(record.nextDue).toLocaleDateString()}
                </Text>
              )}
            </View>
          </View>
        );
      })}
    </View>
  );
};

// Maintenance category filter
interface CategoryFilterProps {
  selectedCategory: string | null;
  onSelectCategory: (category: string | null) => void;
}

const CategoryFilter: React.FC<CategoryFilterProps> = ({ selectedCategory, onSelectCategory }) => {
  return (
    <ScrollView
      horizontal
      showsHorizontalScrollIndicator={false}
      contentContainerStyle={styles.filterContainer}
    >
      <TouchableOpacity
        style={[styles.filterChip, !selectedCategory && styles.filterChipActive]}
        onPress={() => onSelectCategory(null)}
      >
        <Text style={[styles.filterChipText, !selectedCategory && styles.filterChipTextActive]}>
          All
        </Text>
      </TouchableOpacity>

      {maintenanceCategories.map((category) => (
        <TouchableOpacity
          key={category.id}
          style={[
            styles.filterChip,
            selectedCategory === category.id && { backgroundColor: category.color + '20', borderColor: category.color },
          ]}
          onPress={() => onSelectCategory(category.id)}
        >
          <Ionicons
            name={category.icon as keyof typeof Ionicons.glyphMap}
            size={14}
            color={selectedCategory === category.id ? category.color : colors.bark[400]}
          />
          <Text style={[
            styles.filterChipText,
            selectedCategory === category.id && { color: category.color },
          ]}>
            {category.label}
          </Text>
        </TouchableOpacity>
      ))}
    </ScrollView>
  );
};

// Individual maintenance record card
interface RecordCardProps {
  record: MaintenanceRecord;
  onPress: () => void;
}

const RecordCard: React.FC<RecordCardProps> = ({ record, onPress }) => {
  const category = maintenanceCategories.find(c => c.id === record.categoryId);
  const recordDate = new Date(record.date);

  const ContainerWrapper = Platform.OS === 'ios' ? BlurView : View;
  const containerProps = Platform.OS === 'ios'
    ? { tint: 'light' as const, intensity: blur.light, style: styles.recordCard }
    : { style: [styles.recordCard, styles.recordCardFallback] };

  return (
    <TouchableOpacity activeOpacity={0.8} onPress={onPress}>
      <ContainerWrapper {...containerProps}>
        <View style={styles.recordHeader}>
          <View style={[styles.recordIcon, { backgroundColor: (category?.color || colors.bark[400]) + '20' }]}>
            <Ionicons
              name={(category?.icon || 'construct') as keyof typeof Ionicons.glyphMap}
              size={20}
              color={category?.color || colors.bark[400]}
            />
          </View>
          <View style={styles.recordInfo}>
            <Text style={styles.recordTitle}>{record.categoryLabel}</Text>
            <Text style={styles.recordDate}>
              {recordDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
            </Text>
          </View>
          {record.cost !== undefined && record.cost > 0 && (
            <Text style={styles.recordCost}>${record.cost}</Text>
          )}
        </View>

        <View style={styles.recordDetails}>
          {record.mileage && (
            <View style={styles.recordDetailItem}>
              <Ionicons name="speedometer-outline" size={14} color={colors.bark[400]} />
              <Text style={styles.recordDetailText}>{record.mileage.toLocaleString()} mi</Text>
            </View>
          )}
          {record.provider && (
            <View style={styles.recordDetailItem}>
              <Ionicons name="business-outline" size={14} color={colors.bark[400]} />
              <Text style={styles.recordDetailText}>{record.provider}</Text>
            </View>
          )}
          {record.nextDueMileage && (
            <View style={styles.recordDetailItem}>
              <Ionicons name="calendar-outline" size={14} color={colors.bark[400]} />
              <Text style={styles.recordDetailText}>Next: {record.nextDueMileage.toLocaleString()} mi</Text>
            </View>
          )}
        </View>

        {record.notes && (
          <Text style={styles.recordNotes} numberOfLines={2}>{record.notes}</Text>
        )}
      </ContainerWrapper>
    </TouchableOpacity>
  );
};

// Add maintenance record modal
interface AddMaintenanceModalProps {
  visible: boolean;
  rigId: string;
  currentMileage?: number;
  onClose: () => void;
  onSave: (record: MaintenanceRecord) => void;
}

const AddMaintenanceModal: React.FC<AddMaintenanceModalProps> = ({
  visible,
  rigId,
  currentMileage,
  onClose,
  onSave,
}) => {
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [mileage, setMileage] = useState(currentMileage?.toString() || '');
  const [cost, setCost] = useState('');
  const [notes, setNotes] = useState('');
  const [provider, setProvider] = useState('');
  const [nextMileage, setNextMileage] = useState('');

  const selectedCategoryConfig = maintenanceCategories.find(c => c.id === selectedCategory);

  const handleSave = () => {
    if (!selectedCategory || !selectedCategoryConfig) return;

    const newRecord = addMaintenanceRecord({
      rigId,
      categoryId: selectedCategory,
      categoryLabel: selectedCategoryConfig.label,
      date: new Date().toISOString(),
      mileage: mileage ? parseInt(mileage, 10) : undefined,
      cost: cost ? parseFloat(cost) : undefined,
      notes: notes || undefined,
      provider: provider || undefined,
      nextDueMileage: nextMileage ? parseInt(nextMileage, 10) : undefined,
      isCompleted: true,
    });

    onSave(newRecord);
    resetForm();
  };

  const resetForm = () => {
    setSelectedCategory(null);
    setMileage(currentMileage?.toString() || '');
    setCost('');
    setNotes('');
    setProvider('');
    setNextMileage('');
  };

  return (
    <Modal visible={visible} animationType="slide" transparent>
      <KeyboardAvoidingView
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={styles.modalContainer}
      >
        <View style={styles.modalBackdrop}>
          <View style={styles.modalContent}>
            <View style={styles.modalHeader}>
              <Text style={styles.modalTitle}>Log Maintenance</Text>
              <TouchableOpacity onPress={onClose}>
                <Ionicons name="close" size={24} color={colors.bark[500]} />
              </TouchableOpacity>
            </View>

            <ScrollView style={styles.modalBody} showsVerticalScrollIndicator={false}>
              {/* Category selection */}
              <Text style={styles.inputLabel}>Category</Text>
              <View style={styles.categoryGrid}>
                {maintenanceCategories.map((category) => (
                  <TouchableOpacity
                    key={category.id}
                    style={[
                      styles.categoryOption,
                      selectedCategory === category.id && {
                        backgroundColor: category.color + '20',
                        borderColor: category.color,
                      },
                    ]}
                    onPress={() => setSelectedCategory(category.id)}
                  >
                    <Ionicons
                      name={category.icon as keyof typeof Ionicons.glyphMap}
                      size={20}
                      color={selectedCategory === category.id ? category.color : colors.bark[400]}
                    />
                    <Text
                      style={[
                        styles.categoryOptionText,
                        selectedCategory === category.id && { color: category.color },
                      ]}
                    >
                      {category.label}
                    </Text>
                  </TouchableOpacity>
                ))}
              </View>

              {/* Mileage input */}
              <Text style={styles.inputLabel}>Mileage</Text>
              <View style={styles.inputContainer}>
                <Ionicons name="speedometer-outline" size={18} color={colors.bark[400]} />
                <TextInput
                  style={styles.input}
                  value={mileage}
                  onChangeText={setMileage}
                  placeholder="Current mileage"
                  keyboardType="numeric"
                  placeholderTextColor={colors.bark[300]}
                />
                <Text style={styles.inputSuffix}>mi</Text>
              </View>

              {/* Cost input */}
              <Text style={styles.inputLabel}>Cost (optional)</Text>
              <View style={styles.inputContainer}>
                <Text style={styles.inputPrefix}>$</Text>
                <TextInput
                  style={styles.input}
                  value={cost}
                  onChangeText={setCost}
                  placeholder="0.00"
                  keyboardType="decimal-pad"
                  placeholderTextColor={colors.bark[300]}
                />
              </View>

              {/* Provider input */}
              <Text style={styles.inputLabel}>Service Provider (optional)</Text>
              <View style={styles.inputContainer}>
                <Ionicons name="business-outline" size={18} color={colors.bark[400]} />
                <TextInput
                  style={styles.input}
                  value={provider}
                  onChangeText={setProvider}
                  placeholder="Shop name or DIY"
                  placeholderTextColor={colors.bark[300]}
                />
              </View>

              {/* Next due mileage */}
              <Text style={styles.inputLabel}>Next Due Mileage (optional)</Text>
              <View style={styles.inputContainer}>
                <Ionicons name="calendar-outline" size={18} color={colors.bark[400]} />
                <TextInput
                  style={styles.input}
                  value={nextMileage}
                  onChangeText={setNextMileage}
                  placeholder="Next service at"
                  keyboardType="numeric"
                  placeholderTextColor={colors.bark[300]}
                />
                <Text style={styles.inputSuffix}>mi</Text>
              </View>

              {/* Notes */}
              <Text style={styles.inputLabel}>Notes (optional)</Text>
              <View style={[styles.inputContainer, styles.textAreaContainer]}>
                <TextInput
                  style={[styles.input, styles.textArea]}
                  value={notes}
                  onChangeText={setNotes}
                  placeholder="Parts used, observations, etc."
                  multiline
                  numberOfLines={3}
                  placeholderTextColor={colors.bark[300]}
                />
              </View>
            </ScrollView>

            {/* Save button */}
            <TouchableOpacity
              style={[styles.saveButton, !selectedCategory && styles.saveButtonDisabled]}
              onPress={handleSave}
              disabled={!selectedCategory}
            >
              <LinearGradient
                colors={
                  selectedCategory
                    ? [colors.deepTeal[500], colors.deepTeal[600]]
                    : [colors.bark[300], colors.bark[400]]
                }
                start={{ x: 0, y: 0 }}
                end={{ x: 1, y: 1 }}
                style={styles.saveButtonGradient}
              >
                <Ionicons name="checkmark" size={20} color={colors.text.inverse} />
                <Text style={styles.saveButtonText}>Save Record</Text>
              </LinearGradient>
            </TouchableOpacity>
          </View>
        </View>
      </KeyboardAvoidingView>
    </Modal>
  );
};

// Main component
export const MaintenanceTracker: React.FC<MaintenanceTrackerProps> = ({
  rigId,
  currentMileage = 45000,
}) => {
  const [records, setRecords] = useState<MaintenanceRecord[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [showAddModal, setShowAddModal] = useState(false);

  useEffect(() => {
    setRecords(getMaintenanceRecords(rigId));
  }, [rigId]);

  const filteredRecords = useMemo(() => {
    if (!selectedCategory) return records;
    return records.filter(r => r.categoryId === selectedCategory);
  }, [records, selectedCategory]);

  const handleSaveRecord = (record: MaintenanceRecord) => {
    setRecords(getMaintenanceRecords(rigId));
    setShowAddModal(false);
  };

  return (
    <View style={styles.container}>
      {/* Stats card */}
      <MaintenanceStatsCard rigId={rigId} />

      {/* Upcoming alerts */}
      <UpcomingAlerts rigId={rigId} currentMileage={currentMileage} />

      {/* Records list */}
      <ScrollView
        style={styles.recordsList}
        contentContainerStyle={styles.recordsContent}
        showsVerticalScrollIndicator={false}
      >
        {filteredRecords.length === 0 ? (
          <View style={styles.emptyState}>
            <Ionicons name="construct-outline" size={48} color={colors.bark[300]} />
            <Text style={styles.emptyTitle}>No maintenance records</Text>
            <Text style={styles.emptyText}>
              Keep your rig running smooth by logging maintenance tasks.
            </Text>
          </View>
        ) : (
          filteredRecords.map((record) => (
            <RecordCard
              key={record.id}
              record={record}
              onPress={() => {}}
            />
          ))
        )}
      </ScrollView>

      {/* Add button */}
      <TouchableOpacity
        style={styles.fab}
        onPress={() => setShowAddModal(true)}
        activeOpacity={0.9}
      >
        <LinearGradient
          colors={[colors.deepTeal[500], colors.deepTeal[600]]}
          start={{ x: 0, y: 0 }}
          end={{ x: 1, y: 1 }}
          style={styles.fabGradient}
        >
          <Ionicons name="add" size={28} color={colors.text.inverse} />
        </LinearGradient>
      </TouchableOpacity>

      {/* Add modal */}
      <AddMaintenanceModal
        visible={showAddModal}
        rigId={rigId}
        currentMileage={currentMileage}
        onClose={() => setShowAddModal(false)}
        onSave={handleSaveRecord}
      />
    </View>
  );
};

