import React, { useState } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  KeyboardAvoidingView,
  Platform,
  ScrollView,
} from 'react-native';
import { useRouter } from '@/hooks/useRouterCompat';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { colors, typography, spacing, borderRadius, shadows } from '@/constants/theme';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { GlassCard } from '@/components/ui/GlassCard';
import { NatureBackground } from '@/components/ui/NatureBackground';
import { useAuth } from '@/contexts/AuthContext';

export default function PhoneAuthScreen() {
  const router = useRouter();
  const insets = useSafeAreaInsets();
  const { sendOTP } = useAuth();
  const [authMethod, setAuthMethod] = useState<'phone' | 'email'>('phone');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleContinue = async () => {
    setError('');
    setLoading(true);

    if (authMethod === 'phone') {
      if (phone.length < 10) {
        setError('Please enter a valid phone number');
        setLoading(false);
        return;
      }
    } else {
      if (!email.includes('@')) {
        setError('Please enter a valid email address');
        setLoading(false);
        return;
      }
    }

    const value = authMethod === 'phone' ? phone : email;
    const result = await sendOTP(authMethod, value);

    if (result.success) {
      router.push('/(onboarding)/verify-otp');
    } else {
      setError(result.message || 'Failed to send verification code');
    }

    setLoading(false);
  };

  return (
    <NatureBackground variant="forest" overlay overlayOpacity={0.45}>
      <KeyboardAvoidingView
        style={styles.container}
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
      >
        <ScrollView
          contentContainerStyle={[
            styles.scrollContent,
            { paddingTop: insets.top + spacing.lg, paddingBottom: insets.bottom + spacing.xl },
          ]}
          keyboardShouldPersistTaps="handled"
        >
          {/* Header */}
          <TouchableOpacity
            style={styles.backButton}
            onPress={() => router.back()}
          >
            <Ionicons name="arrow-back" size={24} color={colors.text.inverse} />
          </TouchableOpacity>

          {/* Progress Indicator */}
          <View style={styles.progressContainer}>
            <View style={[styles.progressBar, styles.progressActive]} />
            <View style={[styles.progressBar, styles.progressActive]} />
            <View style={styles.progressBar} />
            <View style={styles.progressBar} />
          </View>

          <Text style={styles.stepLabel}>Step 2 of 4</Text>

          {/* Title Section */}
          <View style={styles.titleSection}>
            <View style={styles.iconContainer}>
              <Ionicons name="phone-portrait" size={32} color={colors.text.inverse} />
            </View>
            <Text style={styles.title}>Verify Your Identity</Text>
            <Text style={styles.subtitle}>
              We&apos;ll send you a 6-digit code to verify your identity
            </Text>
          </View>

          {/* Auth Method Toggle Card */}
          <GlassCard variant="medium" padding="sm" style={styles.toggleCard}>
            <View style={styles.toggleContainer}>
              <TouchableOpacity
                style={[
                  styles.toggleButton,
                  authMethod === 'phone' && styles.toggleButtonActive,
                ]}
                onPress={() => {
                  setAuthMethod('phone');
                  setError('');
                }}
              >
                <Ionicons
                  name="call"
                  size={18}
                  color={authMethod === 'phone' ? colors.text.inverse : colors.bark[500]}
                />
                <Text
                  style={[
                    styles.toggleText,
                    authMethod === 'phone' && styles.toggleTextActive,
                  ]}
                >
                  Phone
                </Text>
              </TouchableOpacity>
              <TouchableOpacity
                style={[
                  styles.toggleButton,
                  authMethod === 'email' && styles.toggleButtonActive,
                ]}
                onPress={() => {
                  setAuthMethod('email');
                  setError('');
                }}
              >
                <Ionicons
                  name="mail"
                  size={18}
                  color={authMethod === 'email' ? colors.text.inverse : colors.bark[500]}
                />
                <Text
                  style={[
                    styles.toggleText,
                    authMethod === 'email' && styles.toggleTextActive,
                  ]}
                >
                  Email
                </Text>
              </TouchableOpacity>
            </View>
          </GlassCard>

          {/* Input Form Card */}
          <GlassCard variant="medium" padding="lg" style={styles.formCard}>
            <View style={styles.formHeader}>
              <Ionicons
                name={authMethod === 'phone' ? 'call' : 'mail'}
                size={20}
                color={colors.ember[500]}
              />
              <Text style={styles.formLabel}>
                Enter your {authMethod === 'phone' ? 'phone number' : 'email address'}
              </Text>
            </View>

            {authMethod === 'phone' ? (
              <Input
                placeholder="(555) 123-4567"
                value={phone}
                onChangeText={(text) => {
                  setPhone(text.replace(/[^0-9]/g, ''));
                  setError('');
                }}
                error={error}
                keyboardType="phone-pad"
                leftIcon={
                  <View style={styles.countryCode}>
                    <Text style={styles.countryCodeText}>+1</Text>
                  </View>
                }
              />
            ) : (
              <Input
                placeholder="email@example.com"
                value={email}
                onChangeText={(text) => {
                  setEmail(text.toLowerCase());
                  setError('');
                }}
                error={error}
                keyboardType="email-address"
                autoCapitalize="none"
                leftIcon={
                  <Ionicons name="mail-outline" size={20} color={colors.bark[400]} />
                }
              />
            )}

            {/* Privacy Notice */}
            <View style={styles.privacyNotice}>
              <Ionicons name="shield-checkmark" size={16} color={colors.moss[500]} />
              <Text style={styles.privacyText}>
                Your {authMethod} will only be used for verification and will never be shared
              </Text>
            </View>
          </GlassCard>

          {/* CTA Button */}
          <View style={styles.ctaSection}>
            <Button
              title="Send Verification Code"
              onPress={handleContinue}
              variant="ember"
              size="lg"
              fullWidth
              loading={loading}
              disabled={authMethod === 'phone' ? !phone : !email}
              icon={<Ionicons name="arrow-forward" size={20} color={colors.text.inverse} />}
              iconPosition="right"
            />
          </View>
        </ScrollView>
      </KeyboardAvoidingView>
    </NatureBackground>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  scrollContent: {
    flexGrow: 1,
    paddingHorizontal: spacing.xl,
  },
  backButton: {
    width: 44,
    height: 44,
    borderRadius: borderRadius.full,
    backgroundColor: colors.glass.whiteMedium,
    justifyContent: 'center',
    alignItems: 'center',
    ...shadows.glass,
  },
  progressContainer: {
    flexDirection: 'row',
    gap: spacing.sm,
    marginTop: spacing.xl,
  },
  progressBar: {
    flex: 1,
    height: 4,
    backgroundColor: colors.glass.whiteLight,
    borderRadius: borderRadius.full,
  },
  progressActive: {
    backgroundColor: colors.ember[500],
  },
  stepLabel: {
    fontSize: typography.fontSize.sm,
    color: colors.bark[200],
    marginTop: spacing.md,
  },
  titleSection: {
    alignItems: 'center',
    marginTop: spacing['2xl'],
    marginBottom: spacing['2xl'],
  },
  iconContainer: {
    width: 72,
    height: 72,
    borderRadius: borderRadius.pill,
    backgroundColor: colors.glass.whiteMedium,
    justifyContent: 'center',
    alignItems: 'center',
    marginBottom: spacing.lg,
    ...shadows.glass,
  },
  title: {
    fontSize: typography.fontSize.xl,
    fontWeight: '700',
    color: colors.text.inverse,
    marginBottom: spacing.sm,
  },
  subtitle: {
    fontSize: typography.fontSize.base,
    color: colors.bark[200],
    textAlign: 'center',
    lineHeight: 22,
  },
  toggleCard: {
    marginBottom: spacing.lg,
  },
  toggleContainer: {
    flexDirection: 'row',
    gap: spacing.sm,
  },
  toggleButton: {
    flex: 1,
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
    paddingVertical: spacing.md,
    borderRadius: borderRadius.xl,
    gap: spacing.sm,
  },
  toggleButtonActive: {
    backgroundColor: colors.moss[500],
    ...shadows.glassSubtle,
  },
  toggleText: {
    fontSize: typography.fontSize.base,
    fontWeight: '600',
    color: colors.bark[500],
  },
  toggleTextActive: {
    color: colors.text.inverse,
  },
  formCard: {
    marginBottom: spacing.xl,
  },
  formHeader: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: spacing.sm,
    marginBottom: spacing.lg,
  },
  formLabel: {
    fontSize: typography.fontSize.md,
    fontWeight: '600',
    color: colors.bark[700],
  },
  countryCode: {
    borderRightWidth: 1,
    borderRightColor: colors.glass.border,
    paddingRight: spacing.md,
    marginRight: spacing.sm,
  },
  countryCodeText: {
    fontSize: typography.fontSize.base,
    fontWeight: '600',
    color: colors.bark[600],
  },
  privacyNotice: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: colors.moss[500] + '15',
    padding: spacing.md,
    borderRadius: borderRadius.lg,
    marginTop: spacing.sm,
    gap: spacing.sm,
  },
  privacyText: {
    flex: 1,
    fontSize: typography.fontSize.sm,
    color: colors.moss[700],
    lineHeight: 18,
  },
  ctaSection: {
    marginBottom: spacing.xl,
  },
});

client/services/ai/emergencyTriageServic.content:
/**
 * WilderGo Emergency Triage AI Service
 * AI-powered emergency assistance:
 * - Analyze help request descriptions and provide immediate safety advice
 * - Generate reassuring icebreaker messages for responders
 * - Prioritize emergency responses based on severity
 * 
 * Note: AI text generation is disabled in this environment.
 * Using intelligent fallback logic instead.
 */

// Stub function that throws to trigger fallback logic
async function generateText(_options: { prompt: string }): Promise<string> {
  throw new Error('AI generation not available - using fallback');
}

export type EmergencyCategory = 'mechanical' | 'medical' | 'security' | 'supplies';
export type EmergencyPriority = 'critical' | 'urgent' | 'assistance';

export interface TriageInput {
  category: EmergencyCategory;
  description: string;
  priority: EmergencyPriority;
  location?: {
    address?: string;
    latitude?: number;
    longitude?: number;
  };
  userContext?: {
    rigType?: string;
    travelingAlone?: boolean;
    hasTools?: boolean;
  };
}

export interface TriageResult {
  safetyAdvice: string;
  immediateActions: string[];
  thingsToAvoid: string[];
  whatToExpect: string;
  estimatedWaitMessage: string;
}

export interface IcebreakerInput {
  category: EmergencyCategory;
  priority: EmergencyPriority;
  description: string;
  responderDistance?: number; // in miles
  responderHasTools?: boolean;
}

export interface IcebreakerResult {
  messages: string[];
  suggestedActions: string[];
}

/**
 * Analyze emergency description and provide immediate safety advice
 * Called when user submits a help request - provides guidance while waiting for responders
 */
export async function analyzeEmergencyTriage(input: TriageInput): Promise<TriageResult> {
  const { category, description, priority, location, userContext } = input;

  const categoryContext = getCategoryContext(category);
  const priorityLevel = priority === 'critical' ? 'life-threatening' : priority === 'urgent' ? 'serious' : 'non-urgent';

  const prompt = `You are an emergency triage assistant for nomadic travelers (van lifers, RVers). Analyze this ${priorityLevel} ${category} emergency and provide immediate safety advice.

SITUATION:
Category: ${category}
Priority: ${priority}
Description: ${description}
${location?.address ? `Location: ${location.address}` : ''}
${userContext?.rigType ? `Vehicle: ${userContext.rigType}` : ''}
${userContext?.travelingAlone !== undefined ? `Traveling alone: ${userContext.travelingAlone ? 'Yes' : 'No'}` : ''}

${categoryContext}

Respond in this exact JSON format:
{
  "safetyAdvice": "Main safety guidance paragraph (2-3 sentences, reassuring but practical)",
  "immediateActions": ["Action 1", "Action 2", "Action 3"],
  "thingsToAvoid": ["Thing to avoid 1", "Thing to avoid 2"],
  "whatToExpect": "Brief description of what help will look like when it arrives",
  "estimatedWaitMessage": "Reassuring message about wait time"
}

Keep advice practical, calm, and specific to nomadic/vehicle living situations. Be reassuring but prioritize safety.`;

  try {
    const response = await generateText({ prompt });

    // Parse JSON response
    const jsonMatch = response.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      return {
        safetyAdvice: parsed.safetyAdvice || getDefaultSafetyAdvice(category, priority),
        immediateActions: parsed.immediateActions || getDefaultActions(category),
        thingsToAvoid: parsed.thingsToAvoid || getDefaultAvoidances(category),
        whatToExpect: parsed.whatToExpect || 'Nearby nomads are being notified and may reach out to help.',
        estimatedWaitMessage: parsed.estimatedWaitMessage || 'Help is on the way. Stay safe and someone will contact you soon.',
      };
    }

    // Fallback if JSON parsing fails
    return getDefaultTriageResult(category, priority);
  } catch (error) {
    // AI not available - using default triage (this is expected behavior)
    return getDefaultTriageResult(category, priority);
  }
}

/**
 * Generate reassuring icebreaker messages for responders
 * Called when a responder is about to reach out to someone in distress
 */
export async function generateSOSIcebreakers(input: IcebreakerInput): Promise<IcebreakerResult> {
  const { category, priority, description, responderDistance, responderHasTools } = input;

  const prompt = `You are helping a Good Samaritan nomad traveler respond to someone who needs ${category} help. Generate 3 short, reassuring first-contact messages they can send.

SITUATION THEY'RE RESPONDING TO:
Category: ${category}
Priority: ${priority}
Their description: "${description}"
${responderDistance ? `Responder is ${responderDistance.toFixed(1)} miles away` : ''}
${responderHasTools !== undefined ? `Responder has tools: ${responderHasTools ? 'Yes' : 'Maybe'}` : ''}

Respond in this exact JSON format:
{
  "messages": [
    "Short friendly first message (under 50 chars)",
    "Second option message (under 50 chars)",
    "Third option with specific offer (under 60 chars)"
  ],
  "suggestedActions": [
    "Quick action the responder could offer",
    "Another helpful action"
  ]
}

Messages should be:
- Warm and reassuring
- Not overly formal
- Show they're coming to help
- Appropriate for nomad/van life community`;

  try {
    const response = await generateText({ prompt });

    // Parse JSON response
    const jsonMatch = response.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      return {
        messages: parsed.messages || getDefaultIcebreakers(category, responderDistance),
        suggestedActions: parsed.suggestedActions || getDefaultSuggestedActions(category),
      };
    }

    return {
      messages: getDefaultIcebreakers(category, responderDistance),
      suggestedActions: getDefaultSuggestedActions(category),
    };
  } catch (error) {
    // AI not available - using default icebreakers (this is expected behavior)
    return {
      messages: getDefaultIcebreakers(category, responderDistance),
      suggestedActions: getDefaultSuggestedActions(category),
    };
  }
}

/**
 * Quick triage assessment without full AI call (for immediate UI feedback)
 * Uses predefined responses based on category and priority
 */
export function getQuickTriageAdvice(category: EmergencyCategory, priority: EmergencyPriority): string {
  const adviceMap: Record<EmergencyCategory, Record<EmergencyPriority, string>> = {
    mechanical: {
      critical: 'Turn on hazard lights and get to safety if possible. Do not attempt repairs in traffic. Help is being notified.',
      urgent: 'Stay with your vehicle in a safe location. Turn on hazard lights. Nearby nomads with mechanical experience are being alerted.',
      assistance: 'Document the issue with photos if safe. Nearby nomads who may be able to help are being notified.',
    },
    medical: {
      critical: 'Call 911 immediately for life-threatening emergencies. Keep the person comfortable and still. Help is on the way.',
      urgent: 'Stay calm and rest. Gather any relevant medical information. Nearby nomads are being notified.',
      assistance: 'Rest and stay hydrated. Nearby nomads who may have supplies or experience are being contacted.',
    },
    security: {
      critical: 'If in immediate danger, call 911. Lock doors and stay in your vehicle. Nearby nomads are being alerted.',
      urgent: 'Trust your instincts. Lock your vehicle. Keep your phone charged. Help is being coordinated.',
      assistance: 'Stay aware of your surroundings. Nearby community members are being notified.',
    },
    supplies: {
      critical: 'Conserve what resources you have. Stay sheltered. Emergency supplies assistance is being coordinated.',
      urgent: 'Ration your current supplies. Nearby nomads who can help are being notified.',
      assistance: 'Help with supplies is on the way. Nearby nomads are being contacted.',
    },
  };

  return adviceMap[category][priority];
}

// Helper functions for context and defaults

function getCategoryContext(category: EmergencyCategory): string {
  const contexts: Record<EmergencyCategory, string> = {
    mechanical: `MECHANICAL EMERGENCY CONTEXT:
- Common van/RV issues: flat tires, dead batteries, overheating, alternator failure, transmission issues
- Important: Many nomads carry basic tools and have mechanical knowledge
- Safety considerations: Traffic, weather, remote locations`,
    medical: `MEDICAL EMERGENCY CONTEXT:
- For life-threatening emergencies, always recommend calling 911 first
- Consider: Nearest hospital access, limited medical supplies on road
- Many nomads have first aid kits and basic training`,
    security: `SECURITY EMERGENCY CONTEXT:
- Safety is paramount - validate their instincts
- Consider: Remote locations, limited cell service possible
- Community support can provide presence and escort`,
    supplies: `SUPPLIES EMERGENCY CONTEXT:
- Common needs: Water, fuel, food, propane, medication
- Consider: Distance to nearest town, weather conditions
- Nomad community often shares resources`,
  };
  return contexts[category];
}

function getDefaultTriageResult(category: EmergencyCategory, priority: EmergencyPriority): TriageResult {
  return {
    safetyAdvice: getDefaultSafetyAdvice(category, priority),
    immediateActions: getDefaultActions(category),
    thingsToAvoid: getDefaultAvoidances(category),
    whatToExpect: 'Nearby nomads are being notified and someone will reach out to help shortly.',
    estimatedWaitMessage: 'Help is on the way. Stay safe and keep your phone accessible.',
  };
}

function getDefaultSafetyAdvice(category: EmergencyCategory, priority: EmergencyPriority): string {
  if (priority === 'critical') {
    if (category === 'medical') {
      return 'For life-threatening emergencies, please call 911 immediately. Keep the person as comfortable as possible while waiting for help.';
    }
    if (category === 'security') {
      return 'If you are in immediate danger, call 911. Lock your vehicle and stay inside until help arrives.';
    }
  }

  const defaults: Record<EmergencyCategory, string> = {
    mechanical: 'Stay safe and visible. Turn on your hazard lights if stopped on the road. Do not attempt risky repairs alone.',
    medical: 'Rest and stay calm. Gather any relevant health information. Help from nearby nomads is being coordinated.',
    security: 'Trust your instincts and prioritize your safety. Lock your vehicle and stay aware of your surroundings.',
    supplies: 'Conserve your current resources. Help with supplies is being coordinated from nearby community members.',
  };

  return defaults[category];
}

function getDefaultActions(category: EmergencyCategory): string[] {
  const actions: Record<EmergencyCategory, string[]> = {
    mechanical: [
      'Turn on hazard lights',
      'Move to a safe location if possible',
      'Document the issue with photos',
    ],
    medical: [
      'Rest in a comfortable position',
      'Stay hydrated if possible',
      'Have any medications or medical info ready',
    ],
    security: [
      'Lock all doors and windows',
      'Keep your phone charged and accessible',
      'Note descriptions of any concerns',
    ],
    supplies: [
      'Take inventory of current supplies',
      'Conserve water and fuel',
      'Stay sheltered from weather',
    ],
  };
  return actions[category];
}

function getDefaultAvoidances(category: EmergencyCategory): string[] {
  const avoidances: Record<EmergencyCategory, string[]> = {
    mechanical: [
      'Do not attempt repairs in traffic',
      'Avoid opening hot radiator caps',
    ],
    medical: [
      'Do not ignore worsening symptoms',
      'Avoid strenuous activity',
    ],
    security: [
      'Do not confront suspicious individuals',
      'Do not share your exact location publicly',
    ],
    supplies: [
      'Do not ration too severely - help is coming',
      'Avoid unnecessary travel to conserve fuel',
    ],
  };
  return avoidances[category];
}

function getDefaultIcebreakers(category: EmergencyCategory, distance?: number): string[] {
  const distanceText = distance ? `${distance.toFixed(0)} min away` : 'nearby';

  const defaults: Record<EmergencyCategory, string[]> = {
    mechanical: [
      `Hey! I'm ${distanceText} and can help - hang tight!`,
      'Fellow nomad here - what tools do you need?',
      'On my way! I have a basic toolkit with me',
    ],
    medical: [
      `I'm ${distanceText} - how can I help?`,
      'Nearby and have a first aid kit - coming to check on you',
      'Fellow traveler here - what do you need most?',
    ],
    security: [
      `I'm ${distanceText} - can come provide some company`,
      'Fellow nomad here - happy to come hang nearby',
      'On my way to check on you - stay safe!',
    ],
    supplies: [
      `Hey! I'm ${distanceText} and have supplies to share`,
      'Fellow traveler - what do you need most urgently?',
      'Happy to help! What supplies are you low on?',
    ],
  };

  return defaults[category];
}

function getDefaultSuggestedActions(category: EmergencyCategory): string[] {
  const actions: Record<EmergencyCategory, string[]> = {
    mechanical: [
      'Offer to take a look at the issue',
      'Share tools or spare parts if available',
      'Help search for nearby mechanics',
    ],
    medical: [
      'Offer first aid supplies',
      'Help locate nearest medical facility',
      'Provide company and reassurance',
    ],
    security: [
      'Offer to park nearby for company',
      'Help scout the area',
      'Provide escort to a safer location',
    ],
    supplies: [
      'Share water, fuel, or food',
      'Help locate nearest supply point',
      'Offer to make a supply run',
    ],
  };
  return actions[category];
}

export default {
  analyzeEmergencyTriage,
  generateSOSIcebreakers,
  getQuickTriageAdvice,
};

