/**
 * SmartRouteScreen
 * Complete Smart Route UI with Map, Weather, Road Risk, and Destination Search
 */

import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
  ActivityIndicator,
  Dimensions,
  Platform,
  TextInput,
  FlatList,
  Keyboard,
} from 'react-native';
import MapView, { Polyline, Marker, PROVIDER_GOOGLE } from 'react-native-maps';
import { Ionicons } from '@expo/vector-icons';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { LinearGradient } from 'expo-linear-gradient';
import {
  getSmartRoute,
  getWeatherIconName,
  getRoadRiskColor,
  searchPlaces,
  getPlaceCoordinates,
  SmartRouteData,
  Coordinate,
  PlaceSuggestion,
} from '@/services/smartRouteService';
import { colors, typography, spacing, borderRadius } from '@/constants/theme';

const { width, height } = Dimensions.get('window');

const COLORS = {
  warmCream: '#F5EFE6',
  lightCream: '#FAF6F2',
  desertSand: '#E8C5A5',
  sandDark: '#D9B894',
  skyBlue: '#4A90E2',
  skyBlueLight: '#E3F0FF',
  skyBlueDark: '#3B7BC8',
  amber: '#F2A154',
  amberLight: '#FFF9F0',
  amberDark: '#D48A3A',
  forestGreenLight: '#E8F5E9',
  forestGreenDark: '#2D5A3D',
};

interface SmartRouteScreenProps {
  origin?: Coordinate;
  destination?: Coordinate;
  originName?: string;
  destinationName?: string;
  onClose?: () => void;
  onStartNavigation?: () => void;
}

export function SmartRouteScreen({
  origin = { latitude: 39.7392, longitude: -104.9903 },
  destination: initialDestination,
  originName: initialOriginName = 'Your Location',
  destinationName: initialDestinationName,
  onClose,
  onStartNavigation,
}: SmartRouteScreenProps) {
  const insets = useSafeAreaInsets();
  const [smartRoute, setSmartRoute] = useState<SmartRouteData | null>(null);
  const [loading, setLoading] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [suggestions, setSuggestions] = useState<PlaceSuggestion[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showSearch, setShowSearch] = useState(!initialDestination);
  const [selectedDestination, setSelectedDestination] = useState<Coordinate | null>(initialDestination || null);
  const [destinationName, setDestinationName] = useState(initialDestinationName || '');
  const [originNameState] = useState(initialOriginName);
  const searchTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const searchInputRef = useRef<TextInput>(null);

  const [mapRegion, setMapRegion] = useState({
    latitude: origin.latitude,
    longitude: origin.longitude,
    latitudeDelta: 2,
    longitudeDelta: 2,
  });

  const handleSearch = useCallback((text: string) => {
    setSearchQuery(text);

    if (searchTimerRef.current) {
      clearTimeout(searchTimerRef.current);
    }

    if (text.length < 2) {
      setSuggestions([]);
      return;
    }

    searchTimerRef.current = setTimeout(async () => {
      setIsSearching(true);
      try {
        const results = await searchPlaces(text);
        setSuggestions(results);
      } catch (error) {
        console.warn('Search error:', error);
      } finally {
        setIsSearching(false);
      }
    }, 300);
  }, []);

  const [error, setError] = useState<string | null>(null);

  const handleSelectPlace = useCallback(async (place: PlaceSuggestion) => {
    Keyboard.dismiss();
    setSuggestions([]);
    setSearchQuery(place.mainText);
    setShowSearch(false);
    setLoading(true);
    setError(null);

    try {
      console.log('[SmartRoute] Getting coordinates for:', place.mainText, place.placeId);
      const result = await getPlaceCoordinates(place.placeId, place.description);
      console.log('[SmartRoute] Place coordinates result:', result ? 'success' : 'null');

      if (!result) {
        setError('Could not find location. Please try another search.');
        setShowSearch(true);
        setLoading(false);
        return;
      }

      setSelectedDestination(result.coordinate);
      setDestinationName(result.name);

      const midLat = (origin.latitude + result.coordinate.latitude) / 2;
      const midLon = (origin.longitude + result.coordinate.longitude) / 2;
      setMapRegion({
        latitude: midLat,
        longitude: midLon,
        latitudeDelta: Math.max(Math.abs(result.coordinate.latitude - origin.latitude) * 1.8, 0.5),
        longitudeDelta: Math.max(Math.abs(result.coordinate.longitude - origin.longitude) * 1.8, 0.5),
      });

      console.log('[SmartRoute] Fetching route from', origin, 'to', result.coordinate);
      const route = await getSmartRoute(origin, result.coordinate);
      console.log('[SmartRoute] Route result:', route.success, route.distance);

      if (route.success) {
        setSmartRoute(route);
      } else {
        setError('Could not calculate route. Please try again.');
        setShowSearch(true);
      }
    } catch (err: any) {
      console.error('[SmartRoute] Error selecting place:', err);
      setError('Something went wrong. Please try again.');
      setShowSearch(true);
    } finally {
      setLoading(false);
    }
  }, [origin]);

  const loadSmartRoute = useCallback(async () => {
    if (!selectedDestination) return;
    setLoading(true);
    try {
      const route = await getSmartRoute(origin, selectedDestination);
      if (route.success) {
        setSmartRoute(route);

        const midLat = (origin.latitude + selectedDestination.latitude) / 2;
        const midLon = (origin.longitude + selectedDestination.longitude) / 2;
        setMapRegion({
          latitude: midLat,
          longitude: midLon,
          latitudeDelta: Math.abs(selectedDestination.latitude - origin.latitude) * 1.5,
          longitudeDelta: Math.abs(selectedDestination.longitude - origin.longitude) * 1.5,
        });
      }
    } catch (error) {
      console.error('Error loading Smart Route:', error);
    } finally {
      setLoading(false);
    }
  }, [origin, selectedDestination]);

  useEffect(() => {
    if (initialDestination && !smartRoute) {
      setSelectedDestination(initialDestination);
      loadSmartRoute();
    }
  }, []);

  const handleChangeDestination = useCallback(() => {
    setSmartRoute(null);
    setShowSearch(true);
    setSearchQuery('');
    setSuggestions([]);
    setTimeout(() => searchInputRef.current?.focus(), 300);
  }, []);

  const renderWeatherMarker = (
    coordinate: Coordinate,
    weather: { temperature: number; condition: string },
    title: string,
    markerStyle: object
  ) => (
    <Marker
      coordinate={coordinate}
      title={title}
      description={`${weather.temperature}°F - ${weather.condition}`}
    >
      <View style={styles.markerContainer}>
        <View style={[styles.marker, markerStyle]}>
          <Ionicons
            name={getWeatherIconName(weather.condition) as keyof typeof Ionicons.glyphMap}
            size={24}
            color={colors.sunsetOrange[600]}
          />
          <Text style={styles.markerTemp}>{weather.temperature}°</Text>
        </View>
        <View style={styles.markerArrow} />
      </View>
    </Marker>
  );

  return (
    <View style={styles.container}>
      {/* Header */}
      <View style={[styles.header, { paddingTop: insets.top + spacing.sm }]}>
        <View style={styles.headerContent}>
          {onClose ? (
            <TouchableOpacity onPress={onClose} style={styles.closeButton} testID="smart-route-close">
              <Ionicons name="close" size={24} color={colors.bark[700]} />
            </TouchableOpacity>
          ) : null}
          <View style={styles.headerText}>
            <Text style={styles.headerTitle}>Smart Route</Text>
            <Text style={styles.headerSubtitle}>Real-Time Weather Navigation</Text>
          </View>
          {selectedDestination ? (
            <TouchableOpacity onPress={loadSmartRoute} style={styles.refreshButton}>
              <Ionicons name="refresh" size={20} color={colors.sunsetOrange[500]} />
            </TouchableOpacity>
          ) : null}
        </View>
      </View>

      {/* Search Section */}
      {showSearch ? (
        <View style={styles.searchSection}>
          {/* Error Message */}
          {error ? (
            <View style={styles.errorBanner}>
              <Ionicons name="alert-circle" size={18} color="#D32F2F" />
              <Text style={styles.errorText}>{error}</Text>
            </View>
          ) : null}
          <View style={styles.routeInputs}>
            <View style={styles.inputRow}>
              <View style={[styles.inputDot, { backgroundColor: colors.forestGreen[500] }]} />
              <View style={styles.inputField}>
                <Text style={styles.inputLabel}>FROM</Text>
                <Text style={styles.originText} numberOfLines={1}>{originNameState}</Text>
              </View>
            </View>
            <View style={styles.inputDivider} />
            <View style={styles.inputRow}>
              <View style={[styles.inputDot, { backgroundColor: colors.sunsetOrange[500] }]} />
              <View style={styles.inputFieldActive}>
                <Text style={styles.inputLabel}>TO</Text>
                <TextInput
                  ref={searchInputRef}
                  style={styles.searchInput}
                  placeholder="Search destination (e.g. Copper Mountain)"
                  placeholderTextColor={colors.bark[400]}
                  value={searchQuery}
                  onChangeText={handleSearch}
                  autoFocus
                  returnKeyType="search"
                  testID="destination-search-input"
                />
              </View>
              {isSearching ? (
                <ActivityIndicator size="small" color={colors.sunsetOrange[500]} />
              ) : null}
            </View>
          </View>

          {/* Search Results */}
          {suggestions.length > 0 ? (
            <View style={styles.suggestionsContainer}>
              <FlatList
                data={suggestions}
                keyExtractor={(item) => item.placeId}
                keyboardShouldPersistTaps="handled"
                renderItem={({ item }) => (
                  <TouchableOpacity
                    style={styles.suggestionItem}
                    onPress={() => handleSelectPlace(item)}
                    testID={`suggestion-${item.placeId}`}
                  >
                    <Ionicons name="location" size={20} color={colors.sunsetOrange[500]} />
                    <View style={styles.suggestionText}>
                      <Text style={styles.suggestionMain} numberOfLines={1}>{item.mainText}</Text>
                      <Text style={styles.suggestionSecondary} numberOfLines={1}>{item.secondaryText}</Text>
                    </View>
                  </TouchableOpacity>
                )}
              />
            </View>
          ) : null}

          {/* Popular Destinations */}
          {searchQuery.length === 0 ? (
            <View style={styles.popularSection}>
              <Text style={styles.popularTitle}>Popular Destinations</Text>
              {[
                { name: 'Copper Mountain, CO', lat: 39.5022, lng: -106.1497 },
                { name: 'Moab, UT', lat: 38.5733, lng: -109.5498 },
                { name: 'Sedona, AZ', lat: 34.8697, lng: -111.7610 },
                { name: 'Yellowstone National Park', lat: 44.4280, lng: -110.5885 },
                { name: 'Big Sur, CA', lat: 36.2704, lng: -121.8081 },
              ].map((dest) => (
                <TouchableOpacity
                  key={dest.name}
                  style={styles.popularItem}
                  onPress={() => {
                    setShowSearch(false);
                    setLoading(true);
                    setError(null);
                    setSelectedDestination({ latitude: dest.lat, longitude: dest.lng });
                    setDestinationName(dest.name);
                    const midLat = (origin.latitude + dest.lat) / 2;
                    const midLon = (origin.longitude + dest.lng) / 2;
                    setMapRegion({
                      latitude: midLat,
                      longitude: midLon,
                      latitudeDelta: Math.max(Math.abs(dest.lat - origin.latitude) * 1.8, 0.5),
                      longitudeDelta: Math.max(Math.abs(dest.lng - origin.longitude) * 1.8, 0.5),
                    });
                    getSmartRoute(origin, { latitude: dest.lat, longitude: dest.lng })
                      .then(route => {
                        if (route.success) {
                          setSmartRoute(route);
                        } else {
                          setError('Could not calculate route. Please try again.');
                          setShowSearch(true);
                        }
                      })
                      .catch(() => {
                        setError('Something went wrong. Please try again.');
                        setShowSearch(true);
                      })
                      .finally(() => setLoading(false));
                  }}
                >
                  <Ionicons name="compass" size={20} color={colors.sunsetOrange[500]} />
                  <Text style={styles.popularText}>{dest.name}</Text>
                  <Ionicons name="chevron-forward" size={16} color={colors.bark[400]} />
                </TouchableOpacity>
              ))}
            </View>
          ) : null}
        </View>
      ) : null}

      {/* Loading State */}
      {loading ? (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="large" color={colors.sunsetOrange[500]} />
          <Text style={styles.loadingText}>Fetching real weather data...</Text>
          <Text style={styles.loadingSubtext}>Analyzing conditions along your route</Text>
        </View>
      ) : null}

      {/* Map + Route Info (shown after route is calculated) */}
      {!showSearch && !loading && smartRoute ? (
        <>
          {/* Change Destination Button */}
          <TouchableOpacity
            style={styles.changeDestButton}
            onPress={handleChangeDestination}
            testID="change-destination"
          >
            <Ionicons name="search" size={16} color={colors.sunsetOrange[600]} />
            <Text style={styles.changeDestText}>Change Destination</Text>
          </TouchableOpacity>

          {/* Map */}
          <MapView
            provider={Platform.OS === 'android' ? PROVIDER_GOOGLE : undefined}
            style={styles.map}
            region={mapRegion}
            onRegionChangeComplete={setMapRegion}
            showsUserLocation
            showsMyLocationButton={false}
          >
            {smartRoute.coordinates ? (
              <Polyline
                coordinates={smartRoute.coordinates}
                strokeColor={colors.sunsetOrange[500]}
                strokeWidth={5}
              />
            ) : null}

            {renderWeatherMarker(
              origin,
              smartRoute.weather.start,
              `Start: ${originNameState}`,
              styles.startMarker
            )}

            {smartRoute.coordinates ? renderWeatherMarker(
              smartRoute.coordinates[Math.floor(smartRoute.coordinates.length / 2)],
              smartRoute.weather.middle,
              'Midpoint',
              styles.middleMarker
            ) : null}

            {selectedDestination ? renderWeatherMarker(
              selectedDestination,
              smartRoute.weather.end,
              `Destination: ${destinationName}`,
              styles.endMarker
            ) : null}
          </MapView>

          {/* Bottom Info Card */}
          <ScrollView
            style={styles.infoCardContainer}
            contentContainerStyle={[styles.infoCard, { paddingBottom: insets.bottom + spacing.lg }]}
            showsVerticalScrollIndicator={false}
          >
            {/* Live Data Badge */}
            <View style={styles.liveBadge}>
              <View style={styles.liveIndicator} />
              <Text style={styles.liveBadgeText}>LIVE WEATHER DATA</Text>
            </View>

            {/* Route Info */}
            <View style={styles.routeInfo}>
              <View style={styles.routeEndpoints}>
                <View style={styles.endpointRow}>
                  <View style={[styles.endpointDot, { backgroundColor: colors.forestGreen[500] }]} />
                  <Text style={styles.endpointText} numberOfLines={1}>{originNameState}</Text>
                </View>
                <View style={styles.routeLine} />
                <View style={styles.endpointRow}>
                  <View style={[styles.endpointDot, { backgroundColor: colors.sunsetOrange[500] }]} />
                  <Text style={styles.endpointText} numberOfLines={1}>{destinationName}</Text>
                </View>
              </View>
              <View style={styles.routeStats}>
                <Text style={styles.distance}>{smartRoute.distance}</Text>
                <Text style={styles.duration}>{smartRoute.duration}</Text>
              </View>
            </View>

            {/* Road Risk Indicator */}
            <View style={[
              styles.roadRiskBadge,
              { backgroundColor: getRoadRiskColor(smartRoute.safety.level) }
            ]}>
              <View style={styles.roadRiskHeader}>
                <Ionicons name="shield-checkmark" size={24} color="#FFFFFF" />
                <Text style={styles.roadRiskLabel}>ROAD RISK</Text>
              </View>
              <Text style={styles.roadRiskLevel}>
                {smartRoute.safety.level.toUpperCase()}
              </Text>
              <View style={styles.roadRiskScoreContainer}>
                <Text style={styles.roadRiskScore}>{smartRoute.safety.score}</Text>
                <Text style={styles.roadRiskScoreMax}>/100</Text>
              </View>
            </View>

            {/* Weather Summary */}
            <View style={styles.weatherSummary}>
              <View style={styles.sectionHeader}>
                <Ionicons name="partly-sunny" size={20} color={colors.sunsetOrange[500]} />
                <Text style={styles.sectionTitle}>Live Weather Along Route</Text>
              </View>
              <View style={styles.weatherRow}>
                <View style={styles.weatherPoint}>
                  <View style={[styles.weatherIconContainer, { backgroundColor: COLORS.forestGreenLight }]}>
                    <Ionicons
                      name={getWeatherIconName(smartRoute.weather.start.condition) as keyof typeof Ionicons.glyphMap}
                      size={28}
                      color={COLORS.forestGreenDark}
                    />
                  </View>
                  <Text style={styles.weatherTemp}>{smartRoute.weather.start.temperature}°F</Text>
                  <Text style={styles.weatherCondition}>{smartRoute.weather.start.condition}</Text>
                  <Text style={styles.weatherLabel}>Start</Text>
                </View>
                <View style={styles.weatherDivider} />
                <View style={styles.weatherPoint}>
                  <View style={[styles.weatherIconContainer, { backgroundColor: COLORS.skyBlueLight }]}>
                    <Ionicons
                      name={getWeatherIconName(smartRoute.weather.middle.condition) as keyof typeof Ionicons.glyphMap}
                      size={28}
                      color={COLORS.skyBlueDark}
                    />
                  </View>
                  <Text style={styles.weatherTemp}>{smartRoute.weather.middle.temperature}°F</Text>
                  <Text style={styles.weatherCondition}>{smartRoute.weather.middle.condition}</Text>
                  <Text style={styles.weatherLabel}>Midpoint</Text>
                </View>
                <View style={styles.weatherDivider} />
                <View style={styles.weatherPoint}>
                  <View style={[styles.weatherIconContainer, { backgroundColor: colors.sunsetOrange[100] }]}>
                    <Ionicons
                      name={getWeatherIconName(smartRoute.weather.end.condition) as keyof typeof Ionicons.glyphMap}
                      size={28}
                      color={colors.sunsetOrange[600]}
                    />
                  </View>
                  <Text style={styles.weatherTemp}>{smartRoute.weather.end.temperature}°F</Text>
                  <Text style={styles.weatherCondition}>{smartRoute.weather.end.condition}</Text>
                  <Text style={styles.weatherLabel}>Destination</Text>
                </View>
              </View>

              {/* Wind & Humidity Details */}
              <View style={styles.weatherDetails}>
                <View style={styles.weatherDetailItem}>
                  <Ionicons name="water" size={16} color={COLORS.skyBlue} />
                  <Text style={styles.weatherDetailText}>
                    Humidity: {smartRoute.weather.start.humidity}% - {smartRoute.weather.end.humidity}%
                  </Text>
                </View>
                <View style={styles.weatherDetailItem}>
                  <Ionicons name="flag" size={16} color={COLORS.skyBlue} />
                  <Text style={styles.weatherDetailText}>
                    Wind: {smartRoute.weather.start.windSpeed} - {smartRoute.weather.end.windSpeed} mph
                  </Text>
                </View>
              </View>
            </View>

            {/* Warnings */}
            {smartRoute.safety.warnings.length > 0 ? (
              <View style={styles.warningsContainer}>
                <View style={styles.sectionHeader}>
                  <Ionicons name="warning" size={20} color={colors.sunsetOrange[600]} />
