export function getUpcomingMaintenance(rigId: string, currentMileage: number): MaintenanceRecord[] {
  return mockMaintenanceRecords
    .filter(m => m.rigId === rigId && m.isCompleted)
    .filter(m => {
      if (m.nextDueMileage && currentMileage >= m.nextDueMileage - 500) return true;
      if (m.nextDue && new Date(m.nextDue) <= new Date(Date.now() + 7 * 24 * 60 * 60 * 1000)) return true;
      return false;
    });
}

export function addMaintenanceRecord(record: Omit<MaintenanceRecord, 'id'>): MaintenanceRecord {
