export function addJournalEntry(entry: Omit<JournalEntry, 'id' | 'createdAt' | 'updatedAt'>): JournalEntry {
  const now = new Date().toISOString();
  const newEntry: JournalEntry = {
    ...entry,
    id: `journal-${Date.now()}`,
    createdAt: now,
    updatedAt: now,
  };
  mockJournalEntries.unshift(newEntry);
  return newEntry;
}

export function updateJournalEntry(entryId: string, updates: Partial<JournalEntry>): JournalEntry | null {
  const index = mockJournalEntries.findIndex(j => j.id === entryId);
  if (index >= 0) {
    mockJournalEntries[index] = {
      ...mockJournalEntries[index],
      ...updates,
      updatedAt: new Date().toISOString(),
    };
    return mockJournalEntries[index];
  }
  return null;
}

export function deleteJournalEntry(entryId: string): void {
  const index = mockJournalEntries.findIndex(j => j.id === entryId);
  if (index >= 0) {
    mockJournalEntries.splice(index, 1);
  }
}

// Stats helpers
export function getTravelStats(userId: string): {
  totalSpots: number;
  totalDays: number;
  favoriteSpots: number;
  mostVisitedType: SpotType | null;
  averageRating: number;
} {
  const spots = getPinnedSpots(userId);
  const totalDays = spots.reduce((sum, s) => sum + s.daysStayed, 0);
  const favoriteSpots = spots.filter(s => s.isFavorite).length;

  const typeCounts = spots.reduce((acc, s) => {
    acc[s.type] = (acc[s.type] || 0) + 1;
    return acc;
  }, {} as Record<SpotType, number>);

  const mostVisitedType = Object.entries(typeCounts).sort(([, a], [, b]) => b - a)[0]?.[0] as SpotType | undefined;

  const ratedSpots = spots.filter(s => s.rating);
  const averageRating = ratedSpots.length > 0
    ? ratedSpots.reduce((sum, s) => sum + (s.rating || 0), 0) / ratedSpots.length
    : 0;

  return {
    totalSpots: spots.length,
    totalDays,
    favoriteSpots,
    mostVisitedType: mostVisitedType || null,
    averageRating: Math.round(averageRating * 10) / 10,
  };
}

export function getMaintenanceStats(rigId: string): {
  totalRecords: number;
  upcomingCount: number;
  totalSpent: number;
  lastServiceDate: string | null;
} {
  const records = getMaintenanceRecords(rigId);
  const totalSpent = records.reduce((sum, r) => sum + (r.cost || 0), 0);
  const upcomingCount = getUpcomingMaintenance(rigId, 45000).length; // Mock mileage

  const sortedByDate = [...records].sort((a, b) =>
    new Date(b.date).getTime() - new Date(a.date).getTime()
  );

  return {
    totalRecords: records.length,
    upcomingCount,
    totalSpent,
    lastServiceDate: sortedByDate[0]?.date || null,
  };
}

export const nomadPassportService = {
  // Rig Specs
  getRigSpecs,
  updateRigSpecs,
  // Pinned Spots
  getPinnedSpots,
  getFavoriteSpots,
  addPinnedSpot,
  updatePinnedSpot,
  deletePinnedSpot,
  // Maintenance
  getMaintenanceRecords,
  getUpcomingMaintenance,
  addMaintenanceRecord,
  updateMaintenanceRecord,
  // Journal
  getJournalEntries,
  addJournalEntry,
  updateJournalEntry,
  deleteJournalEntry,
  // Stats
  getTravelStats,
  getMaintenanceStats,
  // Config
  spotTypeConfig,
  moodConfig,
};

export default nomadPassportService;

