/**
 * WilderGo Convoy Paywall
 * Premium frosted glass subscription UI with RevenueCat integration
 * Highlights: Full Dating Mode, Builder priority, Ghost Mode, Advanced Route Planning
 */

import React, { useState, useEffect, useRef } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
  Animated,
  Dimensions,
  Platform,
  ActivityIndicator,
  Alert,
} from 'react-native';
import { BlurView } from 'expo-blur';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { colors, typography, spacing, borderRadius, shadows, blur, natureImages } from '@/constants/theme';
import { Image } from 'expo-image';
import RevenueCatUI from 'react-native-purchases-ui';

const { height: SCREEN_HEIGHT } = Dimensions.get('window');

// Premium features for The Convoy subscription
const premiumFeatures = [
  {
    id: 'dating',
    icon: 'heart',
    emoji: '💕',
    title: 'Full Dating Mode',
    description: 'Unlock romantic connections with route-synced matches',
    gradient: [colors.ember[400], colors.ember[500], colors.ember[600]] as const,
    glow: 'rgba(214, 138, 92, 0.4)',
  },
  {
    id: 'builder',
    icon: 'construct',
    emoji: '🔧',
    title: 'Builder Priority',
    description: 'First access to top-rated rig builders and consultations',
    gradient: [colors.driftwood[400], colors.driftwood[500], colors.driftwood[600]] as const,
    glow: 'rgba(104, 92, 80, 0.4)',
  },
  {
    id: 'ghost',
    icon: 'eye-off',
    emoji: '👻',
    title: 'Ghost Mode',
    description: 'Hide your exact location while staying connected',
    gradient: [colors.sage[400], colors.sage[500], colors.sage[600]] as const,
    glow: 'rgba(90, 102, 88, 0.4)',
  },
  {
    id: 'route',
    icon: 'map',
    emoji: '🗺️',
    title: 'Advanced Routes',
    description: 'AI-powered route planning with nomad density insights',
    gradient: [colors.moss[400], colors.moss[500], colors.moss[600]] as const,
    glow: 'rgba(74, 107, 80, 0.4)',
  },
];

interface ConvoyPaywallProps {
  visible: boolean;
  onClose: () => void;
  onSubscribe?: (success: boolean) => void;
}

export const ConvoyPaywall: React.FC<ConvoyPaywallProps> = ({
  visible,
  onClose,
  onSubscribe,
}) => {
  const insets = useSafeAreaInsets();
  const [loading, setLoading] = useState(false);
  const [restoring, setRestoring] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState<'monthly' | 'annual'>('monthly');

  // Animation values
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const slideAnim = useRef(new Animated.Value(SCREEN_HEIGHT)).current;
  const scaleAnim = useRef(new Animated.Value(0.9)).current;
  const glowAnim = useRef(new Animated.Value(0)).current;

  // Feature card animations
  const featureAnims = useRef(
    premiumFeatures.map(() => new Animated.Value(0))
  ).current;

  useEffect(() => {
    if (visible) {
      // Entrance animation sequence
      Animated.parallel([
        Animated.timing(fadeAnim, {
          toValue: 1,
          duration: 300,
          useNativeDriver: true,
        }),
        Animated.spring(slideAnim, {
          toValue: 0,
          tension: 65,
          friction: 11,
          useNativeDriver: true,
        }),
        Animated.spring(scaleAnim, {
          toValue: 1,
          tension: 65,
          friction: 11,
          useNativeDriver: true,
        }),
      ]).start();

      // Staggered feature card animations
      featureAnims.forEach((anim, index) => {
        Animated.spring(anim, {
          toValue: 1,
          delay: 150 + index * 100,
          tension: 60,
          friction: 8,
          useNativeDriver: true,
        }).start();
      });

      // Continuous glow animation
      Animated.loop(
        Animated.sequence([
          Animated.timing(glowAnim, {
            toValue: 1,
            duration: 2000,
            useNativeDriver: false,
          }),
          Animated.timing(glowAnim, {
            toValue: 0.6,
            duration: 2000,
            useNativeDriver: false,
          }),
        ])
      ).start();
    } else {
      // Exit animation
      Animated.parallel([
        Animated.timing(fadeAnim, {
          toValue: 0,
          duration: 200,
          useNativeDriver: true,
        }),
        Animated.timing(slideAnim, {
          toValue: SCREEN_HEIGHT,
          duration: 200,
          useNativeDriver: true,
        }),
      ]).start();
    }
  }, [visible, fadeAnim, slideAnim, scaleAnim, glowAnim, featureAnims]);

  const handleSubscribe = async () => {
    setLoading(true);

    try {
      const result = await RevenueCatUI.presentPaywallIfNeeded({
        requiredEntitlementIdentifier: "pro",
      });

      if (result === 'PURCHASED' || result === 'RESTORED') {
        onSubscribe?.(true);
        onClose();
      }
    } catch (error: any) {
      console.log('RevenueCat UI paywall error, falling back:', error?.message);
      try {
        const Purchases = await import('react-native-purchases').then(m => m.default).catch(() => null);
        if (Purchases) {
          const offerings = await Purchases.getOfferings();
          const packages = offerings.current?.availablePackages ?? [];
          if (packages.length > 0) {
            const packageId = selectedPlan === 'annual' ? '$rc_annual' : '$rc_monthly';
            const selectedPackage = packages.find(p => p.identifier === packageId) || packages[0];
            const { customerInfo } = await Purchases.purchasePackage(selectedPackage);
            if (customerInfo.entitlements.active['pro'] || customerInfo.entitlements.active['convoy'] || customerInfo.entitlements.active['premium']) {
              onSubscribe?.(true);
              onClose();
            }
          }
        }
      } catch (fallbackError: any) {
        if (!fallbackError.userCancelled) {
          console.error('Purchase error:', fallbackError);
        }
      }
    } finally {
      setLoading(false);
    }
  };

  const handleRestore = async () => {
    setRestoring(true);

    try {
      const Purchases = await import('react-native-purchases').then(m => m.default).catch(() => null);

      if (!Purchases) {
        setRestoring(false);
        return;
      }

      const customerInfo = await Purchases.restorePurchases();

      if (customerInfo.entitlements.active['pro'] || customerInfo.entitlements.active['convoy'] || customerInfo.entitlements.active['premium']) {
        onSubscribe?.(true);
        onClose();
      }
    } catch (error: any) {
      console.error('Restore error:', error);
    } finally {
      setRestoring(false);
    }
  };

  if (!visible) return null;

  const ContainerWrapper = Platform.OS === 'ios' ? BlurView : View;

  return (
    <Animated.View
      style={[
        styles.overlay,
        {
          opacity: fadeAnim,
        },
      ]}
    >
      {/* Background Image */}
      <Image
        source={{ uri: natureImages.starryNight }}
        style={StyleSheet.absoluteFill}
        contentFit="cover"
      />
      <View style={styles.imageOverlay} />

      <Animated.View
        style={[
          styles.container,
          {
            transform: [
              { translateY: slideAnim },
              { scale: scaleAnim },
            ],
          },
        ]}
      >
        <ScrollView
          contentContainerStyle={[
            styles.scrollContent,
            { paddingTop: insets.top + spacing.lg, paddingBottom: insets.bottom + spacing.xl },
          ]}
          showsVerticalScrollIndicator={false}
        >
          {/* Close Button */}
          <TouchableOpacity
            style={styles.closeButton}
            onPress={onClose}
            activeOpacity={0.7}
          >
            <Ionicons name="close" size={24} color={colors.text.inverse} />
          </TouchableOpacity>

          {/* Premium Badge */}
          <View style={styles.premiumBadge}>
            <LinearGradient
              colors={[colors.ember[400], colors.ember[500], colors.ember[600]]}
              start={{ x: 0, y: 0 }}
              end={{ x: 1, y: 1 }}
              style={styles.premiumBadgeGradient}
            >
              <Ionicons name="star" size={16} color={colors.text.inverse} />
              <Text style={styles.premiumBadgeText}>PREMIUM</Text>
            </LinearGradient>
          </View>

          {/* Title Section */}
          <View style={styles.titleSection}>
            <Text style={styles.convoyTitle}>THE CONVOY</Text>
            <Text style={styles.convoySubtitle}>
              Unlock the full nomadic experience
            </Text>
          </View>

          {/* Feature Cards */}
          <View style={styles.featuresContainer}>
            {premiumFeatures.map((feature, index) => (
              <Animated.View
                key={feature.id}
                style={[
                  styles.featureCardWrapper,
                  {
                    opacity: featureAnims[index],
                    transform: [
                      {
                        translateY: featureAnims[index].interpolate({
                          inputRange: [0, 1],
                          outputRange: [30, 0],
                        }),
                      },
                    ],
                  },
                ]}
              >
                <ContainerWrapper
                  {...(Platform.OS === 'ios'
                    ? { tint: 'dark' as const, intensity: blur.medium, style: styles.featureCard }
                    : { style: [styles.featureCard, styles.featureCardFallback] }
                  )}
                >
                  <View style={styles.featureContent}>
                    <LinearGradient
                      colors={feature.gradient as unknown as [string, string, ...string[]]}
                      style={styles.featureIconContainer}
                    >
                      <Text style={styles.featureEmoji}>{feature.emoji}</Text>
                    </LinearGradient>
                    <View style={styles.featureTextContainer}>
                      <Text style={styles.featureTitle}>{feature.title}</Text>
                      <Text style={styles.featureDescription}>{feature.description}</Text>
                    </View>
                    <Ionicons name="checkmark-circle" size={22} color={colors.moss[400]} />
                  </View>
                </ContainerWrapper>
              </Animated.View>
            ))}
          </View>

          {/* Pricing Section */}
          <ContainerWrapper
            {...(Platform.OS === 'ios'
              ? { tint: 'light' as const, intensity: blur.heavy, style: styles.pricingCard }
              : { style: [styles.pricingCard, styles.pricingCardFallback] }
            )}
          >
            {/* Plan Toggle */}
            <View style={styles.planToggle}>
              <TouchableOpacity
                style={[
                  styles.planOption,
                  selectedPlan === 'monthly' && styles.planOptionSelected,
                ]}
                onPress={() => setSelectedPlan('monthly')}
                activeOpacity={0.7}
              >
                <Text style={[
                  styles.planOptionText,
                  selectedPlan === 'monthly' && styles.planOptionTextSelected,
                ]}>
                  Monthly
                </Text>
              </TouchableOpacity>
              <TouchableOpacity
                style={[
                  styles.planOption,
                  selectedPlan === 'annual' && styles.planOptionSelected,
                ]}
                onPress={() => setSelectedPlan('annual')}
                activeOpacity={0.7}
              >
                <Text style={[
                  styles.planOptionText,
                  selectedPlan === 'annual' && styles.planOptionTextSelected,
                ]}>
                  Annual
                </Text>
                <View style={styles.saveBadge}>
                  <Text style={styles.saveBadgeText}>SAVE 33%</Text>
                </View>
              </TouchableOpacity>
            </View>

            {/* Price Display */}
            <View style={styles.priceContainer}>
              <Text style={styles.priceAmount}>
                {selectedPlan === 'monthly' ? '$9.99' : '$79.99'}
              </Text>
              <Text style={styles.pricePeriod}>
                /{selectedPlan === 'monthly' ? 'month' : 'year'}
              </Text>
            </View>

            {selectedPlan === 'annual' && (
              <Text style={styles.monthlyBreakdown}>
                Just $6.67/month billed annually
              </Text>
            )}

            {/* Subscribe Button */}
            <TouchableOpacity
              style={styles.subscribeButton}
              onPress={handleSubscribe}
              activeOpacity={0.85}
              disabled={loading}
            >
              <LinearGradient
                colors={[colors.ember[400], colors.ember[500], colors.ember[600]]}
                start={{ x: 0, y: 0 }}
                end={{ x: 1, y: 0 }}
                style={styles.subscribeButtonGradient}
              >
                {loading ? (
                  <ActivityIndicator size="small" color={colors.text.inverse} />
                ) : (
                  <>
                    <Text style={styles.subscribeButtonText}>JOIN THE CONVOY</Text>
                    <Ionicons name="arrow-forward" size={20} color={colors.text.inverse} />
                  </>
                )}
              </LinearGradient>
            </TouchableOpacity>

            {/* Restore Purchases */}
            <TouchableOpacity
              style={styles.restoreButton}
              onPress={handleRestore}
              disabled={restoring}
            >
              {restoring ? (
                <ActivityIndicator size="small" color={colors.bark[400]} />
              ) : (
                <Text style={styles.restoreButtonText}>Restore Purchases</Text>
              )}
            </TouchableOpacity>

            {/* Terms */}
            <Text style={styles.termsText}>
              Cancel anytime. Subscription auto-renews until cancelled.
            </Text>
          </ContainerWrapper>

          {/* Trust Indicators */}
          <View style={styles.trustSection}>
            <View style={styles.trustItem}>
              <Ionicons name="shield-checkmark" size={18} color={colors.moss[400]} />
              <Text style={styles.trustText}>Secure Payment</Text>
            </View>
            <View style={styles.trustItem}>
              <Ionicons name="refresh" size={18} color={colors.moss[400]} />
              <Text style={styles.trustText}>Cancel Anytime</Text>
            </View>
            <View style={styles.trustItem}>
              <Ionicons name="people" size={18} color={colors.moss[400]} />
              <Text style={styles.trustText}>10K+ Nomads</Text>
            </View>
          </View>
        </ScrollView>
      </Animated.View>
    </Animated.View>
  );
};

const styles = StyleSheet.create({
  overlay: {
    ...StyleSheet.absoluteFillObject,
