              </View>
              <TouchableOpacity onPress={() => setShowIcebreakerModal(false)}>
                <Ionicons name="close" size={24} color={colors.bark[600]} />
              </TouchableOpacity>
            </View>

            <Text style={styles.modalDescription}>
              Generate a personalized introduction message to break the ice with your convoy!
            </Text>

            {generatedIcebreaker ? (
              <View style={styles.icebreakerResult}>
                <Text style={styles.icebreakerText}>{generatedIcebreaker}</Text>
                <View style={styles.icebreakerActions}>
                  <TouchableOpacity
                    style={styles.icebreakerUseButton}
