                      setShowIcebreakerModal(false);
                      setGeneratedIcebreaker('');
                    }}
                  >
                    <Text style={styles.icebreakerUseText}>Use This</Text>
                  </TouchableOpacity>
                  <TouchableOpacity
                    style={styles.icebreakerRegenerateButton}
                    onPress={() => {
                      const icebreakers = [
                        "Hey everyone! Just rolled into the area with my Sprinter. Anyone know a good spot with decent cell service? Would love to meet up!",
                        "New to the convoy! I'm traveling with my pup and always looking for dog-friendly trails. What's everyone's favorite local hike?",
                        "Greetings fellow nomads! I'm parked up near the hot springs. Who's up for a sunset soak later?",
                      ];
                      setGeneratedIcebreaker(icebreakers[Math.floor(Math.random() * icebreakers.length)]);
                    }}
                  >
                    <Ionicons name="refresh" size={16} color={colors.bark[600]} />
                  </TouchableOpacity>
                </View>
              </View>
            ) : (
              <TouchableOpacity
                style={styles.modalButton}
                onPress={() => {
                  const icebreakers = [
                    "Hey everyone! Just rolled into the area with my Sprinter. Anyone know a good spot with decent cell service? Would love to meet up!",
                    "New to the convoy! I'm traveling with my pup and always looking for dog-friendly trails. What's everyone's favorite local hike?",
                    "Greetings fellow nomads! I'm parked up near the hot springs. Who's up for a sunset soak later?",
                  ];
                  setGeneratedIcebreaker(icebreakers[Math.floor(Math.random() * icebreakers.length)]);
                }}
              >
                <Ionicons name="sparkles" size={18} color={colors.text.inverse} />
                <Text style={styles.modalButtonText}>Generate Icebreaker</Text>
              </TouchableOpacity>
            )}
          </View>
        </View>
      </Modal>
    </View>
  );
}

