/**
 * WilderGo Advanced Map Service
 * Handles Weather Layer, Campfire Clustering, and Liquid Ripple effects
 */

import { colors, socialLayer, mapboxConfig, animations, markerTypes } from '@/constants/theme';
import { MapMarkerData, getMarkersForMode, AppMode } from './mapService';

// ============================================
// WEATHER LAYER TYPES & DATA
// ============================================

export type WeatherCondition = 'clear' | 'cloudy' | 'rain' | 'storm' | 'snow' | 'windy' | 'fog';

export interface WeatherData {
  id: string;
  latitude: number;
  longitude: number;
  condition: WeatherCondition;
  temperature: number; // Fahrenheit
  humidity: number; // Percentage
  windSpeed: number; // mph
  windDirection: string;
  feelsLike: number;
  uvIndex: number;
  visibility: number; // miles
  timestamp: string;
  forecast?: WeatherForecast[];
}

export interface WeatherForecast {
  day: string;
  high: number;
  low: number;
  condition: WeatherCondition;
  precipChance: number;
}

export interface WeatherAlert {
  id: string;
  type: 'warning' | 'advisory' | 'watch';
  title: string;
  description: string;
  severity: 'minor' | 'moderate' | 'severe' | 'extreme';
  affectedArea: { latitude: number; longitude: number; radius: number };
  expiresAt: string;
}

// Weather condition configuration
