import { useNavigation, NavigationProp, CommonActions } from '@react-navigation/native';

type RootParamList = Record<string, object | undefined>;

const routeMap: Record<string, string> = {
  'welcome': 'Welcome',
  'create-account': 'CreateAccount',
  'email-verification': 'EmailVerification',
  'selfie-verify': 'SelfieVerify',
  'vehicle-select': 'VehicleSelect',
  'nomad-style': 'NomadStyle',
  'complete': 'Complete',
  'paywall': 'Paywall',
  'discovery': 'Discovery',
  'map': 'Map',
  'messages': 'Messages',
  'profile': 'Profile',
  'help': 'Help',
  'dm-chat': 'dm-chat',
};

function resolveRouteName(path: string): string {
  let cleaned = path
    .replace(/^\/?(\(tabs\)|\(onboarding\))\//, '')
    .replace(/^\//, '');

  if (routeMap[cleaned]) {
    return routeMap[cleaned];
  }

  return cleaned;
}

export function useRouter() {
  const navigation = useNavigation<NavigationProp<RootParamList>>();

  return {
    push: (path: string, params?: Record<string, unknown>) => {
      const routeName = resolveRouteName(path);
      navigation.navigate(routeName, params);
    },
    replace: (path: string, params?: Record<string, unknown>) => {
      const routeName = resolveRouteName(path);
      navigation.dispatch(
        CommonActions.reset({
          index: 0,
          routes: [{ name: routeName, params }],
        })
      );
    },
    back: () => {
      if (navigation.canGoBack()) {
        navigation.goBack();
      }
    },
    canGoBack: () => navigation.canGoBack(),
  };
}

