client/components/builder/BuilderService.content:
/**
 * WilderGo Builder Service HUD
 * Professional marketplace component showing build history, expertise, and consultation booking
 * Part of the Builder Mode marketplace with verified professional network
 */

import React, { useState, useRef, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
  Animated,
  Dimensions,
  Platform,
} from 'react-native';
import { BlurView } from 'expo-blur';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import { Image } from 'expo-image';
import { colors, typography, spacing, borderRadius, shadows, blur } from '@/constants/theme';
import { GlassCard } from '@/components/ui/GlassCard';

const { width: SCREEN_WIDTH } = Dimensions.get('window');

interface BuildProject {
  id: string;
  title: string;
  vehicleType: string;
  completionDate: string;
  imageUrl: string;
  rating: number;
  features: string[];
}

interface Certification {
  id: string;
  name: string;
  issuer: string;
  icon: keyof typeof Ionicons.glyphMap;
}

interface BuilderService {
  id: string;
  name: string;
  description: string;
  price: string;
  duration: string;
  icon: keyof typeof Ionicons.glyphMap;
  popular?: boolean;
}

interface BuilderData {
  id: string;
  name: string;
  businessName: string;
  avatarUrl: string;
  coverImageUrl: string;
  location: string;
  rating: number;
  reviewCount: number;
  verified: boolean;
  yearsExperience: number;
  buildsCompleted: number;
  responseTime: string;
  specialties: string[];
  certifications: Certification[];
  services: BuilderService[];
  portfolio: BuildProject[];
  bio: string;
  availability: 'available' | 'limited' | 'booked';
}

interface BuilderServiceHUDProps {
  builder: BuilderData;
  onBookConsultation?: () => void;
  onViewPortfolio?: () => void;
  onMessage?: () => void;
  onRequestQuote?: (service: BuilderService) => void;
}

const availabilityConfig = {
  available: {
    color: colors.moss[500],
    label: 'Available Now',
    icon: 'checkmark-circle' as const,
  },
  limited: {
    color: colors.ember[500],
    label: 'Limited Slots',
    icon: 'time' as const,
  },
  booked: {
    color: colors.bark[400],
    label: 'Fully Booked',
    icon: 'close-circle' as const,
  },
};

export const BuilderServiceHUD: React.FC<BuilderServiceHUDProps> = ({
  builder,
  onBookConsultation,
  onViewPortfolio,
  onMessage,
  onRequestQuote,
}) => {
  const [activeTab, setActiveTab] = useState<'services' | 'portfolio' | 'reviews'>('services');
  const tabIndicatorAnim = useRef(new Animated.Value(0)).current;
  const statsAnims = useRef([
    new Animated.Value(0),
    new Animated.Value(0),
    new Animated.Value(0),
    new Animated.Value(0),
  ]).current;

  const availability = availabilityConfig[builder.availability];

  useEffect(() => {
    // Animate stats on mount
    statsAnims.forEach((anim, index) => {
      Animated.spring(anim, {
        toValue: 1,
        delay: index * 100,
        tension: 60,
        friction: 8,
        useNativeDriver: true,
      }).start();
    });
  }, [statsAnims]);

  useEffect(() => {
    const tabIndex = activeTab === 'services' ? 0 : activeTab === 'portfolio' ? 1 : 2;
    Animated.spring(tabIndicatorAnim, {
      toValue: tabIndex,
      tension: 120,
      friction: 12,
      useNativeDriver: true,
    }).start();
  }, [activeTab, tabIndicatorAnim]);

  const ContainerWrapper = Platform.OS === 'ios' ? BlurView : View;
  const tabWidth = (SCREEN_WIDTH - spacing.xl * 2) / 3;

  return (
    <ScrollView
      style={styles.container}
      showsVerticalScrollIndicator={false}
    >
      {/* Hero Header */}
      <View style={styles.heroSection}>
        <Image
          source={{ uri: builder.coverImageUrl }}
          style={styles.coverImage}
          contentFit="cover"
        />
        <LinearGradient
          colors={['transparent', 'rgba(0,0,0,0.8)']}
          style={styles.coverGradient}
        />

        {/* Builder Avatar & Info */}
        <View style={styles.heroContent}>
          <View style={styles.avatarContainer}>
            <Image
              source={{ uri: builder.avatarUrl }}
              style={styles.avatar}
              contentFit="cover"
            />
            {builder.verified && (
              <View style={styles.verifiedBadge}>
                <Ionicons name="shield-checkmark" size={14} color={colors.moss[500]} />
              </View>
            )}
          </View>

          <View style={styles.heroInfo}>
            <Text style={styles.businessName}>{builder.businessName}</Text>
            <Text style={styles.builderName}>{builder.name}</Text>
            <View style={styles.locationRow}>
              <Ionicons name="location" size={14} color={colors.text.inverse} />
              <Text style={styles.locationText}>{builder.location}</Text>
            </View>
          </View>

          {/* Availability Badge */}
          <View style={[styles.availabilityBadge, { backgroundColor: availability.color + '20' }]}>
            <Ionicons name={availability.icon} size={14} color={availability.color} />
            <Text style={[styles.availabilityText, { color: availability.color }]}>
              {availability.label}
            </Text>
          </View>
        </View>
      </View>

      {/* Stats Row */}
      <View style={styles.statsRow}>
        {[
          { value: builder.rating.toFixed(1), label: 'Rating', icon: 'star' },
          { value: `${builder.buildsCompleted}+`, label: 'Builds', icon: 'construct' },
          { value: `${builder.yearsExperience}yr`, label: 'Experience', icon: 'calendar' },
          { value: builder.responseTime, label: 'Response', icon: 'time' },
        ].map((stat, index) => (
          <Animated.View
            key={stat.label}
            style={[
              styles.statItem,
              {
                opacity: statsAnims[index],
                transform: [
                  {
                    translateY: statsAnims[index].interpolate({
                      inputRange: [0, 1],
                      outputRange: [20, 0],
                    }),
                  },
                ],
              },
            ]}
          >
            <ContainerWrapper
              {...(Platform.OS === 'ios'
                ? { tint: 'light' as const, intensity: blur.medium, style: styles.statCard }
                : { style: [styles.statCard, styles.statCardFallback] }
              )}
            >
              <Ionicons
                name={stat.icon as keyof typeof Ionicons.glyphMap}
                size={16}
                color={colors.driftwood[500]}
              />
              <Text style={styles.statValue}>{stat.value}</Text>
              <Text style={styles.statLabel}>{stat.label}</Text>
            </ContainerWrapper>
          </Animated.View>
        ))}
      </View>

      {/* Quick Actions */}
      <View style={styles.actionsRow}>
        <TouchableOpacity
          style={styles.primaryAction}
          onPress={onBookConsultation}
          activeOpacity={0.85}
        >
          <LinearGradient
            colors={[colors.driftwood[400], colors.driftwood[500], colors.driftwood[600]]}
            style={styles.primaryActionGradient}
          >
            <Ionicons name="videocam" size={20} color={colors.text.inverse} />
            <Text style={styles.primaryActionText}>Book Consultation</Text>
          </LinearGradient>
        </TouchableOpacity>

        <TouchableOpacity
          style={styles.secondaryAction}
          onPress={onMessage}
          activeOpacity={0.7}
        >
          <Ionicons name="chatbubble-outline" size={20} color={colors.driftwood[600]} />
        </TouchableOpacity>
      </View>

      {/* Specialties */}
      <GlassCard variant="light" padding="lg" style={styles.section}>
        <Text style={styles.sectionTitle}>Specialties</Text>
        <View style={styles.specialtiesGrid}>
          {builder.specialties.map((specialty, index) => (
            <View key={index} style={styles.specialtyChip}>
              <Text style={styles.specialtyText}>{specialty}</Text>
            </View>
          ))}
        </View>
      </GlassCard>

      {/* Certifications */}
      {builder.certifications.length > 0 && (
        <GlassCard variant="light" padding="lg" style={styles.section}>
          <Text style={styles.sectionTitle}>Certifications</Text>
          <View style={styles.certificationsContainer}>
            {builder.certifications.map((cert) => (
              <View key={cert.id} style={styles.certificationItem}>
                <View style={styles.certificationIcon}>
                  <Ionicons name={cert.icon} size={18} color={colors.moss[500]} />
                </View>
                <View style={styles.certificationInfo}>
                  <Text style={styles.certificationName}>{cert.name}</Text>
                  <Text style={styles.certificationIssuer}>{cert.issuer}</Text>
                </View>
                <Ionicons name="checkmark-circle" size={18} color={colors.moss[500]} />
              </View>
            ))}
          </View>
        </GlassCard>
      )}

      {/* Tab Navigation */}
      <View style={styles.tabContainer}>
        <View style={styles.tabBar}>
          <Animated.View
            style={[
              styles.tabIndicator,
              {
                width: tabWidth - spacing.sm,
                transform: [
                  {
                    translateX: tabIndicatorAnim.interpolate({
                      inputRange: [0, 1, 2],
                      outputRange: [spacing.xs, tabWidth + spacing.xs, tabWidth * 2 + spacing.xs],
                    }),
                  },
                ],
              },
            ]}
          />
          {(['services', 'portfolio', 'reviews'] as const).map((tab) => (
            <TouchableOpacity
              key={tab}
              style={[styles.tab, { width: tabWidth }]}
              onPress={() => setActiveTab(tab)}
              activeOpacity={0.7}
            >
              <Text
                style={[
                  styles.tabText,
                  activeTab === tab && styles.tabTextActive,
                ]}
              >
                {tab.charAt(0).toUpperCase() + tab.slice(1)}
              </Text>
            </TouchableOpacity>
          ))}
        </View>
      </View>

      {/* Tab Content */}
      {activeTab === 'services' && (
        <View style={styles.tabContent}>
          {builder.services.map((service) => (
            <GlassCard key={service.id} variant="frost" padding="lg" style={styles.serviceCard}>
              <View style={styles.serviceHeader}>
                <View style={styles.serviceIconContainer}>
                  <Ionicons name={service.icon} size={22} color={colors.driftwood[500]} />
                </View>
                <View style={styles.serviceInfo}>
                  <View style={styles.serviceNameRow}>
                    <Text style={styles.serviceName}>{service.name}</Text>
                    {service.popular && (
                      <View style={styles.popularBadge}>
                        <Text style={styles.popularText}>Popular</Text>
                      </View>
                    )}
                  </View>
                  <Text style={styles.serviceDescription}>{service.description}</Text>
                </View>
              </View>
              <View style={styles.serviceFooter}>
                <View style={styles.serviceMeta}>
                  <Text style={styles.servicePrice}>{service.price}</Text>
                  <Text style={styles.serviceDuration}>{service.duration}</Text>
                </View>
                <TouchableOpacity
                  style={styles.requestQuoteButton}
                  onPress={() => onRequestQuote?.(service)}
                  activeOpacity={0.8}
                >
                  <Text style={styles.requestQuoteText}>Request Quote</Text>
                  <Ionicons name="arrow-forward" size={14} color={colors.driftwood[600]} />
                </TouchableOpacity>
              </View>
            </GlassCard>
          ))}
        </View>
      )}

      {activeTab === 'portfolio' && (
        <View style={styles.tabContent}>
          <View style={styles.portfolioGrid}>
            {builder.portfolio.map((project) => (
              <TouchableOpacity
                key={project.id}
                style={styles.portfolioCard}
                onPress={onViewPortfolio}
                activeOpacity={0.9}
              >
                <Image
                  source={{ uri: project.imageUrl }}
                  style={styles.portfolioImage}
                  contentFit="cover"
                />
                <LinearGradient
                  colors={['transparent', 'rgba(0,0,0,0.85)']}
                  style={styles.portfolioOverlay}
                >
                  <Text style={styles.portfolioTitle}>{project.title}</Text>
                  <Text style={styles.portfolioType}>{project.vehicleType}</Text>
                  <View style={styles.portfolioRating}>
                    <Ionicons name="star" size={12} color={colors.ember[400]} />
                    <Text style={styles.portfolioRatingText}>{project.rating}</Text>
                  </View>
                </LinearGradient>
              </TouchableOpacity>
            ))}
          </View>
          <TouchableOpacity
            style={styles.viewAllButton}
            onPress={onViewPortfolio}
            activeOpacity={0.8}
          >
            <Text style={styles.viewAllText}>View Full Portfolio</Text>
            <Ionicons name="arrow-forward" size={16} color={colors.driftwood[600]} />
          </TouchableOpacity>
        </View>
      )}

      {activeTab === 'reviews' && (
        <View style={styles.tabContent}>
          <View style={styles.reviewsSummary}>
            <Text style={styles.reviewsRating}>{builder.rating.toFixed(1)}</Text>
            <View style={styles.reviewsStars}>
              {[1, 2, 3, 4, 5].map((star) => (
                <Ionicons
                  key={star}
                  name={star <= Math.round(builder.rating) ? 'star' : 'star-outline'}
                  size={20}
                  color={colors.ember[400]}
                />
              ))}
            </View>
            <Text style={styles.reviewsCount}>Based on {builder.reviewCount} reviews</Text>
          </View>

          {/* Placeholder for reviews */}
          <GlassCard variant="frost" padding="lg" style={styles.reviewCard}>
            <View style={styles.reviewHeader}>
              <View style={styles.reviewerAvatar}>
                <Text style={styles.reviewerInitial}>J</Text>
              </View>
              <View style={styles.reviewerInfo}>
                <Text style={styles.reviewerName}>Jake M.</Text>
                <View style={styles.reviewStars}>
                  {[1, 2, 3, 4, 5].map((star) => (
                    <Ionicons key={star} name="star" size={12} color={colors.ember[400]} />
                  ))}
                </View>
              </View>
              <Text style={styles.reviewDate}>2 weeks ago</Text>
            </View>
            <Text style={styles.reviewText}>
              Incredible work on my Sprinter build! Attention to detail was amazing and they really
              understood the nomadic lifestyle. Highly recommend for any conversion project.
            </Text>
          </GlassCard>
        </View>
      )}

      {/* Bio */}
      <GlassCard variant="light" padding="lg" style={styles.bioSection}>
        <Text style={styles.sectionTitle}>About</Text>
        <Text style={styles.bioText}>{builder.bio}</Text>
      </GlassCard>

      {/* Bottom padding */}
      <View style={{ height: spacing['3xl'] }} />
    </ScrollView>
  );
};

