    name: string;
  };
  nomads: FutureNomad[];
  events: FutureEvent[];
  nomadicDensity: 'low' | 'medium' | 'high';
  recommendation?: string;
}

export interface RouteOverlapNotification {
  id: string;
  type: 'route_overlap' | 'upcoming_event' | 'convoy_forming' | 'high_match';
  title: string;
  description: string;
  matchPercentage?: number;
  relatedUser?: {
