const getWeatherIcon = (condition: WeatherCondition): keyof typeof Ionicons.glyphMap => {
  const icons: Record<WeatherCondition, keyof typeof Ionicons.glyphMap> = {
    sunny: 'sunny',
    cloudy: 'cloudy',
    rainy: 'rainy',
    snowy: 'snow',
    stormy: 'thunderstorm',
    windy: 'flag',
    foggy: 'cloud',
    partlyCloudy: 'partly-sunny',
    clear: 'moon',
  };
  return icons[condition];
};

const getCellServiceDisplay = (quality: CellServiceQuality) => {
  const displays: Record<CellServiceQuality, { icon: keyof typeof Ionicons.glyphMap; color: string; label: string; bars: number }> = {
    good: { icon: 'cellular', color: colors.forestGreen[500], label: 'Good', bars: 4 },
    fair: { icon: 'cellular', color: colors.sunsetOrange[400], label: 'Fair', bars: 2 },
    bad: { icon: 'cellular', color: colors.sunsetOrange[600], label: 'Bad', bars: 1 },
    none: { icon: 'cellular', color: colors.bark[400], label: 'None', bars: 0 },
  };
  return displays[quality];
};

