interface OutdoorEventsProps {
  onEventSelect?: (event: OutdoorEvent) => void;
}

export function OutdoorEvents({ onEventSelect }: OutdoorEventsProps) {
  const [selectedFilter, setSelectedFilter] = useState<ActivityType | 'all'>('all');
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<OutdoorEvent | null>(null);

  const filteredEvents = selectedFilter === 'all' 
    ? sampleEvents 
    : sampleEvents.filter(e => e.activityType === selectedFilter);

  const filters: (ActivityType | 'all')[] = ['all', 'backpacking', 'mtb', 'ski', 'snowboard', 'climb', 'camp', 'fishing', 'kayak', 'sup', 'surf', 'offroad', 'motorcycle', 'explore'];

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.title}>Nomad Meetups</Text>
        <TouchableOpacity 
          style={styles.createButton}
          onPress={() => setShowCreateModal(true)}
        >
          <Ionicons name="add" size={20} color="#FFFFFF" />
          <Text style={styles.createButtonText}>Host</Text>
        </TouchableOpacity>
      </View>

      <ScrollView 
        horizontal 
        showsHorizontalScrollIndicator={false}
        contentContainerStyle={styles.filterScroll}
      >
        {filters.map((filter) => (
          <TouchableOpacity
            key={filter}
            style={[
              styles.filterChip,
              selectedFilter === filter && styles.filterChipActive,
            ]}
            onPress={() => setSelectedFilter(filter)}
          >
            {filter !== 'all' && (
              <Ionicons 
                name={activityIcons[filter]} 
                size={14} 
                color={selectedFilter === filter ? '#FFFFFF' : colors.bark[500]} 
              />
            )}
            <Text style={[
              styles.filterChipText,
              selectedFilter === filter && styles.filterChipTextActive,
            ]}>
              {filter === 'all' ? 'All' : activityLabels[filter]}
            </Text>
          </TouchableOpacity>
        ))}
      </ScrollView>

      <ScrollView 
        horizontal 
        showsHorizontalScrollIndicator={false}
        contentContainerStyle={styles.eventsScroll}
      >
        {filteredEvents.map((event) => (
          <TouchableOpacity
            key={event.id}
            style={styles.eventCard}
            onPress={() => setSelectedEvent(event)}
            activeOpacity={0.9}
          >
            <Image
              source={{ uri: event.imageUrl }}
              style={styles.eventImage}
              contentFit="cover"
            />
            <View style={styles.eventBadge}>
              <Ionicons name={activityIcons[event.activityType]} size={12} color="#FFFFFF" />
              <Text style={styles.eventBadgeText}>{activityLabels[event.activityType]}</Text>
            </View>
            <View style={[styles.skillBadge, { backgroundColor: skillLevelColors[event.skillLevel] }]}>
              <Text style={styles.skillBadgeText}>{skillLevelLabels[event.skillLevel]}</Text>
            </View>
            {event.weather ? (
              <View style={styles.weatherBadgeContainer}>
                <View style={[styles.weatherBadge, { backgroundColor: impactRatingColors[event.weather.impactRating] }]}>
                  <Ionicons 
                    name={getWeatherIcon(event.weather.condition)} 
                    size={12} 
                    color="#FFFFFF" 
                  />
                  <Text style={styles.weatherBadgeTemp}>{event.weather.temperature}°</Text>
                </View>
                {event.weather.alerts && event.weather.alerts.length > 0 ? (
                  <View style={[styles.alertIndicator, { backgroundColor: event.weather.alerts[0].severity === 'danger' ? '#EF4444' : '#F59E0B' }]}>
                    <Ionicons name="warning" size={10} color="#FFFFFF" />
                  </View>
                ) : null}
              </View>
            ) : null}
            <View style={styles.eventContent}>
              <Text style={styles.eventTitle} numberOfLines={2}>{event.title}</Text>
              <View style={styles.eventMeta}>
                <View style={styles.eventMetaRow}>
                  <Ionicons name="location" size={12} color={colors.bark[400]} />
                  <Text style={styles.eventMetaText}>{event.location}</Text>
                </View>
                <View style={styles.eventMetaRow}>
                  <Ionicons name="calendar" size={12} color={colors.bark[400]} />
                  <Text style={styles.eventMetaText}>{event.date}</Text>
                </View>
              </View>
              {event.weather ? (
                <View style={styles.eventWeatherPreview}>
                  <Text style={[styles.weatherImpactLabel, { color: impactRatingColors[event.weather.impactRating] }]}>
                    {event.weather.impactRating.charAt(0).toUpperCase() + event.weather.impactRating.slice(1)} Conditions
                  </Text>
                  {event.weather.alerts && event.weather.alerts.length > 0 ? (
                    <Text style={styles.alertPreviewText} numberOfLines={1}>
                      {event.weather.alerts[0].title}
                    </Text>
                  ) : null}
                </View>
              ) : null}
              <View style={styles.eventHostRow}>
                <View style={styles.eventHost}>
                  <Image
                    source={{ uri: event.hostImage }}
                    style={styles.hostAvatar}
                    contentFit="cover"
                  />
                  <Text style={styles.hostName}>Hosted by {event.hostName}</Text>
                </View>
                {event.cellService ? (
                  <View style={[styles.cellServiceBadge, { backgroundColor: getCellServiceDisplay(event.cellService).color + '20' }]}>
                    <Ionicons 
                      name={getCellServiceDisplay(event.cellService).icon} 
                      size={12} 
                      color={getCellServiceDisplay(event.cellService).color} 
                    />
                    <Text style={[styles.cellServiceText, { color: getCellServiceDisplay(event.cellService).color }]}>
                      {getCellServiceDisplay(event.cellService).label}
                    </Text>
                  </View>
                ) : null}
              </View>
              <View style={styles.attendeeBar}>
                <View style={[styles.attendeeFill, { width: `${(event.currentAttendees / event.maxAttendees) * 100}%` }]} />
              </View>
              <Text style={styles.attendeeText}>
                {event.currentAttendees}/{event.maxAttendees} spots filled
              </Text>
            </View>
          </TouchableOpacity>
        ))}
      </ScrollView>

      <EventDetailModal
        event={selectedEvent}
        visible={selectedEvent !== null}
        onClose={() => setSelectedEvent(null)}
      />

      <CreateEventModal
        visible={showCreateModal}
        onClose={() => setShowCreateModal(false)}
      />
    </View>
  );
}

