                  <Ionicons name="moon" size={16} color={colors.bark[400]} />
                  <Text style={styles.sunMoonLabel}>Moon</Text>
                  <Text style={styles.sunMoonValue}>{event.weather.moonPhase}</Text>
                </View>
              </View>
