                  <Text style={styles.lightingBadgeText}>Golden Hour</Text>
                </View>
                <Text style={styles.lightingTimeText}>
                  {event.weather.goldenHour.start} - {event.weather.goldenHour.end}
                </Text>
              </View>
            ) : null}

            {event.weather.blueHour ? (
              <View style={styles.lightingInfoRow}>
                <View style={styles.blueHourBadge}>
                  <Ionicons name="moon" size={12} color="#FFFFFF" />
                  <Text style={styles.lightingBadgeText}>Blue Hour</Text>
                </View>
                <Text style={styles.lightingTimeText}>
                  {event.weather.blueHour.start} - {event.weather.blueHour.end}
                </Text>
              </View>
            ) : null}

            {event.weather.stargazingRating ? (
              <View style={styles.stargazingInfoRow}>
                <Ionicons name="star" size={16} color={colors.bark[400]} />
                <Text style={styles.stargazingLabel}>Stargazing Conditions:</Text>
                <Text style={[styles.stargazingRating, { color: impactRatingColors[event.weather.stargazingRating] }]}>
                  {event.weather.stargazingRating.charAt(0).toUpperCase() + event.weather.stargazingRating.slice(1)}
                </Text>
              </View>
            ) : null}
          </>
        ) : null}

        <TouchableOpacity style={styles.joinButton}>
          <Ionicons name="add-circle" size={20} color="#FFFFFF" />
          <Text style={styles.joinButtonText}>Join This Adventure</Text>
        </TouchableOpacity>
      </View>
    </ScrollView>
  );

  return (
    <Modal visible={visible} animationType="slide" transparent onRequestClose={onClose}>
      <View style={styles.modalOverlay}>
        {Platform.OS === 'ios' ? (
          <BlurView intensity={90} tint="dark" style={styles.detailModal}>
            <ModalContent />
          </BlurView>
        ) : (
          <View style={[styles.detailModal, styles.modalFallback]}>
            <ModalContent />
          </View>
        )}
      </View>
    </Modal>
  );
}

interface CreateEventModalProps {
  visible: boolean;
  onClose: () => void;
}

function CreateEventModal({ visible, onClose }: CreateEventModalProps) {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    activityType: 'backpacking' as ActivityType,
    skillLevel: 'intermediate' as SkillLevel,
    location: '',
    date: '',
    time: '',
    maxAttendees: '8',
    schedule: '',
  });

  const activityOptions: ActivityType[] = ['backpacking', 'mtb', 'fishing', 'ski', 'snowboard', 'kayak', 'sup', 'surf', 'climb', 'camp', 'offroad', 'motorcycle', 'dirtbike', 'snowmobile', 'explore'];

  const handleCreate = () => {
    onClose();
  };

  const ModalContent = () => (
    <ScrollView showsVerticalScrollIndicator={false}>
      <View style={styles.createHeader}>
        <Text style={styles.createTitle}>Host a Nomad Meetup</Text>
        <TouchableOpacity onPress={onClose} style={styles.closeCreateButton}>
          <Ionicons name="close" size={24} color="#FFFFFF" />
        </TouchableOpacity>
      </View>

      <View style={styles.formGroup}>
        <Text style={styles.formLabel}>Activity Type</Text>
        <ScrollView horizontal showsHorizontalScrollIndicator={false}>
          <View style={styles.activitySelector}>
            {activityOptions.map((activity) => (
              <TouchableOpacity
                key={activity}
                style={[
                  styles.activityOption,
                  formData.activityType === activity && styles.activityOptionActive,
                ]}
                onPress={() => setFormData(prev => ({ ...prev, activityType: activity }))}
              >
                <Ionicons 
                  name={activityIcons[activity]} 
                  size={20} 
                  color={formData.activityType === activity ? '#FFFFFF' : colors.bark[400]} 
                />
                <Text style={[
                  styles.activityOptionText,
                  formData.activityType === activity && styles.activityOptionTextActive,
                ]}>
                  {activityLabels[activity]}
                </Text>
              </TouchableOpacity>
            ))}
          </View>
        </ScrollView>
      </View>

      <View style={styles.formGroup}>
        <Text style={styles.formLabel}>Skill Level</Text>
        <View style={styles.skillSelector}>
          {(['beginner', 'intermediate', 'advanced'] as SkillLevel[]).map((level) => (
            <TouchableOpacity
              key={level}
              style={[
                styles.skillOption,
                formData.skillLevel === level && { backgroundColor: skillLevelColors[level] },
              ]}
              onPress={() => setFormData(prev => ({ ...prev, skillLevel: level }))}
            >
              <Text style={[
                styles.skillOptionText,
                formData.skillLevel === level && styles.skillOptionTextActive,
              ]}>
                {skillLevelLabels[level]}
              </Text>
            </TouchableOpacity>
          ))}
        </View>
      </View>

      <View style={styles.formGroup}>
        <Text style={styles.formLabel}>Event Title</Text>
        <TextInput
          style={styles.formInput}
          value={formData.title}
          onChangeText={(text) => setFormData(prev => ({ ...prev, title: text }))}
          placeholder="e.g., Sunrise Photography at the Dunes"
          placeholderTextColor={colors.bark[300]}
        />
      </View>

      <View style={styles.formGroup}>
        <Text style={styles.formLabel}>Description</Text>
        <TextInput
          style={[styles.formInput, styles.formTextArea]}
          value={formData.description}
          onChangeText={(text) => setFormData(prev => ({ ...prev, description: text }))}
          placeholder="Tell adventurers what to expect..."
          placeholderTextColor={colors.bark[300]}
          multiline
          numberOfLines={4}
          textAlignVertical="top"
        />
      </View>

      <View style={styles.formRow}>
        <View style={[styles.formGroup, { flex: 1 }]}>
          <Text style={styles.formLabel}>Location</Text>
          <TextInput
            style={styles.formInput}
            value={formData.location}
            onChangeText={(text) => setFormData(prev => ({ ...prev, location: text }))}
            placeholder="Where?"
            placeholderTextColor={colors.bark[300]}
          />
        </View>
      </View>

      <View style={styles.formRow}>
        <View style={[styles.formGroup, { flex: 1, marginRight: spacing.sm }]}>
          <Text style={styles.formLabel}>Date</Text>
          <TextInput
            style={styles.formInput}
            value={formData.date}
            onChangeText={(text) => setFormData(prev => ({ ...prev, date: text }))}
            placeholder="Feb 15, 2026"
            placeholderTextColor={colors.bark[300]}
          />
        </View>
        <View style={[styles.formGroup, { flex: 1 }]}>
          <Text style={styles.formLabel}>Time</Text>
          <TextInput
            style={styles.formInput}
            value={formData.time}
            onChangeText={(text) => setFormData(prev => ({ ...prev, time: text }))}
            placeholder="4:00 PM"
            placeholderTextColor={colors.bark[300]}
          />
        </View>
      </View>

      <View style={styles.formGroup}>
        <Text style={styles.formLabel}>Max Attendees</Text>
        <TextInput
          style={styles.formInput}
          value={formData.maxAttendees}
          onChangeText={(text) => setFormData(prev => ({ ...prev, maxAttendees: text }))}
          placeholder="8"
          placeholderTextColor={colors.bark[300]}
          keyboardType="number-pad"
        />
      </View>

      <View style={styles.formGroup}>
        <Text style={styles.formLabel}>Schedule (optional)</Text>
        <TextInput
          style={[styles.formInput, styles.formTextArea]}
          value={formData.schedule}
          onChangeText={(text) => setFormData(prev => ({ ...prev, schedule: text }))}
          placeholder="Add timeline items, one per line..."
          placeholderTextColor={colors.bark[300]}
          multiline
          numberOfLines={4}
          textAlignVertical="top"
        />
      </View>

      <TouchableOpacity style={styles.createEventButton} onPress={handleCreate}>
        <Ionicons name="megaphone" size={20} color="#FFFFFF" />
        <Text style={styles.createEventButtonText}>Create Adventure</Text>
      </TouchableOpacity>
    </ScrollView>
  );

  return (
    <Modal visible={visible} animationType="slide" transparent onRequestClose={onClose}>
      <View style={styles.modalOverlay}>
        {Platform.OS === 'ios' ? (
          <BlurView intensity={90} tint="dark" style={styles.createModal}>
            <ModalContent />
          </BlurView>
        ) : (
          <View style={[styles.createModal, styles.modalFallback]}>
            <ModalContent />
          </View>
        )}
      </View>
    </Modal>
  );
}

